-- Poems batch 391
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-172','夜半乐','柳永','宋','宋词','song-ci','夜半乐','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','冻云黯淡天气，扁舟一叶，乘兴离江渚。',175,'宋词/ci.song.0.json','["冻云黯淡天气，扁舟一叶，乘兴离江渚。", "渡万壑千岩，越溪深处。", "怒涛渐息，樵风乍起，更闻商旅相呼。", "片帆高举。", "泛画鹢、翩翩过南浦。", "望中酒旆闪闪，一簇烟村，数行霜树。", "残日下，渔人鸣榔归去。", "败荷零落，衰杨掩映，岸边两两三三，浣沙游女。", "避行客、含羞笑相语。", "到此因念，绣阁轻抛，浪萍难驻。", "叹后约丁宁竟何据。", "惨离怀，空恨岁晚归期阻。", "凝泪眼、杳杳神京路。", "断鸿声远长天暮。"]'),
('song-ci-173','祭天神','柳永','宋','宋词','song-ci','祭天神','[]','叹笑筵歌席轻抛亸。',103,'宋词/ci.song.0.json','["叹笑筵歌席轻抛亸。", "背孤城、几舍烟村停画舸。", "更深钓叟归来，数点残灯火。", "被连绵宿酒醺醺，愁无那。", "寂寞拥、重衾卧。", "又闻得、行客扁舟过。", "篷窗近，兰棹急，好梦还惊破。", "念平生、单栖踪迹，多感情怀，到此厌厌，向晓披衣坐。"]'),
('song-ci-174','过涧歇近・过涧歇','柳永','宋','宋词','song-ci','过涧歇近・过涧歇','[]','淮楚。',97,'宋词/ci.song.0.json','["淮楚。", "旷望极，千里火云烧空，尽日西郊无雨。", "厌行旅。", "数幅轻帆旋落，舣棹蒹葭浦。", "避畏景，两两舟人夜深语。", "此际争可，便恁奔名竞利去。", "九衢尘里，衣冠冒炎暑。", "回首江乡，月观风亭，水边石上，幸有散发披襟处。"]'),
('song-ci-175','安公子','柳永','宋','宋词','song-ci','安公子','[]','长川波潋滟。',95,'宋词/ci.song.0.json','["长川波潋滟。", "楚乡淮岸迢递，一霎烟汀雨过，芳草青如染。", "驱驱携书剑。", "当此好天好景，自觉多愁多病，行役心情厌。", "望处旷野沈沈，暮云黯黯。", "行侵夜色，又是急桨投村店。", "认去程将近，舟子相呼，遥指渔灯一点。"]'),
('song-ci-176','菊花新','柳永','宋','宋词','song-ci','菊花新','[]','欲掩香帏论缱绻。',63,'宋词/ci.song.0.json','["欲掩香帏论缱绻。", "先敛双蛾愁夜短。", "催促少年郎，先去睡、鸳衾图暖。", "须臾放了残针线。", "脱罗裳、恣情无限。", "留取帐前灯，时时待、看伊娇面。"]'),
('song-ci-177','过涧歇近・过涧歇','柳永','宋','宋词','song-ci','过涧歇近・过涧歇','[]','酒醒。',98,'宋词/ci.song.0.json','["酒醒。", "梦才觉，小阁香炭成煤，洞户银蟾移影。", "人寂静。", "夜永清寒，翠瓦霜凝。", "疏帘风动，漏声隐隐，飘来转愁听。", "怎向心绪，近日厌厌长似病。", "凤楼咫尺，佳期杳无定。", "展转无眠，粲枕冰冷。", "香虬烟断，是谁与把重衾整。"]'),
('song-ci-178','轮台子','柳永','宋','宋词','song-ci','轮台子','[]','雾敛澄江，烟消蓝光碧。',171,'宋词/ci.song.0.json','["雾敛澄江，烟消蓝光碧。", "彤霞衬遥天，掩映断续，半空残月。", "孤村望处人寂寞，闻钓叟、甚处一声羌笛。", "九疑山畔才雨过，斑竹作、血痕添色。", "感行客。", "翻思故国，恨因循阻隔。", "路久沈消息。", "正老松枯柏情如织。", "闻野猿啼，愁听得。", "见钓舟初出，芙蓉渡头，鸳鸯滩侧。", "干名利禄终无益。", "念岁岁间阻，迢迢紫陌。", "翠蛾娇艳，从别后经今，花开柳拆伤魂魄。", "利名牵役。", "又争忍、把光景抛掷。"]'),
('song-ci-179','望汉月・忆汉月','柳永','宋','宋词','song-ci','望汉月・忆汉月','[]','明月明月明月。',61,'宋词/ci.song.0.json','["明月明月明月。", "争奈乍圆还缺。", "恰如年少洞房人，暂欢会、依前离别。", "小楼凭槛处，正是去年时节。", "千里清光又依旧，奈夜永、厌厌人绝。"]'),
('song-ci-180','归去来','柳永','宋','宋词','song-ci','归去来','[]','初过元宵三五。',60,'宋词/ci.song.0.json','["初过元宵三五。", "慵困春情绪。", "灯月阑珊嬉游处。", "游人尽、厌欢聚。", "凭仗如花女。", "持杯谢、酒朋诗侣。", "馀酲更不禁香醑。", "歌筵罢、且归去。"]'),
('song-ci-181','燕归梁','柳永','宋','宋词','song-ci','燕归梁','[]','织锦裁编写意深。',61,'宋词/ci.song.0.json','["织锦裁编写意深。", "字值千金。", "一回披玩一愁吟。", "肠成结、泪盈襟。", "幽欢已散前期远，无憀赖、是而今。", "密凭归雁寄芳音。", "恐冷落、旧时心。"]'),
('song-ci-182','八六子','柳永','宋','宋词','song-ci','八六子','[]','如花貌。',109,'宋词/ci.song.0.json','["如花貌。", "当来便约，永结同心偕老。", "为妙年、俊格聪明，凌厉多方怜爱，何期养成心性近，元来都不相表。", "渐作分飞计料。", "稍觉因情难供，恁殛恼。", "争克罢同欢笑。", "已是断弦尤续，覆水难收，常向人前诵谈，空遣时传音耗。", "漫悔懊。", "此事何时坏了。"]'),
('song-ci-183','长寿乐','柳永','宋','宋词','song-ci','长寿乐','[]','尤红殢翠。',137,'宋词/ci.song.0.json','["尤红殢翠。", "近日来、陡把狂心牵系。", "罗绮丛中，笙歌筵上，有个人人可意。", "解严妆巧笑，取次言谈成娇媚。", "知几度、密约秦楼尽醉。", "仍携手，眷恋香衾绣被。", "情渐美。", "算好把、夕雨朝云相继。", "便是仙禁春深，御炉香袅，临轩亲试。", "对天颜咫尺，定然魁甲登高第。", "待恁时、等著回来贺喜。", "好生地。", "剩与我儿利市。"]'),
('song-ci-184','望海潮','柳永','宋','宋词','song-ci','望海潮','[]','东南形胜，三吴都会，钱塘自古繁华。',129,'宋词/ci.song.0.json','["东南形胜，三吴都会，钱塘自古繁华。", "烟柳画桥，风帘翠幕，参差十万人家。", "云树绕堤沙。", "怒涛卷霜雪，天堑无涯。", "市列珠玑，户盈罗绮竞豪奢。", "重湖叠巘清嘉。", "有三秋桂子，十里荷花。", "羌管弄晴，菱歌泛夜，嬉嬉钓叟莲娃。", "千骑拥高牙。", "乘醉听箫鼓，吟赏烟霞。", "异日图将好景，归去凤池夸。"]'),
('song-ci-185','如鱼水','柳永','宋','宋词','song-ci','如鱼水','[]','轻霭浮空，乱峰倒影，潋滟十里银塘。',115,'宋词/ci.song.0.json','["轻霭浮空，乱峰倒影，潋滟十里银塘。", "绕岸垂杨。", "红楼朱阁相望。", "芰荷香。", "双双戏、鸂鶒鸳鸯。", "乍雨过、兰芷汀洲，望中依约似潇湘。", "风淡淡，水茫茫。", "动一片晴光。", "画舫相将。", "盈盈红粉清商。", "紫薇郎。", "修禊饮、且乐仙乡。", "更归去，遍历銮坡凤沼，此景也难忘。"]'),
('song-ci-186','如鱼水','柳永','宋','宋词','song-ci','如鱼水','[]','帝里疏散，数载酒萦花系，九陌狂游。',119,'宋词/ci.song.0.json','["帝里疏散，数载酒萦花系，九陌狂游。", "良景对珍筵恼，佳人自有风流。", "劝琼瓯。", "绛唇启、歌发清幽。", "被举措、艺足才高，在处别得艳姬留。", "浮名利，拟拼休。", "是非莫挂心头。", "富贵岂尤人，时会高志须酬。", "莫闲愁。", "共绿蚁、红粉相尤。", "向绣幄，醉倚芳姿睡，算除此外何求。"]'),
('song-ci-187','玉蝴蝶','柳永','宋','宋词','song-ci','玉蝴蝶','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','望处雨收云断，凭阑悄悄，目送秋光。',124,'宋词/ci.song.0.json','["望处雨收云断，凭阑悄悄，目送秋光。", "晚景萧疏，堪动宋玉悲凉。", "水风轻、苹花渐老，月露冷、梧叶飘黄。", "遣情伤。", "故人何在，烟水茫茫。", "难忘。", "文期酒会，几孤风月，屡变星霜。", "海阔山遥，未知何处是潇湘。", "念双燕、难凭远信，指暮天、空识归航。", "黯相望。", "断鸿声里，立尽斜阳。"]'),
('song-ci-188','玉蝴蝶','柳永','宋','宋词','song-ci','玉蝴蝶','[]','渐觉芳郊明媚，夜来膏雨，一洒尘埃。',124,'宋词/ci.song.0.json','["渐觉芳郊明媚，夜来膏雨，一洒尘埃。", "满目浅桃深杏，露染风裁。", "银塘静、鱼鳞簟展，烟岫翠、龟甲屏开。", "殷晴雷。", "云中鼓吹，游遍蓬莱。", "徘徊。", "隼旟前后，三千珠履，十二金钗。", "雅俗熙熙，下车成宴尽春台。", "好雍容、东山妓女，堪笑傲、北海尊罍。", "且追陪。", "凤池归去，那更重来。"]'),
('song-ci-189','玉蝴蝶','柳永','宋','宋词','song-ci','玉蝴蝶','[]','是处小街斜巷，烂游花馆，连醉瑶卮。',124,'宋词/ci.song.0.json','["是处小街斜巷，烂游花馆，连醉瑶卮。", "选得芳容端丽，冠绝吴姬。", "绛唇轻、笑歌尽雅，莲步稳、举措皆奇。", "出屏帏。", "倚风情态，约素腰肢。", "当时。", "绮罗丛里，知名虽久，识面何迟。", "见了千花万柳，比并不如伊。", "未同欢、寸心暗许，欲话别、纤手重携。", "结前期。", "美人才子，合是相知。"]'),
('song-ci-190','玉蝴蝶','柳永','宋','宋词','song-ci','玉蝴蝶','[]','误入平康小巷，画檐深处，珠箔微褰。',124,'宋词/ci.song.0.json','["误入平康小巷，画檐深处，珠箔微褰。", "罗绮丛中，偶认旧识婵娟。", "翠眉开、娇横远岫，绿鬓亸、浓染春烟。", "忆情牵。", "粉墙曾恁，窥宋三年。", "迁延。", "珊瑚筵上，亲持犀管，旋叠香笺。", "要索新词，殢人含笑立尊前。", "按新声、珠喉渐稳，想旧意、波脸增妍。", "苦留连。", "凤衾鸳枕，忍负良天。"]'),
('song-ci-191','玉蝴蝶','柳永','宋','宋词','song-ci','玉蝴蝶','[]','淡荡素商行暮，远空雨歇，平野烟收。',124,'宋词/ci.song.0.json','["淡荡素商行暮，远空雨歇，平野烟收。", "满目江山，堪助楚客冥搜。", "素光动、云涛涨晚，紫翠冷、霜巘横秋。", "景清幽。", "渚兰香谢，汀树红愁。", "良俦。", "西风吹帽，东篱携酒，共结欢游。", "浅酌低吟，坐中俱是饮家流。", "对残晖、登临休叹，赏令节、酩酊方酬。", "且相留。", "眼前尤物，盏里忘忧。"]'),
('song-ci-192','满江红','柳永','宋','宋词','song-ci','满江红','[]','暮雨初收，长川静、征帆夜落。',115,'宋词/ci.song.0.json','["暮雨初收，长川静、征帆夜落。", "临岛屿、蓼烟疏淡，苇风萧索。", "几许渔人飞短艇，尽载灯火归村落。", "遣行客、当此念回程，伤漂泊。", "桐江好，烟漠漠。", "波似染，山如削。", "绕严陵滩畔，鹭飞鱼跃。", "游宦区区成底事，平生况有云泉约。", "归去来、一曲仲宣吟，从军乐。"]'),
('song-ci-193','满江红','柳永','宋','宋词','song-ci','满江红','[]','访雨寻云，无非是、奇容艳色。',115,'宋词/ci.song.0.json','["访雨寻云，无非是、奇容艳色。", "就中有、天真妖丽，自然标格。", "恶发姿颜欢喜面，细追想处皆堪惜。", "自别后、幽怨与闲愁，成堆积。", "鳞鸿阻，无信息。", "梦魂断，难寻觅。", "尽思量，休又怎生休得。", "谁恁多情凭向道，纵来相见且相忆。", "便不成、常遣似如今，轻抛掷。"]'),
('song-ci-194','满江红','柳永','宋','宋词','song-ci','满江红','[]','万恨千愁，将年少、衷肠牵系。',118,'宋词/ci.song.0.json','["万恨千愁，将年少、衷肠牵系。", "残梦断、酒醒孤馆，夜长无味。", "可惜许枕前多少意，到如今两总无终始。", "独自个、赢得不成眠，成憔悴。", "添伤感，将何计。", "空只恁，厌厌地。", "无人处思量，几度垂泪。", "不会得都来些子事，甚恁底死难拚弃。", "待到头、终久问伊看，如何是。"]'),
('song-ci-195','满江红','柳永','宋','宋词','song-ci','满江红','[]','匹马驱驱，摇征辔、溪边谷畔。',112,'宋词/ci.song.0.json','["匹马驱驱，摇征辔、溪边谷畔。", "望斜日西照，渐沈山半。", "两两栖禽归去急，对人相并声相唤。", "似笑我、独自向长途，离魂乱。", "中心事，多伤感。", "人是宿，前村馆。", "想鸳衾今夜，共他谁暖。", "惟有枕前相思泪，背灯弹了依前满。", "怎忘得、香阁共伊时，嫌更短。"]'),
('song-ci-196','洞仙歌','柳永','宋','宋词','song-ci','洞仙歌','[]','乘兴，闲泛兰舟，渺渺烟波东去。',152,'宋词/ci.song.0.json','["乘兴，闲泛兰舟，渺渺烟波东去。", "淑气散幽香，满蕙兰汀渚。", "绿芜平畹，和风轻暖，曲岸垂杨，隐隐隔、桃花圃。", "芳树外，闪闪酒旗遥举。", "羁旅。", "渐入三吴风景，水村渔市。", "闲思更远神京，抛掷幽会小欢何处。", "不堪独倚危樯，凝情西望日边，繁华地、归程阻。", "空自叹当时，言约无据。", "伤心最苦。", "伫立对、碧云将暮。", "关河远，怎奈向、此时情绪。"]'),
('song-ci-197','引驾行','柳永','宋','宋词','song-ci','引驾行','[]','红尘紫陌，斜阳暮草长安道，是离人、断魂处，迢迢匹马西征。',154,'宋词/ci.song.0.json','["红尘紫陌，斜阳暮草长安道，是离人、断魂处，迢迢匹马西征。", "新晴。", "韶光明媚，轻烟淡薄和气暖，望花村、路隐映，摇鞭时过长亭。", "愁生。", "伤凤城仙子，别来千里重行行。", "又记得临歧，泪眼湿、莲脸盈盈。", "消凝。", "花朝月夕，最苦冷落银屏。", "想媚容、耿耿无眠，屈指已算回程。", "相萦。", "空万般思忆，争如归去睹倾城。", "向绣帏、深处并枕，说如此牵情。"]'),
('song-ci-198','望远行','柳永','宋','宋词','song-ci','望远行','[]','长空降瑞，寒风翦，淅淅瑶花初下。',129,'宋词/ci.song.0.json','["长空降瑞，寒风翦，淅淅瑶花初下。", "乱飘僧舍，密洒歌楼，迤逦渐迷鸳瓦。", "好是渔人，披得一蓑归去，江上晚来堪画。", "满长安，高却旗亭酒价。", "幽雅。", "乘兴最宜访戴，泛小棹、越溪潇洒。", "皓鹤夺鲜，白鹇失素，千里广铺寒野。", "须信幽兰歌断，彤云收尽，别有瑶台琼榭。", "放一轮明月，交光清夜。"]'),
('song-ci-199','八声甘州','柳永','宋','宋词','song-ci','八声甘州','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u957f\u6c5f"]','对潇潇、暮雨洒江天，一番洗清秋。',119,'宋词/ci.song.0.json','["对潇潇、暮雨洒江天，一番洗清秋。", "渐霜风凄惨，关河冷落，残照当楼。", "是处红衰翠减，苒苒物华休。", "惟有长江水，无语东流。", "不忍登高临远，望故乡渺邈，归思难收。", "叹年来踪迹，何事苦淹留。", "想佳人、妆楼顒望，误几回、天际识归舟。", "争知我、倚阑干处，正恁凝愁。"]'),
('song-ci-200','临江仙','柳永','宋','宋词','song-ci','临江仙','[]','梦觉小庭院，冷风淅淅，疏雨潇潇。',117,'宋词/ci.song.0.json','["梦觉小庭院，冷风淅淅，疏雨潇潇。", "绮窗外，秋声败叶狂飘。", "心摇。", "奈寒漏永，孤帏悄，泪烛空烧。", "无端处，是绣衾鸳枕，闲过清宵。", "萧条。", "牵情系恨，争向年少偏饶。", "觉新来、憔悴旧日风标。", "魂消。", "念欢娱事，烟波阻、后约方遥。", "还经岁，问怎生禁得，如许无聊。"]'),
('song-ci-201','竹马子・竹马儿','柳永','宋','宋词','song-ci','竹马子・竹马儿','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','登孤垒荒凉，危亭旷望，静临烟渚。',125,'宋词/ci.song.0.json','["登孤垒荒凉，危亭旷望，静临烟渚。", "对雌霓挂雨，雄风拂槛，微收烦暑。", "渐觉一叶惊秋，残蝉噪晚，素商时序。", "览景想前欢，指神京，非雾非烟深处。", "向此成追感，新愁易积，故人难聚。", "凭高尽日凝伫。", "赢得消魂无语。", "极目霁霭霏微，暝鸦零乱，萧索江城暮。", "南楼画角，又送残阳去。"]'),
('song-ci-202','小镇西・小镇西犯','柳永','宋','宋词','song-ci','小镇西・小镇西犯','[]','意中有个人，芳颜二八。',98,'宋词/ci.song.0.json','["意中有个人，芳颜二八。", "天然俏、自来奸黠。", "最奇绝。", "是笑时、媚靥深深，百态千娇，再三偎著，再三香滑。", "久离缺。", "夜来魂梦里，尤花殢雪。", "分明似旧家时节。", "正欢悦。", "被邻鸡唤起，一场寂寥，无眠向晓，空有半窗残月。"]'),
('song-ci-203','小镇西犯','柳永','宋','宋词','song-ci','小镇西犯','[]','水乡初禁火，青春未老。',88,'宋词/ci.song.0.json','["水乡初禁火，青春未老。", "芳菲满、柳汀烟岛。", "波际红帏缥缈。", "尽杯盘小。", "歌祓禊，声声谐楚调。", "路缭绕。", "野桥新市里，花秾妓好。", "引游人、兢来喧笑。", "酩酊谁家年少。", "信玉山倒。", "家何处，落日眠芳草。"]'),
('song-ci-204','迷神引','柳永','宋','宋词','song-ci','迷神引','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','一叶扁舟轻帆卷。',122,'宋词/ci.song.0.json','["一叶扁舟轻帆卷。", "暂泊楚江南岸。", "孤城暮角，引胡茄怨。", "水茫茫，平沙雁、旋惊散。", "烟敛寒林簇，画屏展。", "天际遥山小，黛眉浅。", "旧赏轻抛，到此成游宦。", "觉客程劳，年光晚。", "异乡风物，忍萧索、当愁眼。", "帝城赊，秦楼阻，旅魂乱。", "芳草连空阔，残照满。", "佳人无消息，断云远。"]'),
('song-ci-205','促拍满路花','柳永','宋','宋词','song-ci','促拍满路花','[]','香靥融春雪，翠鬓亸秋烟。',99,'宋词/ci.song.0.json','["香靥融春雪，翠鬓亸秋烟。", "楚腰纤细正笄年。", "凤帏夜短，偏爱日高眠。", "起来贪颠耍，只恁残却黛眉，不整花钿。", "有时携手闲坐，偎倚绿窗前。", "温柔情态尽人怜。", "画堂春过，悄悄落花天。", "最是娇痴处，尤殢檀郎，未教拆了秋千。"]'),
('song-ci-206','六么令','柳永','宋','宋词','song-ci','六么令','[]','淡烟残照，摇曳溪光碧。',112,'宋词/ci.song.0.json','["淡烟残照，摇曳溪光碧。", "溪边浅桃深杏，迤逦染春色。", "昨夜扁舟泊处，枕底当滩碛。", "波声渔笛。", "惊回好梦，梦里欲归归不得。", "展转翻成无寐，因此伤行役。", "思念多媚多娇，咫尺千山隔。", "都为深情密爱，不忍轻离拆。", "好天良夕。", "鸳帷寂寞，算得也应暗相忆。"]'),
('song-ci-207','剔银灯','柳永','宋','宋词','song-ci','剔银灯','[]','何事春工用意。',92,'宋词/ci.song.0.json','["何事春工用意。", "绣画出、万红千翠。", "艳杏夭桃，垂杨芳草，各斗雨膏烟腻。", "如斯佳致。", "早晚是、读书天气。", "渐渐园林明媚。", "便好安排欢计。", "论槛买花，盈车载酒，百琲千金邀妓。", "何妨沈醉。", "有人伴、日高春睡。"]'),
('song-ci-208','红窗听','柳永','宋','宋词','song-ci','红窗听','[]','如削肌肤红玉莹。',64,'宋词/ci.song.0.json','["如削肌肤红玉莹。", "举措有、许多端正。", "二年三岁同鸳寝。", "表温柔心性。", "别后无非良夜永。", "如何向、名牵利役，归期未定。", "算伊心里，却冤成薄幸。"]'),
('song-ci-209','临江仙','柳永','宋','宋词','song-ci','临江仙','[]','鸣珂碎撼都门晓，旌幢拥下天人。',68,'宋词/ci.song.0.json','["鸣珂碎撼都门晓，旌幢拥下天人。", "马摇金辔破香尘。", "壶浆盈路，欢动一城春。", "扬州曾是追游地，酒台花径仍存。", "凤箫依旧月中闻。", "荆王魂梦，应认岭头云。"]'),
('song-ci-210','凤归云','柳永','宋','宋词','song-ci','凤归云','[]','向深秋，雨馀爽气肃西郊。',124,'宋词/ci.song.0.json','["向深秋，雨馀爽气肃西郊。", "陌上夜阑，襟袖起凉飙。", "天末残星，流电未灭，闪闪隔林梢。", "又是晓鸡声断，阳乌光动，渐分山路迢迢。", "驱驱行役，苒苒光阴，绳头利禄，蜗角功名，毕竟成何事，漫相高。", "抛掷云泉，狎玩尘土，壮节等闲消。", "幸有五湖烟浪，一船风月，会须归去老渔樵。"]'),
('song-ci-211','女冠子','柳永','宋','宋词','song-ci','女冠子','[]','淡烟飘薄。',137,'宋词/ci.song.0.json','["淡烟飘薄。", "莺花谢、清和院落。", "树阴翠、密叶成幄。", "麦秋霁景，夏云忽变奇峰、倚寥廓。", "波暖银塘，涨新萍绿鱼跃。", "想端忧多暇，陈王是日，嫩苔生阁。", "正铄石天高，流金昼永，楚榭光风转蕙，披襟处、波翻翠幕。", "以文会友，沈李浮瓜忍轻诺。", "别馆清闲，避炎蒸、岂须河朔。", "但尊前随分，雅歌艳舞，尽成欢乐。"]'),
('song-ci-212','玉山枕','柳永','宋','宋词','song-ci','玉山枕','[]','骤雨新霁。',141,'宋词/ci.song.0.json','["骤雨新霁。", "荡原野、清如洗。", "断霞散彩，残阳倒影，天外云峰，数朵相倚。", "露荷烟芰满池塘，见次第、几番红翠。", "当是时、河朔飞觞，避炎蒸，想风流堪继。", "晚来高树清风起。", "动帘幕、生秋气。", "画楼昼寂，兰堂夜静，舞艳歌姝，渐任罗绮。", "讼闲时泰足风情，便争奈、雅歌都废。", "省教成、几阕清歌，尽新声，好尊前重理。"]'),
('song-ci-213','减字木兰花','柳永','宋','宋词','song-ci','减字木兰花','[]','花心柳眼。',52,'宋词/ci.song.0.json','["花心柳眼。", "郎似游丝常惹绊。", "慵困谁怜。", "绣线金针不喜穿。", "深房密宴。", "争向好天多聚散。", "绿锁窗前。", "几日春愁废管弦。"]'),
('song-ci-214','木兰花令','柳永','宋','宋词','song-ci','木兰花令','[]','有个人人真攀羡。',64,'宋词/ci.song.0.json','["有个人人真攀羡。", "问著洋洋回却面。", "你若无意向他人，为甚梦中频相见。", "不如闻早还却愿。", "免使牵人虚魂乱。", "风流肠肚不坚牢，祗恐被伊牵引断。"]'),
('song-ci-215','甘州令','柳永','宋','宋词','song-ci','甘州令','[]','冻云深，淑气浅，寒欺绿野。',101,'宋词/ci.song.0.json','["冻云深，淑气浅，寒欺绿野。", "轻雪伴、早梅飘谢。", "艳阳天，正明媚，却成潇洒。", "玉人歌，画楼酒，对此景、骤增高价。", "卖花巷陌，放灯台榭。", "好时节、怎生轻舍。", "赖和风，荡霁蔼，廓清良夜。", "玉尘铺，桂华满，素光里、更堪游冶。"]'),
('song-ci-216','西施','柳永','宋','宋词','song-ci','西施','[]','苎萝妖艳世难偕。',86,'宋词/ci.song.0.json','["苎萝妖艳世难偕。", "善媚悦君怀。", "后庭恃宠，尽使绝嫌猜。", "正恁朝欢暮宴，情未足，早江上兵来。", "捧心调态军前死，罗绮旋变尘埃。", "至今想，怨魂无主尚徘徊。", "夜夜姑苏城外，当时月，但空照荒台。"]'),
('song-ci-217','西施','柳永','宋','宋词','song-ci','西施','[]','柳街灯市好花多。',86,'宋词/ci.song.0.json','["柳街灯市好花多。", "尽让美琼娥。", "万娇千媚，的的在层波。", "取次梳妆，自有天然态，爱浅画双娥。", "断肠最是金闺客，空怜爱、奈伊何。", "洞房咫尺，无计枉朝珂。", "有意怜才，每遇行云处，幸时恁相过。"]'),
('song-ci-218','西施','柳永','宋','宋词','song-ci','西施','[]','自从回步百花桥。',86,'宋词/ci.song.0.json','["自从回步百花桥。", "便独处清宵。", "凤衾鸳枕，何事等闲抛。", "纵有馀香，也似郎恩爱，向日夜潜消。", "恐伊不信芳容改，将憔悴、写霜绡。", "更凭锦字，字字说情憀。", "要识愁肠，但看丁香树，渐结尽春梢。"]'),
('song-ci-219','河传','柳永','宋','宋词','song-ci','河传','[]','翠深红浅。',69,'宋词/ci.song.0.json','["翠深红浅。", "愁娥黛蹙，娇波刀翦。", "奇容妙妓，争逞舞裀歌扇。", "妆光生粉面。", "坐中醉客风流惯。", "尊前见。", "特地惊狂眼。", "不似少年时节，千金争选。", "相逢何太晚。"]'),
('song-ci-220','河传','柳永','宋','宋词','song-ci','河传','[]','淮岸。',70,'宋词/ci.song.0.json','["淮岸。", "向晚。", "圆荷向背，芙蓉深浅。", "仙娥画舸，露渍红芳交乱。", "难分花与面。", "采多渐觉轻船满。", "呼归伴。", "急桨烟村远。", "隐隐棹歌，渐被蒹葭遮断。", "曲终人不见。"]'),
('song-ci-221','郭郎儿近拍','柳永','宋','宋词','song-ci','郭郎儿近拍','[]','帝里。',89,'宋词/ci.song.0.json','["帝里。", "闲居小曲深坊，庭院沈沈朱户闭。", "新霁。", "畏景天气。", "薰风帘幕无人，永昼厌厌如度岁。", "愁悴。", "枕簟微凉，睡久辗转慵起。", "砚席尘生，新诗小阕，等闲都尽废。", "这些儿、寂寞情怀，何事新来常恁地。"]'),
('song-ci-222','透碧霄','柳永','宋','宋词','song-ci','透碧霄','[]','月华边。',139,'宋词/ci.song.0.json','["月华边。", "万年芳树起祥烟。", "帝居壮丽，皇家熙盛，宝运当千。", "端门清昼，觚稜照日，双阙中天。", "太平时、朝野多欢。", "遍锦街香陌，钧天歌吹，阆苑神仙。", "昔观光得意，狂游风景，再睹更精妍。", "傍柳阴，寻花径，空恁亸辔垂鞭。", "乐游雅戏，平康艳质，应也依然。", "仗何人、多谢婵娟。", "道宦途踪迹，歌酒情怀，不似当年。"]'),
('song-ci-223','木兰花慢','柳永','宋','宋词','song-ci','木兰花慢','[]','倚危楼伫立，乍萧索、晚晴初。',124,'宋词/ci.song.0.json','["倚危楼伫立，乍萧索、晚晴初。", "渐素景衰残，风砧韵响，双树红疏。", "云衢。", "见新雁过，奈佳人自别阻音书。", "空遣悲秋念远，寸肠万恨萦纡。", "皇都。", "暗想欢游，成往事、动欷歔。", "念对酒当歌，低帏并枕，翻恁轻孤。", "归途。", "纵凝望处，但斜阳暮霭满平芜。", "赢得无言悄悄，凭阑尽日踟蹰。"]'),
('song-ci-224','木兰花慢','柳永','宋','宋词','song-ci','木兰花慢','[]','拆桐花烂漫，乍疏雨、洗清明。',124,'宋词/ci.song.0.json','["拆桐花烂漫，乍疏雨、洗清明。", "正艳杏烧林，缃桃绣野，芳景如屏。", "倾城。", "尽寻胜去，骤雕鞍绀幰出郊坰。", "风暖繁弦脆管，万家竞奏新声。", "盈盈。", "斗草踏青。", "人艳冶、递逢迎。", "向路傍往往，遗簪坠珥，珠翠纵横。", "欢情。", "对佳丽地，信金罍罄竭玉山倾。", "拼却明朝永日，画堂一枕春酲。"]'),
('song-ci-225','木兰花慢','柳永','宋','宋词','song-ci','木兰花慢','[]','古繁华茂苑，是当日、帝王州。',124,'宋词/ci.song.0.json','["古繁华茂苑，是当日、帝王州。", "咏人物鲜明，土风细腻，曾美诗流。", "寻幽。", "近香径处，聚莲娃钓叟簇汀洲。", "晴景吴波练静，万家绿水朱楼。", "凝旒。", "乃眷东南，思共理、命贤侯。", "继梦得文章，乐天惠爱，布政优优。", "鳌头。", "况虚位久，遇名都胜景阻淹留。", "赢得兰堂酝酒，画船携妓欢游。"]'),
('song-ci-226','临江仙引','柳永','宋','宋词','song-ci','临江仙引','[]','渡口、向晚，乘瘦马、陟平冈。',90,'宋词/ci.song.0.json','["渡口、向晚，乘瘦马、陟平冈。", "西郊又送秋光。", "对暮山横翠，衬残叶飘黄。", "凭高念远，素景楚天，无处不凄凉。", "香闺别来无信息，云愁雨恨难忘。", "指帝城归路，但烟水茫茫。", "凝情望断泪眼，尽日独立斜阳。"]'),
('song-ci-227','临江仙引','柳永','宋','宋词','song-ci','临江仙引','[]','上国。',90,'宋词/ci.song.0.json','["上国。", "去客。", "停飞盖、促离筵。", "长安古道绵绵。", "见岸花啼露，对堤柳愁烟。", "物情人意，向此触目，无处不凄然。", "醉拥征骖犹伫立，盈盈泪眼相看。", "况绣帏人静，更山馆春寒。", "今宵怎向漏永，顿成两处孤眠。"]'),
('song-ci-228','临江仙引','柳永','宋','宋词','song-ci','临江仙引','[]','画舸、荡桨，随浪箭、隔岸虹。',89,'宋词/ci.song.0.json','["画舸、荡桨，随浪箭、隔岸虹。", "□荷占断秋容。", "疑水仙游泳，向别浦相逢。", "鲛丝雾吐渐收，细腰无力转娇慵。", "罗袜凌波成旧恨，有谁更赋惊鸿。", "想媚魂香信，算密锁瑶宫。", "游人漫劳倦□，奈何不逐东风。"]'),
('song-ci-229','瑞鹧鸪','柳永','宋','宋词','song-ci','瑞鹧鸪','[]','宝髻瑶簪。',108,'宋词/ci.song.0.json','["宝髻瑶簪。", "严妆巧，天然绿媚红深。", "绮罗丛里，独逞讴吟。", "一曲阳春定价，何啻值千金。", "倾听处，王孙帝子，鹤盖成阴。", "凝态掩霞襟。", "动象板声声，怨思难任。", "嘹亮处，迥压弦管低沈。", "时恁回眸敛黛，空役五陵心。", "须信道，缘情寄意，别有知音。"]'),
('song-ci-230','瑞鹧鸪','柳永','宋','宋词','song-ci','瑞鹧鸪','[]','吴会风流。',105,'宋词/ci.song.0.json','["吴会风流。", "人烟好，高下水际山头。", "瑶台绛阙，依约蓬丘。", "万井千闾富庶，雄压十三州。", "触处青娥画舸，红粉朱楼。", "方面委元侯。", "致讼简时丰，继日欢游。", "襦温裤暖，已扇民讴。", "旦暮锋车命驾，重整济川舟。", "当恁时，沙堤路稳，归去难留。"]'),
('song-ci-231','忆帝京','柳永','宋','宋词','song-ci','忆帝京','[]','薄衾小枕天气。',86,'宋词/ci.song.0.json','["薄衾小枕天气。", "乍觉别离滋味。", "展转数寒更，起了还重睡。", "毕竟不成眠，一夜长如岁。", "也拟待、却回征辔。", "又争奈、已成行计。", "万种思量，多方开解，只恁寂寞厌厌地。", "系我一生心，负你千行泪。"]'),
('song-ci-232','塞孤','柳永','宋','宋词','song-ci','塞孤','[]','一声鸡，又报残更歇。',119,'宋词/ci.song.0.json','["一声鸡，又报残更歇。", "秣马巾车催发。", "草草主人灯下别。", "山路险，新霜滑。", "瑶珂响、起栖乌，金镫冷、敲残月。", "渐西风紧，襟袖凄冽。", "遥指白玉京，望断黄金阙。", "远道何时行彻。", "算得佳人凝恨切。", "应念念，归时节。", "相见了、执柔荑，幽会处、偎香雪。", "免鸳衾，两恁虚设。"]'),
('song-ci-233','瑞鹧鸪','柳永','宋','宋词','song-ci','瑞鹧鸪','[]','天将奇艳与寒梅。',74,'宋词/ci.song.0.json','["天将奇艳与寒梅。", "乍惊繁杏腊前开。", "暗想花神、巧作江南信，鲜染燕脂细翦裁。", "寿阳妆罢无端饮，凌晨酒入香腮。", "恨听烟坞深中，谁恁吹羌管逐风来。", "绛雪纷纷落翠苔。"]'),
('song-ci-234','瑞鹧鸪','柳永','宋','宋词','song-ci','瑞鹧鸪','[]','全吴嘉会古风流。',75,'宋词/ci.song.0.json','["全吴嘉会古风流。", "渭南往岁忆来游。", "西子方来、越相功成去，千里沧江一叶舟。", "至今无限盈盈者，尽来拾翠芳洲。", "最是簇簇寒村，遥认南朝路、晚烟收。", "三两人家古渡头。"]'),
('song-ci-235','洞仙歌','柳永','宋','宋词','song-ci','洞仙歌','[]','嘉景，向少年彼此，争不雨沾云惹。',148,'宋词/ci.song.0.json','["嘉景，向少年彼此，争不雨沾云惹。", "奈傅粉英俊，梦兰品雅。", "金丝帐暖银屏亚。", "并粲枕、轻偎轻倚，绿娇红姹。", "算一笑，百琲明珠非价。", "闲暇。", "每祗向、洞房深处，痛怜极宠，似觉些子轻孤，早恁背人沾洒。", "从来娇纵多猜讶。", "更对翦香云，须要深心同写。", "爱搵了双眉，索人重画。", "忍孤艳冶。", "断不等闲轻舍。", "鸳衾下。", "愿常恁、好天良夜。"]'),
('song-ci-236','安公子','柳永','宋','宋词','song-ci','安公子','[]','远岸收残雨。',126,'宋词/ci.song.0.json','["远岸收残雨。", "雨残稍觉江天暮。", "拾翠汀洲人寂静，立双双鸥鹭。", "望几点、渔灯隐映蒹葭浦。", "停画桡、两两舟人语。", "道去程今夜，遥指前村烟树。", "游宦成羁旅。", "短樯吟倚闲凝伫。", "万水千山迷远近，想乡关何处。", "自别后、风亭月榭孤欢聚。", "刚断肠、惹得离情苦。", "听杜宇声声，劝人不如归去。"]'),
('song-ci-237','安公子','柳永','宋','宋词','song-ci','安公子','[]','梦觉清宵半。',125,'宋词/ci.song.0.json','["梦觉清宵半。", "悄然屈指听银箭。", "惟有床前残泪烛，啼红相伴。", "暗惹起、云愁雨恨情何限。", "从卧来、展转千馀遍。", "恁数重鸳被，怎向孤眠不暖。", "堪恨还堪叹。", "当初不合轻分散。", "及至厌厌独自个，却眼穿肠断。", "似恁地、深情密意如何拚。", "虽后约、的有于飞愿。", "奈片时难过，怎得如今便见。"]'),
('song-ci-238','长寿乐','柳永','宋','宋词','song-ci','长寿乐','[]','繁红嫩翠。',139,'宋词/ci.song.0.json','["繁红嫩翠。", "艳阳景，妆点神州明媚。", "是处楼台，朱门院落，弦管新声腾沸。", "恣游人、无限驰骤，娇马车如水。", "竟寻芳选胜，归来向晚，起通衢近远，香尘细细。", "太平世。", "少年时，忍把韶光轻弃。", "况有红妆，楚腰越艳，一笑千金何啻。", "向尊前、舞袖飘雪，歌响行云止。", "愿长绳、且把飞乌系。", "任好从容痛饮，谁能惜醉。"]'),
('song-ci-239','倾杯・倾杯乐','柳永','宋','宋词','song-ci','倾杯・倾杯乐','[]','水乡天气，洒蒹葭、露结寒生早。',132,'宋词/ci.song.0.json','["水乡天气，洒蒹葭、露结寒生早。", "客馆更堪秋杪。", "空阶下、木叶飘零，飒飒声乾，狂风乱扫。", "当无绪、人静酒初醒，天外征鸿，知送谁家归信，穿云悲叫。", "蛩响幽窗，鼠窥寒砚，一点银釭闲照。", "梦枕频惊，愁衾半拥，万里归心悄悄。", "往事追思多少。", "赢得空使方寸扰。", "断不成眠，此夜厌厌，就中难晓。"]'),
('song-ci-240','倾杯・倾杯乐','柳永','宋','宋词','song-ci','倾杯・倾杯乐','[]','金风淡荡，渐秋光老、清宵永。',132,'宋词/ci.song.0.json','["金风淡荡，渐秋光老、清宵永。", "小院新晴天气，轻烟乍敛，皓月当轩练净。", "对千里寒光，念幽期阻、当残景。", "早是多情多病。", "那堪细把，旧约前欢重省。", "最苦碧云信断，仙乡路杳，归鸿难倩。", "每高歌、强遣离怀，惨咽、翻成心耿耿。", "漏残露冷。", "空赢得、悄悄无言，愁绪终难整。", "又是立尽，梧桐碎影。"]'),
('song-ci-241','倾杯・倾杯乐','柳永','宋','宋词','song-ci','倾杯・倾杯乐','[]','鹜落霜洲，雁横烟渚，分明画出秋色。',128,'宋词/ci.song.0.json','["鹜落霜洲，雁横烟渚，分明画出秋色。", "暮雨乍歇。", "小楫夜泊，宿苇村山驿。", "何人月下临风处，起一声羌笛。", "离愁万绪，闻岸草、切切蛩吟如织。", "为忆。", "芳容别后，水遥山远，何计凭鳞翼。", "想绣阁深沈，争知憔悴损、天涯行客。", "楚峡云归，高阳人散，寂寞狂踪迹。", "望京国。", "空目断、远峰凝碧。"]'),
('song-ci-242','鹤冲天','柳永','宋','宋词','song-ci','鹤冲天','[]','黄金榜上。',105,'宋词/ci.song.0.json','["黄金榜上。", "偶失龙头望。", "明代暂遗贤，如何向。", "未遂风云便，争不恣狂荡。", "何须论得丧。", "才子词人，自是白衣卿相。", "烟花巷陌，依约丹青屏障。", "幸有意中人，堪寻访。", "且恁偎红翠，风流事、平生畅。", "青春都一饷。", "忍把浮名，换了浅斟低唱。"]'),
('song-ci-243','木兰花・玉楼春','柳永','宋','宋词','song-ci','木兰花・玉楼春','[]','翦裁用尽春工意。',64,'宋词/ci.song.0.json','["翦裁用尽春工意。", "浅蘸朝霞千万蕊。", "天然淡泞好精神，洗尽严妆方见媚。", "风亭月榭闲相倚。", "紫玉枝梢红蜡蒂。", "假饶花落未消愁，煮酒杯盘催结子。"]'),
('song-ci-244','木兰花・玉楼春','柳永','宋','宋词','song-ci','木兰花・玉楼春','[]','东风催露千娇面。',64,'宋词/ci.song.0.json','["东风催露千娇面。", "欲绽红深开处浅。", "日高梳洗甚时忺，点滴燕脂匀未遍。", "霏微雨罢残阳院。", "洗出都城新锦段。", "美人纤手摘芳枝，插在钗头和凤颤。"]'),
('song-ci-245','木兰花・玉楼春','柳永','宋','宋词','song-ci','木兰花・玉楼春','[]','黄金万缕风牵细。',64,'宋词/ci.song.0.json','["黄金万缕风牵细。", "寒食初头春有味。", "殢烟尤雨索春饶，一日三眠夸得意。", "章街隋岸欢游地。", "高拂楼台低映水。", "楚王空待学风流，饿损宫腰终不似。"]'),
('song-ci-246','倾杯乐','柳永','宋','宋词','song-ci','倾杯乐','[]','楼锁轻烟，水横斜照，遥山半隐愁碧。',127,'宋词/ci.song.0.json','["楼锁轻烟，水横斜照，遥山半隐愁碧。", "片帆岸远，行客路杳，簇一天寒色。", "楚梅映雪数枝艳，报青春消息。", "年华梦促，音信断、声远飞鸿南北。", "算伊别来无绪，翠消红减，双带长抛掷。", "但泪眼沈迷，看朱成碧。", "惹闲愁堆积。", "雨意云情，酒心花态，孤负高阳客。", "梦难极。", "和梦也、多时间隔。"]'),
('song-ci-247','祭天神','柳永','宋','宋词','song-ci','祭天神','[]','忆绣衾相向轻轻语。',103,'宋词/ci.song.0.json','["忆绣衾相向轻轻语。", "屏山掩、红蜡长明，金兽盛熏兰炷。", "何期到此，酒态花情顿孤负。", "柔肠断、还是黄昏，那更满庭风雨。", "听空阶和漏，碎声斗滴愁眉聚。", "算伊还共谁人，争知此冤苦。", "念千里烟波，迢迢前约，旧欢慵省，一向无心绪。"]'),
('song-ci-248','鹧鸪天','柳永','宋','宋词','song-ci','鹧鸪天','[]','吹破残烟入夜风。',64,'宋词/ci.song.0.json','["吹破残烟入夜风。", "一轩明月上帘栊。", "因惊路远人还远，纵得心同寝未同。", "情脉脉，意忡忡。", "碧云归去认无踪。", "只应曾向前生里，爱把鸳鸯两处笼。"]'),
('song-ci-249','归去来','柳永','宋','宋词','song-ci','归去来','[]','一夜狂风雨。',64,'宋词/ci.song.0.json','["一夜狂风雨。", "花英坠、碎红无数。", "垂杨漫结黄金缕。", "尽春残、萦不住。", "蝶稀蜂散知何处。", "殢尊酒、转添愁绪。", "多情不惯相思苦。", "休惆怅、好归去。"]'),
('song-ci-250','梁州令','柳永','宋','宋词','song-ci','梁州令','[]','梦觉纱窗晓。',65,'宋词/ci.song.0.json','["梦觉纱窗晓。", "残灯掩然空照。", "因思人事苦萦牵，离愁别恨，无限何时了。", "怜深定是心肠小。", "往往成烦恼。", "一生惆怅情多少。", "月不长圆，春色易为老。"]'),
('song-ci-251','燕归梁','柳永','宋','宋词','song-ci','燕归梁','[]','轻蹑罗鞋掩绛绡。',63,'宋词/ci.song.0.json','["轻蹑罗鞋掩绛绡。", "传音耗、苦相招。", "语声犹颤不成娇。", "乍得见、两魂消。", "匆匆草草难留恋，还归去又无聊。", "若谐雨夕与云朝。", "得似个、有嚣嚣。"]'),
('song-ci-252','夜半乐','柳永','宋','宋词','song-ci','夜半乐','[]','艳阳天气，烟雨风暖，芳郊澄朗闲凝伫。',177,'宋词/ci.song.0.json','["艳阳天气，烟雨风暖，芳郊澄朗闲凝伫。", "渐妆点亭台，参差佳树。", "舞腰困力，垂杨绿映，浅桃秾李夭夭，嫩红无数。", "度绮燕、流莺斗双语。", "翠娥南陌簇簇，蹑影红阴，缓移娇步。", "抬粉面、韶容花光相妒。", "绛绡袖举。", "云鬟风颤，半遮檀口含羞，背人偷顾。", "竞斗草、金钗笑争赌。", "对此嘉景，顿觉消凝，惹成愁绪。", "念解佩、轻盈在何处。", "忍良时、孤负少年等闲度。", "空望极、回首斜阳暮。", "叹浪萍风梗知何去。"]'),
('song-ci-253','清平乐','柳永','宋','宋词','song-ci','清平乐','[]','繁华锦烂。',54,'宋词/ci.song.0.json','["繁华锦烂。", "已恨归期晚。", "翠减红稀莺似懒。", "特地柔肠欲断。", "不堪尊酒频倾。", "恼人转转愁生。", "□□□□□□，多情争似无情。"]'),
('song-ci-254','迷神引','柳永','宋','宋词','song-ci','迷神引','[]','红板桥头秋光暮。',121,'宋词/ci.song.0.json','["红板桥头秋光暮。", "淡月映烟方煦。", "寒溪蘸碧，绕垂杨路。", "重分飞，携纤手、泪如雨。", "波急隋堤远，片帆举。", "倏忽年华改，向期阻。", "时觉春残，渐渐飘花絮。", "好夕良天长孤负。", "洞房闲掩，小屏空、无心觑。", "指归云，仙乡杳、在何处。", "遥夜香衾暖，算谁与。", "知他深深约，记得否。"]'),
('song-ci-255','失调名','柳永','宋','宋词','song-ci','失调名','[]','多情到了多病。',7,'宋词/ci.song.0.json','["多情到了多病。"]'),
('song-ci-256','爪茉莉','柳永','宋','宋词','song-ci','爪茉莉','[]','每到秋来，转添甚况味。',105,'宋词/ci.song.0.json','["每到秋来，转添甚况味。", "金风动、冷清清地。", "残蝉噪晚，甚聒得、人心欲碎，更休道、宋玉多悲，石人、也须下泪。", "衾寒枕冷，夜迢迢、更无寐。", "深院静、月明风细。", "巴巴望晓，怎生捱、更迢递。", "料我儿、只在枕头根底，等人来、睡梦里。"]'),
('song-ci-257','女冠子','柳永','宋','宋词','song-ci','女冠子','[]','火云初布。',132,'宋词/ci.song.0.json','["火云初布。", "迟迟永日炎暑。", "浓阴高树。", "黄鹂叶底，羽毛学整，方调娇语。", "薰风时渐动，峻阁池塘，芰荷争吐。", "画梁紫燕，对对衔泥，飞来又去。", "想佳期、容易成辜负。", "共人人、同上画楼斟香醑。", "恨花无主。", "卧象床犀枕，成何情绪。", "有时魂梦断，半窗残月，透帘穿户。", "去年今夜，扇儿扇我，情人何处。"]'),
('song-ci-258','十二时・忆少年','柳永','宋','宋词','song-ci','十二时・忆少年','[]','晚晴初，淡烟笼月，风透蟾光如洗。',159,'宋词/ci.song.0.json','["晚晴初，淡烟笼月，风透蟾光如洗。", "觉翠帐、凉生秋思。", "渐入微寒天气。", "败叶敲窗，西风满院，睡不成还起。", "更漏咽、滴破忧心，万感并生，都在离人愁耳。", "天怎知、当时一句，做得十分萦系。", "夜永有时，分明枕上，觑着孜孜地。", "烛暗时酒醒，元来又是梦里。", "睡觉来、披衣独坐，万种无憀情意。", "怎得伊来，重谐云雨，再整馀香被。", "祝告天发愿，从今永无抛弃。"]'),
('song-ci-259','红窗迥','柳永','宋','宋词','song-ci','红窗迥','[]','小园东，花共柳。',68,'宋词/ci.song.0.json','["小园东，花共柳。", "红紫又一齐开了。", "引将蜂蝶燕和莺，成阵价、忙忙走。", "花心偏向蜂儿有。", "莺共燕、吃他拖逗。", "蜂儿却入、花里藏身，胡蝶儿、你且退后。"]'),
('song-ci-260','西江月','柳永','宋','宋词','song-ci','西江月','[]','师师生得艳冶，香香於我情多。',58,'宋词/ci.song.0.json','["师师生得艳冶，香香於我情多。", "安安那更久比和。", "四个打成一个。", "幸自苍皇未款，新词写处多磨。", "几回扯了又重挼。", "奸字中心著我。"]'),
('song-ci-261','凤凰阁','柳永','宋','宋词','song-ci','凤凰阁','[]','匆匆相见，懊恼恩情太薄。',82,'宋词/ci.song.0.json','["匆匆相见，懊恼恩情太薄。", "霎时云雨人抛却。", "教我行思坐想，肌肤如削。", "恨只恨、相违旧约。", "相思成病，那更潇潇雨落。", "断肠人在阑干角。", "山远水远人远，音信难托。", "这滋味、黄昏又恶。"]'),
('song-ci-262','醉垂鞭','张先','宋','宋词','song-ci','醉垂鞭','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','双蝶绣罗裙。',52,'宋词/ci.song.0.json','["双蝶绣罗裙。", "东池宴。", "初相见。", "朱粉不深匀。", "闲花淡淡春。", "细看诸处好。", "人人道。", "柳腰身。", "昨日乱山昏。", "来时衣上云。"]'),
('song-ci-263','醉垂鞭','张先','宋','宋词','song-ci','醉垂鞭','[]','朱粉不须施。',52,'宋词/ci.song.0.json','["朱粉不须施。", "花枝小。", "春偏好。", "娇妙近胜衣。", "轻罗红雾垂。", "琵琶金画凤。", "双条重。", "倦眉低。", "啄木细声迟。", "黄蜂花上飞。"]'),
('song-ci-264','南乡子','张先','宋','宋词','song-ci','南乡子','[]','何处可魂消。',66,'宋词/ci.song.0.json','["何处可魂消。", "京口终朝两信潮。", "不管离心千叠恨，滔滔。", "催促行人动去桡。", "记得旧江皋。", "绿杨轻絮几条条。", "春水一篙残照阔，遥遥。", "有个多情立画桥。"]'),
('song-ci-265','南乡子','张先','宋','宋词','song-ci','南乡子','[]','潮上水清浑。',66,'宋词/ci.song.0.json','["潮上水清浑。", "棹影轻於水底云。", "去意徘徊无奈泪，衣巾。", "犹有当时粉黛痕。", "海近古城昏。", "暮角寒沙雁队分。", "今夜相思应看月，无人。", "露冷依前独掩门。"]'),
('song-ci-266','菩萨蛮','张先','宋','宋词','song-ci','菩萨蛮','[]','忆郎还上层楼曲。',52,'宋词/ci.song.0.json','["忆郎还上层楼曲。", "楼前芳草年年绿。", "绿似去时袍。", "回头风袖飘。", "郎袍应已旧。", "颜色非长久。", "惜恐镜中春。", "不如花草新。"]'),
('song-ci-267','菩萨蛮','张先','宋','宋词','song-ci','菩萨蛮','[]','闻人语著仙卿字。',52,'宋词/ci.song.0.json','["闻人语著仙卿字。", "瞋情恨意还须喜。", "何况草长时。", "酒前频共伊。", "娇香堆宝帐。", "月到梨花上。", "心事两人知。", "掩灯罗幕垂。"]'),
('song-ci-268','菩萨蛮','张先','宋','宋词','song-ci','菩萨蛮','[]','夜深不至春蟾见。',52,'宋词/ci.song.0.json','["夜深不至春蟾见。", "令人更更情飞乱。", "翠幕动风亭。", "时疑响屉声。", "花香闻水榭。", "几误飘衣麝。", "不忍下朱扉。", "绕廊重待伊。"]'),
('song-ci-269','菩萨蛮','张先','宋','宋词','song-ci','菩萨蛮','[]','簟纹衫色娇黄浅。',52,'宋词/ci.song.0.json','["簟纹衫色娇黄浅。", "钗头秋叶玲珑翦。", "轻怯瘦腰身。", "纱窗病起人。", "相思魂欲绝。", "莫话新秋别。", "何处断离肠。", "西风昨夜凉。"]'),
('song-ci-270','踏莎行','张先','宋','宋词','song-ci','踏莎行','[]','衾凤犹温，笼鹦尚睡。',68,'宋词/ci.song.0.json','["衾凤犹温，笼鹦尚睡。", "宿妆稀淡眉成字。", "映花避月上行廊，珠裙摺摺轻垂地。", "翠幕成波，新荷贴水。", "纷纷烟柳低还起。", "重墙绕院更重门，春风无路通深意。"]'),
('song-ci-271','踏莎行','张先','宋','宋词','song-ci','踏莎行','[]','波湛横眸，霞分腻脸。',68,'宋词/ci.song.0.json','["波湛横眸，霞分腻脸。", "盈盈笑动笼香靥。", "有情未结凤楼欢，无憀爱把歌眉敛。", "密意欲传，娇羞未敢。", "斜偎象板还偷盰。", "轻轻试问借人麽，佯佯不觑云鬟点。"]'),
('song-ci-272','感皇恩','张先','宋','宋词','song-ci','感皇恩','[]','万乘靴袍御紫宸。',70,'宋词/ci.song.0.json','["万乘靴袍御紫宸。", "挥豪敷丽藻，尽经纶。", "第名天陛首平津。", "东堂桂，重占一枝春。", "殊观耸簪绅。", "蓬山仙话重，霈恩新。", "暂时趋府冠谈宾。", "十年外，身是凤池人。"]'),
('song-ci-273','西江月','张先','宋','宋词','song-ci','西江月','[]','体态看来隐约，梳妆好是家常。',58,'宋词/ci.song.0.json','["体态看来隐约，梳妆好是家常。", "檀槽初抱更安详。", "立向尊前一行。", "小打登钩怕重，尽缠绣带由长。", "娇春莺舌巧如簧。", "飞在四条弦上。"]'),
('song-ci-274','庆金枝','张先','宋','宋词','song-ci','庆金枝','[]','青螺添远山。',58,'宋词/ci.song.0.json','["青螺添远山。", "两娇靥、笑时圆。", "抱云勾雪近灯看。", "妍处不堪怜。", "今生但愿无离别，花月下、绣屏前。", "双蚕成茧共缠绵。", "更结后生缘。"]'),
('song-ci-275','浣溪沙','张先','宋','宋词','song-ci','浣溪沙','[]','轻屉来时不破尘。',48,'宋词/ci.song.0.json','["轻屉来时不破尘。", "石榴花映石榴裙。", "有情应得撞腮春。", "夜短更难留远梦，日高何计学行云。", "树深莺过静无人。"]'),
('song-ci-276','相思儿令','张先','宋','宋词','song-ci','相思儿令','[]','春去几时还。',54,'宋词/ci.song.0.json','["春去几时还。", "问桃李无言。", "燕子归栖风紧，梨雪乱西园。", "犹有月婵娟。", "似人人、难近如天。", "愿教清影长相见，更乞取长圆。"]'),
('song-ci-277','师师令','张先','宋','宋词','song-ci','师师令','[]','香钿宝珥。',87,'宋词/ci.song.0.json','["香钿宝珥。", "拂菱花如水。", "学妆皆道称时宜，粉色有、天然春意。", "蜀彩衣长胜未起。", "纵乱云垂地。", "都城池苑夸桃李。", "问东风何似。", "不须回扇障清歌，唇一点、小於珠子。", "正是残英和月坠。", "寄此情千里。"]'),
('song-ci-278','山亭宴慢・山亭宴','张先','宋','宋词','song-ci','山亭宴慢・山亭宴','[]','宴亭永昼喧箫鼓。',126,'宋词/ci.song.0.json','["宴亭永昼喧箫鼓。", "倚青空、画阑红柱。", "玉莹紫微人，蔼和气、春融日煦。", "故宫池馆更楼台，约风月、今宵何处。", "湖水动鲜衣，竞拾翠、湖边路。", "落花荡漾愁空树。", "晓山静、数声杜宇。", "天意送芳菲，正黯淡、疏烟逗雨。", "新欢宁似旧欢长，此会散、几时还聚。", "试为挹飞云，问解寄、相思否。"]'),
('song-ci-279','谢池春慢','张先','宋','宋词','song-ci','谢池春慢','[]','缭墙重院，时闻有、啼莺到。',112,'宋词/ci.song.0.json','["缭墙重院，时闻有、啼莺到。", "绣被掩馀寒，画幕明新晓。", "朱槛连空阔，飞絮无多少。", "径莎平，池水渺。", "日长风静，花影闲相照。", "尘香拂马，逢谢女、城南道。", "秀艳过施粉，多眉生轻笑。", "斗色鲜衣薄，碾玉双蝉小。", "欢难偶，春过了。", "琵琶流怨，都入相思调。"]'),
('song-ci-280','惜双双・惜分飞','张先','宋','宋词','song-ci','惜双双・惜分飞','[]','城上层楼天边路。',64,'宋词/ci.song.0.json','["城上层楼天边路。", "残照里、平芜绿树。", "伤远更惜春暮。", "有人还在高高处。", "断梦归云经日去。", "无计使、哀弦寄语。", "相望恨不相遇。", "倚桥临水谁家住。"]'),
('song-ci-281','江南柳','张先','宋','宋词','song-ci','江南柳','[]','隋堤远，波急路尘轻。',64,'宋词/ci.song.0.json','["隋堤远，波急路尘轻。", "今古柳桥多送别，见人分袂亦愁生。", "何况自关情。", "斜照后，新月上西城。", "城上楼高重倚望，愿身能似月亭亭。", "千里伴君行。"]'),
('song-ci-282','八宝装・八宝妆','张先','宋','宋词','song-ci','八宝装・八宝妆','[]','锦屏罗幌初睡起。',64,'宋词/ci.song.0.json','["锦屏罗幌初睡起。", "花阴转、重门闭。", "正不寒不暖，和风细雨，困人天气。", "此时无限伤春意。", "凭谁诉、厌厌地。", "这浅情薄幸，千山万水，也须来里。"]'),
('song-ci-283','一丛花令・一丛花','张先','宋','宋词','song-ci','一丛花令・一丛花','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','伤高怀远几时穷。',94,'宋词/ci.song.0.json','["伤高怀远几时穷。", "无物似情浓。", "离愁正引千丝乱，更东陌、飞絮濛濛。", "嘶骑渐遥，征尘不断，何处认郎踪。", "双鸳池沼水溶溶。", "南北小桡通。", "梯横画阁黄昏后，又还是、斜月帘栊。", "沈恨细思，不如桃杏，犹解嫁东风。"]'),
('song-ci-284','西江月','张先','宋','宋词','song-ci','西江月','[]','泛泛春船载乐，溶溶湖水平桥。',58,'宋词/ci.song.0.json','["泛泛春船载乐，溶溶湖水平桥。", "高鬟照影翠烟摇。", "白纻一声云杪。", "倦醉天然玉软，弄妆人惜花娇。", "风情遗恨几时消。", "不见卢郎年少。"]'),
('song-ci-285','感皇恩','张先','宋','宋词','song-ci','感皇恩','[]','廊庙当时共代工。',74,'宋词/ci.song.0.json','["廊庙当时共代工。", "睢陵千里远，约过从。", "欲知宾主与谁同。", "宗枝内，黄阁旧，有三公。", "广乐起云中。", "湖山看画轴，两仙翁。", "武林嘉语几时穷。", "元丰际，德星聚，照江东。"]'),
('song-ci-286','宴春台慢・宴春台','张先','宋','宋词','song-ci','宴春台慢・宴春台','[]','丽日千门，紫烟双阙，琼林又报春回。',121,'宋词/ci.song.0.json','["丽日千门，紫烟双阙，琼林又报春回。", "殿阁风微，当时去燕还来。", "五侯池馆频开。", "探芳菲、走马天街。", "重帘人语，辚辚绣轩，远近轻雷。", "雕觞霞滟，翠幕云飞，楚腰舞柳，宫面妆梅。", "金猊夜暖、罗衣暗裛香煤。", "洞府人归，放笙歌、灯火楼台。", "下蓬莱。", "犹有花上月，清影徘徊。"]'),
('song-ci-287','好事近','张先','宋','宋词','song-ci','好事近','[]','月色透横枝，短叶小花无力。',53,'宋词/ci.song.0.json','["月色透横枝，短叶小花无力。", "北客一声长笛，怨江南先得。", "谁教强半腊前开，多情为春忆。", "留取大家沈醉，正雨休风息。"]'),
('song-ci-288','好事近','张先','宋','宋词','song-ci','好事近','[]','灯烛上山堂，香雾暖生寒夕。',53,'宋词/ci.song.0.json','["灯烛上山堂，香雾暖生寒夕。", "前夜雪清梅瘦，已不禁轻摘。", "双歌声断宝杯空，妆光艳瑶席。", "相趁笑声归去，有随人月色。"]'),
('song-ci-289','清平乐','张先','宋','宋词','song-ci','清平乐','[]','屏山斜展。',54,'宋词/ci.song.0.json','["屏山斜展。", "帐卷红绡半。", "泥浅曲池飞海燕。", "风度杨花满院。", "云情雨意空深。", "觉来一枕春阴。", "陇上梅花落尽，江南消息沈沈。"]'),
('song-ci-290','清平乐','张先','宋','宋词','song-ci','清平乐','[]','清歌逐酒。',54,'宋词/ci.song.0.json','["清歌逐酒。", "腻脸生红透。", "樱小杏青寒食后。", "衣换缕金轻绣。", "画堂新月朱扉。", "严城夜鼓声迟。", "细看玉人娇面，春光不在花枝。"]'),
('song-ci-291','醉桃源・阮郎归','张先','宋','宋词','song-ci','醉桃源・阮郎归','[]','落花浮水树临池。',56,'宋词/ci.song.0.json','["落花浮水树临池。", "年前心眼期。", "见来无事去还思。", "如今花又飞。", "浅螺黛，淡胭脂。", "开花取次宜。", "隔帘灯影闭门时。", "此情风月知。"]'),
('song-ci-292','恨春迟','张先','宋','宋词','song-ci','恨春迟','[]','好梦才成又断。',70,'宋词/ci.song.0.json','["好梦才成又断。", "日晚起、云亸梳鬟。", "秀脸拂新红，酒入娇眉眼，薄衣减春寒。", "红柱溪桥波平岸。", "画阁外、落日西山。", "不分闲花并蒂，秋藕连根，何时重得双眠。"]'),
('song-ci-293','恨春迟','张先','宋','宋词','song-ci','恨春迟','[]','欲借红梅荐饮。',70,'宋词/ci.song.0.json','["欲借红梅荐饮。", "望陇驿、音信沈沈。", "住在柳州东岸，彼此相思，梦去难寻。", "乳燕来时花期寝。", "淡月坠、将晓还阴。", "争奈多情易感，音信无凭，如何消遣得初心。"]'),
('song-ci-294','庆佳节','张先','宋','宋词','song-ci','庆佳节','[]','莫风流。',63,'宋词/ci.song.0.json','["莫风流。", "莫风流。", "风流后、有闲愁。", "花满南园月满楼。", "偏使我、忆欢游。", "我忆欢游无计奈，除却且醉金瓯。", "醉了醒来春复秋。", "我心事、几时休。"]'),
('song-ci-295','庆佳节','张先','宋','宋词','song-ci','庆佳节','[]','芳菲节。',63,'宋词/ci.song.0.json','["芳菲节。", "芳菲节。", "天意应不虚设。", "对酒高歌玉壶阙。", "慎莫负、狂风月。", "人间万事何时歇。", "空赢得、鬓成雪。", "我有闲愁与君说。", "且莫用、轻离别。"]'),
('song-ci-296','采桑子','张先','宋','宋词','song-ci','采桑子','[]','水云薄薄天同色，竟日清辉。',52,'宋词/ci.song.0.json','["水云薄薄天同色，竟日清辉。", "风影轻飞。", "花发瑶林春未知。", "剡溪不辨沙头路，粉水平堤。", "姑射人归。", "记得歌声与舞时。"]'),
('song-ci-297','御街行','张先','宋','宋词','song-ci','御街行','[]','画船横倚烟溪半。',90,'宋词/ci.song.0.json','["画船横倚烟溪半。", "春入吴山遍。", "主人凭客且迟留，程入花溪远远。", "数声芦叶，两行霓袖，几处成离宴。", "纷纷归骑亭皋晚。", "风顺樯乌转。", "古今为别最消魂，因别有情须怨。", "更独自、尽上高台望，望尽飞云断。"]'),
('song-ci-298','玉联环・解连环','张先','宋','宋词','song-ci','玉联环・解连环','[]','都人未逐风云散。',57,'宋词/ci.song.0.json','["都人未逐风云散。", "愿留离宴。", "不须都爱洛城春，黄花讶、归来晚。", "叶落灞陵如翦。", "泪沾歌扇。", "无由重肯日边来，上马便、长安远。"]'),
('song-ci-299','玉联环・解连环','张先','宋','宋词','song-ci','玉联环・解连环','[]','来时露裛衣香润。',57,'宋词/ci.song.0.json','["来时露裛衣香润。", "彩绦垂鬓。", "卷帘还喜月相亲，把酒更、花相近。", "西去阳关休问。", "未歌先恨。", "玉峰山下水长流，流水尽、情无尽。"]'),
('song-ci-300','武陵春','张先','宋','宋词','song-ci','武陵春','[]','秋染青溪天外水，风棹采菱还。',56,'宋词/ci.song.0.json','["秋染青溪天外水，风棹采菱还。", "波上逢郎密意传。", "语近隔丛莲。", "相看忘却归来路，遮日小荷圆。", "菱蔓虽多不上船。", "心眼在郎边。"]'),
('song-ci-301','定风波','张先','宋','宋词','song-ci','定风波','[]','素藕抽条未放莲。',73,'宋词/ci.song.0.json','["素藕抽条未放莲。", "晚蚕将茧不成眠。", "若比相思如乱絮。", "何异。", "两心俱被暗丝牵。", "暂觉欲归还是恨。", "莫问。", "有情谁信道无缘。", "有似中秋云外月。", "皎洁。", "不团圆待几时圆。"]'),
('song-ci-302','百媚娘','张先','宋','宋词','song-ci','百媚娘','[]','珠阙五云仙子。',87,'宋词/ci.song.0.json','["珠阙五云仙子。", "未省有谁能似。", "百媚算应天乞与，净饰艳妆俱美。", "若取次芳华皆可意。", "何处比桃李。", "蜀被锦纹铺水。", "不放彩鸳双戏。", "乐事也知存后会，争奈眼前心里。", "绿皱小池红叠砌。", "花外东风起。"]'),
('song-ci-303','梦仙乡','张先','宋','宋词','song-ci','梦仙乡','[]','江东苏小。',64,'宋词/ci.song.0.json','["江东苏小。", "夭斜窈窕。", "都不胜、彩鸾娇妙。", "春艳上新妆。", "肌肉过人香。", "佳树阴阴池院。", "华灯绣幔。", "花月好、可能长见。", "离聚此生缘。", "无计问天天。"]'),
('song-ci-304','归朝欢','张先','宋','宋词','song-ci','归朝欢','[]','声转辘轳闻露井。',122,'宋词/ci.song.0.json','["声转辘轳闻露井。", "晓引银瓶牵素绠。", "西园人语夜来风，丛英飘坠红成径。", "宝猊烟未冷。", "莲台香蜡残痕凝。", "等身金，谁能得意，买此好光景。", "粉落轻妆红玉莹。", "月枕横钗云坠领。", "有情无物不双栖，文禽只合常交颈。", "昼长欢岂定。", "争如翻作春消永。", "日曈昽，娇柔懒起，帘押残花影。"]'),
('song-ci-305','相思令・相思儿令','张先','宋','宋词','song-ci','相思令・相思儿令','[]','苹满溪。',44,'宋词/ci.song.0.json','["苹满溪。", "柳绕堤。", "相送行人溪水西。", "回时陇月低。", "烟霏霏。", "风凄凄。", "重倚朱门听马嘶。", "寒鸥相对飞。"]'),
('song-ci-306','少年游','张先','宋','宋词','song-ci','少年游','[]','红叶黄花秋又老，疏雨更西风。',62,'宋词/ci.song.0.json','["红叶黄花秋又老，疏雨更西风。", "山重水远，云闲天淡，游子断肠中。", "青楼薄幸何时见，细说与、这忡忡。", "念远离情，感时愁绪，应解与人同。"]'),
('song-ci-307','贺圣朝','张先','宋','宋词','song-ci','贺圣朝','[]','淡黄衫子浓妆了。',57,'宋词/ci.song.0.json','["淡黄衫子浓妆了。", "步缕金鞋小。", "爱来书幌绿窗前，半和娇笑。", "谢家姊妹，诗名空杳。", "何曾机巧。", "争如奴道，春来情思，乱如芳草。"]'),
('song-ci-308','生查子','张先','宋','宋词','song-ci','生查子','[]','当初相见时，彼此心萧洒。',48,'宋词/ci.song.0.json','["当初相见时，彼此心萧洒。", "近日见人来，却恁相谩諕。", "休休休便休，美底教他且。", "匹似没伊时，更不思量也。"]'),
('song-ci-309','夜厌厌・夜行船','张先','宋','宋词','song-ci','夜厌厌・夜行船','[]','昨夜小筵欢纵。',67,'宋词/ci.song.0.json','["昨夜小筵欢纵。", "烛房深、舞鸾歌凤。", "酒迷花困共厌厌，倚朱弦、未成归弄。", "峡雨忽收寻断梦。", "依前是、画楼钟动。", "争拂雕鞍葱葱去，万千恨、不能相送。"]'),
('song-ci-310','迎春乐','张先','宋','宋词','song-ci','迎春乐','[]','城头画角催夕宴。',63,'宋词/ci.song.0.json','["城头画角催夕宴。", "忆前时、小楼晚。", "残虹数尺云中断。", "愁送目、天涯远。", "枕清风、停画扇。", "逗蛮簟、碧纱零乱。", "怎生得伊来，今夜里、银蟾满。"]'),
('song-ci-311','凤栖梧・蝶恋花','张先','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','密宴厌厌池馆暮。',70,'宋词/ci.song.0.json','["密宴厌厌池馆暮。", "天汉沈沈，借得春光住。", "红翠斗为长袖舞。", "香檀拍过惊鸿翥。", "明日不知花在否。", "今夜圆蟾，后夜忧风雨。", "可惜歌云容易去。", "东城杨柳东城路。"]'),
('song-ci-312','双燕儿','张先','宋','宋词','song-ci','双燕儿','[]','榴花帘外飘红。',62,'宋词/ci.song.0.json','["榴花帘外飘红。", "藕丝罩、小屏风。", "东山别后，高唐梦短，犹喜相逢。", "几时再与眠香翠，悔旧欢、何事匆匆。", "芳心念我，也应那里，蹙破眉峰。"]'),
('song-ci-313','卜算子慢','张先','宋','宋词','song-ci','卜算子慢','[]','溪山别意，烟树去程，日落采苹春晚。',106,'宋词/ci.song.0.json','["溪山别意，烟树去程，日落采苹春晚。", "欲上征鞍，更掩翠帘相眄。", "惜弯弯浅黛长长眼。", "奈画阁欢游，也学狂花乱絮轻散。", "水影横池馆。", "对静夜无人，月高云远。", "一饷凝思，两袖泪痕还满。", "恨私书、又逐东风断。", "纵西北层楼万尺，望重城那见。"]'),
('song-ci-314','更漏子','张先','宋','宋词','song-ci','更漏子','[]','锦筵红，罗幕翠。',58,'宋词/ci.song.0.json','["锦筵红，罗幕翠。", "侍宴美人姝丽。", "十五六，解怜才。", "劝人深酒杯。", "黛眉长，檀口小。", "耳畔向人轻道。", "柳阴曲，是儿家。", "门前红杏花。"]'),
('song-ci-315','更漏子','张先','宋','宋词','song-ci','更漏子','[]','相君家，宾宴集。',58,'宋词/ci.song.0.json','["相君家，宾宴集。", "秋叶晓霜红湿。", "帘额动，水纹浮。", "缬花相对流。", "薄霞衣，酣酒面。", "重抱琵琶轻按。", "回画拨，抹幺弦。", "一声飞露蝉。"]'),
('song-ci-316','南歌子','张先','宋','宋词','song-ci','南歌子','[]','醉后和衣倒，愁来殢酒醺。',62,'宋词/ci.song.0.json','["醉后和衣倒，愁来殢酒醺。", "困人天气近清明。", "尽日厌厌□脸、浅含颦。", "睡觉□□恨，依然月映门。", "楚天何处觅行云。", "唯有暗灯残漏、伴消魂。"]'),
('song-ci-317','南歌子','张先','宋','宋词','song-ci','南歌子','[]','蝉抱高高柳，莲开浅浅波。',62,'宋词/ci.song.0.json','["蝉抱高高柳，莲开浅浅波。", "倚风疏叶下庭柯。", "况是不寒不暖、正清和。", "浮世欢会少，劳生怨别多。", "相逢休惜醉颜酡。", "赖有西园明月、照笙歌。"]'),
('song-ci-318','南歌子','张先','宋','宋词','song-ci','南歌子','[]','残照催行棹，乘春拂去衣。',62,'宋词/ci.song.0.json','["残照催行棹，乘春拂去衣。", "海棠花下醉芳菲。", "无计少留君住、泪双垂。", "烟染春江暮，云藏阁道危。", "行行听取杜鹃啼。", "是妾此时离恨、尽呼伊。"]'),
('song-ci-319','蝶恋花','张先','宋','宋词','song-ci','蝶恋花','[]','临水人家深宅院。',70,'宋词/ci.song.0.json','["临水人家深宅院。", "阶下残花，门外斜阳岸。", "柳舞麴尘千万线。", "青楼百尺临天半。", "楼上东风春不浅。", "十二阑干，尽日珠帘卷。", "有个离人凝泪眼。", "淡烟芳草连云远。"]'),
('song-ci-320','蝶恋花','张先','宋','宋词','song-ci','蝶恋花','[]','槛菊愁烟兰泣露。',70,'宋词/ci.song.0.json','["槛菊愁烟兰泣露。", "罗幕轻寒，燕子双来去。", "明月不谙离恨苦。", "斜光到晓穿朱户。", "昨夜西风雕碧树。", "独上高楼，望尽天涯路。", "欲寄彩笺兼尺素。", "山长水阔知何处。"]'),
('song-ci-321','蝶恋花','张先','宋','宋词','song-ci','蝶恋花','[]','绿水波平花烂漫。',70,'宋词/ci.song.0.json','["绿水波平花烂漫。", "照影红妆，步转垂杨岸。", "别后深情将为断。", "相逢添得人留恋。", "絮软丝轻无系绊。", "烟惹风迎，并入春心乱。", "和泪语娇声又颤。", "行行尽远犹回面。"]'),
('song-ci-322','蝶恋花','张先','宋','宋词','song-ci','蝶恋花','[]','移得绿杨栽后院。',70,'宋词/ci.song.0.json','["移得绿杨栽后院。", "学舞宫腰，二月青犹短。", "不比灞陵多送远。", "残丝乱絮东西岸。", "几叶小眉寒不展。", "莫唱阳关，真个肠先断。", "分付与春休细看。", "条条尽是离人怨。"]'),
('song-ci-323','诉衷情','张先','宋','宋词','song-ci','诉衷情','[]','花前月下暂相逢。',54,'宋词/ci.song.0.json','["花前月下暂相逢。", "苦恨阻从容。", "何况酒醒梦断，花谢月朦胧。", "花不尽，月无穷。", "两心同。", "此时愿作，杨柳千丝，绊惹春风。"]'),
('song-ci-324','诉衷情','张先','宋','宋词','song-ci','诉衷情','[]','数枝金菊对芙蓉。',54,'宋词/ci.song.0.json','["数枝金菊对芙蓉。", "零落意忡忡。", "不知多少幽怨，和泪泣东风。", "人散后，月明中。", "夜寒浓。", "谢娘愁卧，潘令闲眠，往事何穷。"]'),
('song-ci-325','木兰花・玉楼春','张先','宋','宋词','song-ci','木兰花・玉楼春','["\u897f\u6e56"]','青钱贴水萍无数。',64,'宋词/ci.song.0.json','["青钱贴水萍无数。", "临晓西湖春涨雨。", "泥新轻燕面前飞，风慢落花衣上住。", "红裙空引烟娥聚。", "云月却能随马去。", "明朝何处上高台，回认玉峰山下路。"]'),
('song-ci-326','木兰花・玉楼春','张先','宋','宋词','song-ci','木兰花・玉楼春','["\u897f\u6e56"]','西湖杨柳风流绝。',64,'宋词/ci.song.0.json','["西湖杨柳风流绝。", "满缕青春看赠别。", "墙头簌簌暗飞花，山外阴阴初落月。", "秦姬秾丽云梳发。", "持酒唱歌留晚发。", "骊驹应解恼人情，欲出重城嘶不歇。"]'),
('song-ci-327','木兰花・玉楼春','张先','宋','宋词','song-ci','木兰花・玉楼春','[]','楼下雪飞楼上宴。',64,'宋词/ci.song.0.json','["楼下雪飞楼上宴。", "歌咽笙簧声韵颤。", "尊前有个好人人，十二阑干同倚遍。", "帘重不知金屋晚。", "信马归来肠欲断。", "多情无奈苦相思，醉眼开时犹似见。"]'),
('song-ci-328','减字木兰花','张先','宋','宋词','song-ci','减字木兰花','[]','垂螺近额。',52,'宋词/ci.song.0.json','["垂螺近额。", "走上红裀初趁拍。", "只恐轻飞。", "拟倩游丝惹住伊。", "文鸳绣履。", "去似杨花尘不起。", "舞彻伊州。", "头上宫花颤未休。"]'),
('song-ci-329','少年游','张先','宋','宋词','song-ci','少年游','[]','碎霞浮动晓朦胧。',60,'宋词/ci.song.0.json','["碎霞浮动晓朦胧。", "春意与花浓。", "银瓶素绠，玉泉金甃，真色浸朝红。", "花枝人面难常见，青子小丛丛。", "韶华长在，明年依旧，相与笑春风。"]'),
('song-ci-330','少年游','张先','宋','宋词','song-ci','少年游','[]','帽檐风细马蹄尘。',60,'宋词/ci.song.0.json','["帽檐风细马蹄尘。", "常记探花人。", "露英千样，粉香无尽，蓦地酒初醒。", "探花人向花前老，花上旧时春。", "行歌声外，靓妆丛里，须贵少年身。"]'),
('song-ci-331','醉落魄・一斛珠','张先','宋','宋词','song-ci','醉落魄・一斛珠','[]','云轻柳弱。',67,'宋词/ci.song.0.json','["云轻柳弱。", "内家髻要新梳掠。", "生香真色人难学。", "横管孤吹，月淡天垂暮。", "朱唇浅破桃花萼。", "倚楼谁在阑干角。", "夜寒手冷罗衣薄。", "声入霜林，簌簌惊梅落。"]'),
('song-ci-332','喜朝天・踏莎行','张先','宋','宋词','song-ci','喜朝天・踏莎行','[]','晓云开。',125,'宋词/ci.song.0.json','["晓云开。", "睨仙馆陵虚，步入蓬莱。", "玉宇琼甃，对青林近，归鸟徘徊。", "风月顿消清暑，野色对、江山助诗才。", "潇鼓宴，璇题宝字，浮动持杯。", "人多送目天际，识渡舟帆小，时见潮回。", "故国千里，共十万室，日日春台。", "睢社朝京非远，正和羹、民口渴盐梅。", "佳景在，吴侬还望，分阃重来。"]'),
('song-ci-333','破阵乐','张先','宋','宋词','song-ci','破阵乐','["\u897f\u6e56"]','四堂互映，双门并丽，龙阁开府。',166,'宋词/ci.song.0.json','["四堂互映，双门并丽，龙阁开府。", "郡美东南第一，望故苑、楼台霏雾。", "垂柳池塘，流泉巷陌，吴歌处处。", "近黄昏，渐更宜良夜，簇簇繁星灯烛，长衢如昼，暝色韶光，几许粉面，飞甍朱户。", "和煦。", "雁齿桥红，裙腰草绿，云际寺、林下路。", "酒熟梨花宾客醉，但觉满山潇鼓。", "尽朋游、同民乐，芳菲有主。", "自此归从泥诏，去指沙堤，南屏水石，西湖风月，好作千骑行春，画图写取。"]'),
('song-ci-334','菊花新','张先','宋','宋词','song-ci','菊花新','[]','堕髻慵妆来日暮。',63,'宋词/ci.song.0.json','["堕髻慵妆来日暮。", "家在画桥堤下住。", "衣缓绛绡垂，琼树袅、一枝红雾。", "院深池静娇相妒。", "粉墙低、乐声时度。", "长恐舞筵空，轻化作、彩云飞去。"]'),
('song-ci-335','虞美人','张先','宋','宋词','song-ci','虞美人','[]','苕花飞尽汀风定。',66,'宋词/ci.song.0.json','["苕花飞尽汀风定。", "苕水天摇影。", "画船罗绮满溪春。", "一曲石城清响、入高云。", "壶觞昔岁同歌舞。", "今日无欢侣。", "南园花少故人稀。", "月照玉楼依旧、似当时。"]'),
('song-ci-336','醉红妆','张先','宋','宋词','song-ci','醉红妆','[]','琼枝玉树不相饶。',64,'宋词/ci.song.0.json','["琼枝玉树不相饶。", "薄云衣、细柳腰。", "一般妆样百般娇。", "眉眼细、好如描。", "东风摇草百花飘。", "恨无计、上青条。", "更起双歌郎且饮，郎未醉、有金貂。"]'),
('song-ci-337','天仙子','张先','宋','宋词','song-ci','天仙子','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','水调数声持酒听。',80,'宋词/ci.song.0.json','["水调数声持酒听。", "午醉醒来愁未醒。", "送春春去几时回，临晚镜。", "伤流景。", "往事后期空记省。", "沙上并禽池上暝。", "云破月来花弄影。", "重重帘幕密遮灯，风不定。", "人初静。", "明日落红应满径。"]'),
('song-ci-338','天仙子','张先','宋','宋词','song-ci','天仙子','[]','持节来时初有雁。',80,'宋词/ci.song.0.json','["持节来时初有雁。", "十万人家春已满。", "龙标名第凤池身，堂阜远。", "江桥晚。", "一见湖山看未遍。", "障扇欲收歌泪溅。", "亭下花空罗绮散。", "樯竿渐向望中疏，旗影转。", "鼙声断。", "惆怅不如船尾燕。"]'),
('song-ci-339','菩萨蛮','张先','宋','宋词','song-ci','菩萨蛮','[]','玉人又是匆匆去。',52,'宋词/ci.song.0.json','["玉人又是匆匆去。", "马蹄何处垂杨路。", "残日倚楼时。", "断魂郎未知。", "阑干移倚遍。", "薄幸教人怨。", "明月却多情。", "随人处处行。"]'),
('song-ci-340','怨春风・一斛珠','张先','宋','宋词','song-ci','怨春风・一斛珠','[]','无由且住。',67,'宋词/ci.song.0.json','["无由且住。", "绵绵恨似春蚕绪。", "见来时饷还须去。", "月浅灯收，多在偷期处。", "今夜掩妆花下语。", "明朝芳草东西路。", "愿身不学相思树。", "但愿罗衣，化作双飞羽。"]'),
('song-ci-341','于飞乐令・于飞乐','张先','宋','宋词','song-ci','于飞乐令・于飞乐','[]','宝奁开，菱鉴静，一掏清蟾。',93,'宋词/ci.song.0.json','["宝奁开，菱鉴静，一掏清蟾。", "新妆脸、旋学花添。", "蜀红衫，双绣蝶，裙缕鹣鹣。", "寻思前事，小屏风、巧画江南。", "怎空教、草解宜男。", "柔桑暗、又过春蚕。", "正阴晴天气，更暝色相兼。", "幽期消息，曲房西、碎月筛帘。"]'),
('song-ci-342','临江仙','张先','宋','宋词','song-ci','临江仙','[]','自古伤心惟远别，登山临水迟留。',68,'宋词/ci.song.0.json','["自古伤心惟远别，登山临水迟留。", "暮尘衰草一番秋。", "寻常景物，到此尽成愁。", "况与佳人分凤侣，盈盈粉泪难收。", "高城深处是青楼。", "红尘远道，明日忍回头。"]'),
('song-ci-343','江城子','张先','宋','宋词','song-ci','江城子','[]','镂牙歌板齿如犀。',43,'宋词/ci.song.0.json','["镂牙歌板齿如犀。", "串珠齐。", "画桥西。", "杂花池院，风幕卷金泥。", "酒入四肢波入鬓，娇不尽，翠眉低。"]'),
('song-ci-344','转声虞美人・桃源忆故人','张先','宋','宋词','song-ci','转声虞美人・桃源忆故人','[]','使君欲醉离亭酒。',56,'宋词/ci.song.0.json','["使君欲醉离亭酒。", "酒醒离愁转有。", "紫禁多时虚右。", "苕霄留难久。", "一声歌掩双罗袖。", "日落乱山春后。", "犹有东城烟柳。", "青荫长依旧。"]'),
('song-ci-345','燕归梁','张先','宋','宋词','song-ci','燕归梁','[]','去岁中秋玩桂轮。',62,'宋词/ci.song.0.json','["去岁中秋玩桂轮。", "河汉净无云。", "今年江上共瑶尊。", "都不是、去年人。", "水精宫殿，琉璃台阁，红翠两行分。", "点唇机动秀眉颦。", "清影外、见微尘。"]'),
('song-ci-346','燕归梁','张先','宋','宋词','song-ci','燕归梁','[]','夜月啼乌促乱弦。',62,'宋词/ci.song.0.json','["夜月啼乌促乱弦。", "江树远无烟。", "缺多圆少奈何天。", "愁只恐、下关山。", "粉香生润，衣珠弄彩，人月两蝉娟。", "留连残夜惜馀欢。", "人月在、又明年。"]'),
('song-ci-347','定西番','张先','宋','宋词','song-ci','定西番','[]','年少登瀛词客，飘逸气，拂晴霓。',50,'宋词/ci.song.0.json','["年少登瀛词客，飘逸气，拂晴霓。", "尽带江南春色、过长淮。", "一曲艳歌留别，翠蝉摇宝钗。", "此后吴姬难见、且徘徊。"]'),
('song-ci-348','河传','张先','宋','宋词','song-ci','河传','[]','花暮。',63,'宋词/ci.song.0.json','["花暮。", "春去。", "都门东路。", "嘶马将行。", "江南江北，十里五里邮亭。", "几程程。", "高城望远看回睇。", "烟细。", "晚碧空无际。", "今夜何处，冷落衾帏。", "欲眠时。"]'),
('song-ci-349','偷声木兰花','张先','宋','宋词','song-ci','偷声木兰花','[]','雪笼琼苑梅花瘦。',58,'宋词/ci.song.0.json','["雪笼琼苑梅花瘦。", "外院重扉联宝兽。", "海月新生。", "上得高楼无奈情。", "帘波不动凝釭小。", "今夜夜长争得晓。", "欲梦高唐。", "只恐觉来添断肠。"]'),
('song-ci-350','偷声木兰花','张先','宋','宋词','song-ci','偷声木兰花','[]','画桥浅映横塘路。',58,'宋词/ci.song.0.json','["画桥浅映横塘路。", "流水滔滔春共去。", "目送残晖。", "燕子双高蝶对飞。", "风花将尽持杯送。", "往事只成清夜梦。", "莫更登楼。", "坐想行思已是愁。"]'),
('song-ci-351','醉桃源・阮郎归','张先','宋','宋词','song-ci','醉桃源・阮郎归','[]','双花连袂近香猊。',56,'宋词/ci.song.0.json','["双花连袂近香猊。", "歌随镂板齐。", "分明珠索漱烟溪。", "凝云定不飞。", "唇破点，齿编犀。", "春莺莫乱啼。", "阳关更在碧峰西。", "相看翠黛低。"]'),
('song-ci-352','千秋岁','张先','宋','宋词','song-ci','千秋岁','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','数声鶗鴂。',87,'宋词/ci.song.0.json','["数声鶗鴂。", "又报芳菲歇。", "惜春更把残红折。", "雨轻风色暴，梅子青时节。", "永丰柳，无人尽日飞花雪。", "莫把幺弦拨。", "怨极弦能说。", "天不老，情难绝。", "心似双丝网，中有千千结。", "夜过也，东窗未白凝残月。"]'),
('song-ci-353','天仙子','张先','宋','宋词','song-ci','天仙子','[]','醉笑相逢能几度。',80,'宋词/ci.song.0.json','["醉笑相逢能几度。", "为报江头春且住。", "主人今日是行人，红袖舞。", "清歌女。", "凭仗东风教点取。", "三月柳枝柔似缕。", "落絮尽飞还恋树。", "有情宁不忆西园，莺解语。", "花无数。", "应讶使君何处去。"]'),
('song-ci-354','渔家傲','张先','宋','宋词','song-ci','渔家傲','[]','巴子城头青草暮。',72,'宋词/ci.song.0.json','["巴子城头青草暮。", "巴山重叠相逢处。", "燕子占巢花脱树。", "杯且举。", "瞿塘水阔舟难渡。", "天外吴门清霅路。", "君家正在吴门住。", "赠我柳枝情几许。", "春满缕。", "为君将入江南去。"]'),
('song-ci-355','天仙子','张先','宋','宋词','song-ci','天仙子','[]','十岁手如芽子笋。',80,'宋词/ci.song.0.json','["十岁手如芽子笋。", "固爱弄妆偷傅粉。", "金蕉并为舞时空，红脸嫩。", "轻衣褪。", "春重日浓花觉困。", "斜雁轧弦随步趁。", "小凤累珠光绕鬓。", "密教持履恐仙飞，催拍紧。", "惊鸿奔。", "风袂飘摇无定准。"]'),
('song-ci-356','天仙子','张先','宋','宋词','song-ci','天仙子','[]','坐治吴州成乐土。',80,'宋词/ci.song.0.json','["坐治吴州成乐土。", "诏卷风飞来圣语。", "亲舆乞得便藩归，瑶席主。", "杯休数。", "清夜为君歌白苎。", "花接旧枝新蕊吐。", "造化不知人有助。", "看花岁岁比甘棠，嘉月暮。", "东门路。", "只恐带将春色去。"]'),
('song-ci-357','南乡子','张先','宋','宋词','song-ci','南乡子','[]','相并细腰身。',66,'宋词/ci.song.0.json','["相并细腰身。", "时样宫妆一样新。", "曲项胡琴鱼尾拨，离人。", "入塞弦声水上闻。", "天碧染衣巾。", "血色轻罗碎摺裙。", "百卉已随霜女妒，东君。", "暗折双花借小春。"]'),
('song-ci-358','少年游','张先','宋','宋词','song-ci','少年游','[]','听歌持酒且休行。',60,'宋词/ci.song.0.json','["听歌持酒且休行。", "云树几程程。", "眼看檐牙，手搓花蕊，未必两无情。", "拓夫滩上闻新雁，离袖掩盈盈。", "此恨无穷，远如江水，东去几时平。"]'),
('song-ci-359','定风波令・定风波','张先','宋','宋词','song-ci','定风波令・定风波','[]','碧玉篦扶坠髻云。',73,'宋词/ci.song.0.json','["碧玉篦扶坠髻云。", "莺黄衫子退红裙。", "妆样巧将花草竞。", "相并。", "要教人意胜於春。", "酒眼茸茸香拂面。", "□见。", "丹青宁似镜中真。", "自是有情偏小小。", "向道。", "江东谁信更无人。"]'),
('song-ci-360','定风波令・定风波','张先','宋','宋词','song-ci','定风波令・定风波','[]','浴殿词臣亦议兵。',73,'宋词/ci.song.0.json','["浴殿词臣亦议兵。", "禁中颇牧党羌平。", "诏卷促归难自缓。", "溪馆。", "彩花千数酒泉清。", "春草未青秋叶暮。", "□去。", "一家行色万家情。", "可恨黄莺相识晚。", "望断。", "湖边亭上不闻声。"]'),
('song-ci-361','定风波令・定风波','张先','宋','宋词','song-ci','定风波令・定风波','[]','谈辨才疏堂上兵。',73,'宋词/ci.song.0.json','["谈辨才疏堂上兵。", "画船齐岸暗潮平。", "万乘靴袍曾好问。", "须信。", "文章传口齿牙清。", "三百寺应游未遍。", "□算。", "湖山风物岂无情。", "不独渠丘歌叔度。", "行路。", "吴谣终日有馀声。"]'),
('song-ci-362','定风波令・定风波','张先','宋','宋词','song-ci','定风波令・定风波','[]','西阁明呈奉诏行。',73,'宋词/ci.song.0.json','["西阁明呈奉诏行。", "南床吏部锦衣荣。", "中有瀛仙宾与主。", "相遇。", "平津选首更神清。", "溪上玉楼同宴喜。", "欢醉。", "对堤杯叶惜秋英。", "尽道贤人聚吴分。", "试问。", "也应旁有老人星。"]'),
('song-ci-363','木兰花・玉楼春','张先','宋','宋词','song-ci','木兰花・玉楼春','[]','人意共怜花月满。',64,'宋词/ci.song.0.json','["人意共怜花月满。", "花好月圆人又散。", "欢情去逐远云空，往事过如幽梦断。", "草树争春红影乱。", "一唱鸡声千万怨。", "任教迟日更添长，能得几时抬眼看。"]'),
('song-ci-364','木兰花・玉楼春','张先','宋','宋词','song-ci','木兰花・玉楼春','[]','相离徒有相逢梦。',64,'宋词/ci.song.0.json','["相离徒有相逢梦。", "门外马蹄尘已动。", "怨歌留待醉时听，远目不堪空际送。", "今宵风月知谁共。", "声咽琵琶槽上凤。", "人生无物比多情，江水不深山不重。"]'),
('song-ci-365','木兰花・玉楼春','张先','宋','宋词','song-ci','木兰花・玉楼春','[]','檀槽碎响金丝拨。',64,'宋词/ci.song.0.json','["檀槽碎响金丝拨。", "露湿浔阳江上月。", "不知商妇为谁愁，一曲行人留晚发。", "画堂花入新声别。", "红蕊调高弹未彻。", "暗将深意语胶弦，长愿弦丝无断绝。"]'),
('song-ci-366','木兰花・玉楼春','张先','宋','宋词','song-ci','木兰花・玉楼春','[]','插花劝酒盐桥馆。',64,'宋词/ci.song.0.json','["插花劝酒盐桥馆。", "召节促行龙阙远。", "吴船渐起晚潮生，蛮榼未空寒日短。", "庆门奕世隆宸眷。", "归到月陂梅已绽。", "有情愿寄向南枝，图得洛阳春色看。"]'),
('song-ci-367','木兰花・玉楼春','张先','宋','宋词','song-ci','木兰花・玉楼春','[]','去年春入芳菲国。',64,'宋词/ci.song.0.json','["去年春入芳菲国。", "青蕊如梅终忍摘。", "阑边徒欲说相思，绿蜡密缄朱粉饰。", "归来故苑重寻觅。", "花满旧枝心更惜。", "鸳鸯从小自相双，若不多情头不白。"]'),
('song-ci-368','木兰花・玉楼春','张先','宋','宋词','song-ci','木兰花・玉楼春','[]','龙头舴艋吴儿竞。',64,'宋词/ci.song.0.json','["龙头舴艋吴儿竞。", "笋柱秋千游女并。", "芳洲拾翠暮忘归，秀野踏青来不定。", "行云去后遥山暝。", "已放笙歌池院静。", "中庭月色正清明，无数杨花过无影。"]'),
('song-ci-369','木兰花・玉楼春','张先','宋','宋词','song-ci','木兰花・玉楼春','[]','轻牙低掌随声听。',64,'宋词/ci.song.0.json','["轻牙低掌随声听。", "合调破空云自凝。", "姝娘翠黛有人描，琼女分鬟待谁并。", "弄妆俱学闲心性。", "固向鸾台同照影。", "双头莲子一时花，天碧秋池水如镜。"]'),
('song-ci-370','倾杯・倾杯乐','张先','宋','宋词','song-ci','倾杯・倾杯乐','[]','横塘水静，花窥影、孤城转。',133,'宋词/ci.song.0.json','["横塘水静，花窥影、孤城转。", "浮玉无尘，五亭争景，画桥对起，垂虹不断。", "爱溪上琼楼，凭雕栏、久□飞云远。", "人在虚空，月生溟海，寒渔夜泛，游鳞可辨。", "正是草长苹老，江南地暖。", "汀洲日晚。", "更茶山、已过清明，风雨暴千岩、啼鸟怨。", "芳菲故苑。", "深红尽、绿叶阴浓，青子枝头满。", "史君莫放寻春缓。"]'),
('song-ci-371','倾杯・倾杯乐','张先','宋','宋词','song-ci','倾杯・倾杯乐','[]','飞云过尽，明河浅、天无畔。',133,'宋词/ci.song.0.json','["飞云过尽，明河浅、天无畔。", "草色栖萤，霜华清暑，轻飔弄袂，澄澜拍岸。", "宴玉麈谈宾，倚琼枝、秀挹雕觞满。", "午夜中秋，十分圆月，香槽拨凤，朱弦轧雁。", "正是欲醒还醉，临空怅远。", "壶更叠换。", "对东西、数里回塘，恨零落芙蓉、春不管。", "笼灯待散。", "谁知道、座有离人，目断双歌伴。", "烟江艇子归来晚。"]'),
('song-ci-372','离亭宴','张先','宋','宋词','song-ci','离亭宴','[]','捧黄封诏卷。',92,'宋词/ci.song.0.json','["捧黄封诏卷。", "随处是、离亭别宴。", "红翠成轮歌未遍。", "已恨野桥风便。", "此去济南非久，惟有凤池鸾殿。", "三月花飞几片。", "又减却、芳菲过半。", "千里恩深云海浅。", "民爱比、春流不断。", "更上玉楼西，归雁与、征帆共远。"]'),
('song-ci-373','沁园春','张先','宋','宋词','song-ci','沁园春','[]','心膂良臣，帷幄元勋，左右万几。',142,'宋词/ci.song.0.json','["心膂良臣，帷幄元勋，左右万几。", "暂武林分阃，东南外翰，锦衣乡社，未满瓜时。", "易镇梧台，宣条期岁，又西指夷桥千骑移。", "珠滩上，喜甘棠翠荫，依旧春晖。", "须知。", "系国安危。", "料节召、还趋浴凤池。", "且代工施化，持钧播泽，置盂天下，此外何思。", "素卷书名，赤松游道，飙驭云軿仙可期。", "湖山美，有啼猿唳鹤，相望东归。"]'),
('song-ci-374','感皇恩','张先','宋','宋词','song-ci','感皇恩','[]','延寿芸香七世孙。',74,'宋词/ci.song.0.json','["延寿芸香七世孙。", "华轩承大对，见经纶。", "溟鱼一息化天津。", "袍如草，三百骑，从清尘。", "玉树莹风神。", "同时棠棣萼，一家春。", "十年身是凤池人。", "蓬莱阁，黄合主，迟谈宾。"]'),
('song-ci-375','忆秦娥','张先','宋','宋词','song-ci','忆秦娥','[]','参差竹。',50,'宋词/ci.song.0.json','["参差竹。", "吹断相思曲。", "情不足。", "西北有楼穷远目。", "忆苕溪、寒影透清玉。", "秋雁南飞速。", "菰草绿。", "应下溪头沙上宿。"]'),
('song-ci-376','系裙腰','张先','宋','宋词','song-ci','系裙腰','[]','惜霜蟾照夜云天。',75,'宋词/ci.song.0.json','["惜霜蟾照夜云天。", "朦胧影、画勾阑。", "人情纵是长情月，算一年年。", "又能得、几番圆。", "欲寄西江题叶字，流不到、五亭前。", "东池始有荷新绿，尚小如钱。", "问何日藕、几时莲。"]'),
('song-ci-377','清平乐','张先','宋','宋词','song-ci','清平乐','[]','青袍如草。',54,'宋词/ci.song.0.json','["青袍如草。", "得意还年少。", "马跃绿螭金络脑。", "寒食乍临新晓。", "曲池斜度鸾桥。", "西园一片笙箫。", "自欲剩留春住，风花无奈飘飘。"]'),
('song-ci-378','偷声木兰花','张先','宋','宋词','song-ci','偷声木兰花','[]','曾居别乘康吴俗。',58,'宋词/ci.song.0.json','["曾居别乘康吴俗。", "民到於今歌不足。", "骊驭征鞭。", "一去东风十二年。", "重来却拥诸侯骑。", "宝带垂鱼金照地。", "和气融人。", "清霅千家日日春。"]'),
('song-ci-379','菩萨蛮','张先','宋','宋词','song-ci','菩萨蛮','[]','佳人学得平阳曲。',52,'宋词/ci.song.0.json','["佳人学得平阳曲。", "纤纤玉笋横孤竹。", "一弄入云声。", "海门江月清。", "髻摇金钿落。", "惜恐樱唇薄。", "听罢已依依。", "莫吹杨柳枝。"]'),
('song-ci-380','菩萨蛮','张先','宋','宋词','song-ci','菩萨蛮','[]','藕丝衫翦猩红窄。',52,'宋词/ci.song.0.json','["藕丝衫翦猩红窄。", "衫轻不碍琼肤白。", "缦鬓小横波。", "花楼东是家。", "上湖闲荡桨。", "粉艳芙蓉样。", "湖水亦多情。", "照妆天底清。"]'),
('song-ci-381','菩萨蛮','张先','宋','宋词','song-ci','菩萨蛮','[]','牛星织女年年别。',52,'宋词/ci.song.0.json','["牛星织女年年别。", "分明不及人间物。", "匹鸟少孤飞。", "断沙犹并栖。", "洗车昏雨过。", "缺月云中堕。", "斜汉晓依依。", "暗蛩还促机。"]'),
('song-ci-382','菩萨蛮','张先','宋','宋词','song-ci','菩萨蛮','[]','双针竞引双丝缕。',52,'宋词/ci.song.0.json','["双针竞引双丝缕。", "家家尽道迎牛女。", "不见渡河时。", "空闻乌鹊飞。", "西南低片月。", "应恐云梳发。", "寄语问星津。", "谁为得巧人。"]'),
('song-ci-383','庆春泽','张先','宋','宋词','song-ci','庆春泽','[]','飞阁危桥相倚。',80,'宋词/ci.song.0.json','["飞阁危桥相倚。", "人独立东风，满衣轻絮。", "还记忆江南，如今天气。", "正白苹花，绕堤涨流水。", "寒梅落尽谁寄。", "方春意无穷，青空千里。", "愁草树依依，关城初闭。", "对月黄昏，角声傍烟起。"]'),
('song-ci-384','庆春泽','张先','宋','宋词','song-ci','庆春泽','[]','艳色不须妆样。',80,'宋词/ci.song.0.json','["艳色不须妆样。", "风韵好天真，画毫难上。", "花影滟金尊，酒泉生浪。", "镇欲留春，傍花为春唱。", "银塘玉宇空旷。", "冰齿映轻唇，蕊红新放。", "声宛转，疑随烟香悠扬。", "对暮林静，寥寥振清响。"]'),
('song-ci-385','玉联环・解连环','张先','宋','宋词','song-ci','玉联环・解连环','[]','南园已恨归来晚。',58,'宋词/ci.song.0.json','["南园已恨归来晚。", "芳菲满眼。", "春工偏上好花多，疑不向、空枝暖。", "惜恐红云易散。", "丛丛看遍。", "当时犹有蕊如梅，问几日上、东风绽。"]'),
('song-ci-386','玉树后庭花・后庭花','张先','宋','宋词','song-ci','玉树后庭花・后庭花','[]','华灯火树红相斗。',52,'宋词/ci.song.0.json','["华灯火树红相斗。", "往来如昼。", "桥河水白天青，讶别生星斗。", "落梅秾李还依旧。", "宝钗沽酒。", "晓蟾残漏心情，恨雕鞍归后。"]'),
('song-ci-387','玉树后庭花・后庭花','张先','宋','宋词','song-ci','玉树后庭花・后庭花','[]','宝床香重春眠觉。',52,'宋词/ci.song.0.json','["宝床香重春眠觉。", "魫窗难晓。", "新声丽色千人，歌后庭清妙。", "青骢一骑来飞鸟。", "靓妆难好。", "至今落日寒蟾，照台城秋草。"]'),
('song-ci-388','卜算子','张先','宋','宋词','song-ci','卜算子','[]','梦断寒夜长，坐待清霜晓。',56,'宋词/ci.song.0.json','["梦断寒夜长，坐待清霜晓。", "临镜无人为整妆，但自学、孤鸾照。", "楼台红树杪。", "风月依前好。", "江水东流郎在西，问尺素、何由到。"]'),
('song-ci-389','双韵子','张先','宋','宋词','song-ci','双韵子','[]','鸣鞘电过晓闱静。',61,'宋词/ci.song.0.json','["鸣鞘电过晓闱静。", "敛龙旗风定。", "凤楼远出霏烟，闻笑语、中天迥。", "清光近。", "欢声竟。", "鸳鸯集、仙花斗影。", "更闻度曲瑶山，升瑞日、春宫永。"]'),
('song-ci-390','鹊桥仙','张先','宋','宋词','song-ci','鹊桥仙','[]','星桥火树，长安一夜，开遍红莲万蕊。',68,'宋词/ci.song.0.json','["星桥火树，长安一夜，开遍红莲万蕊。", "绮罗能借月中春，风露细、天清似水。", "重城闭月，青楼夸乐，人在银潢影里。", "画屏期约近收灯，归步急、双鸳欲起。"]'),
('song-ci-391','醉垂鞭','张先','宋','宋词','song-ci','醉垂鞭','[]','酒面滟金鱼。',52,'宋词/ci.song.0.json','["酒面滟金鱼。", "吴娃唱。", "吴潮上。", "玉殿白麻书。", "待君归后除。", "勾留风月好。", "平湖晓。", "翠峰孤。", "此景出关无。", "西州空画图。"]'),
('song-ci-392','定西番','张先','宋','宋词','song-ci','定西番','[]','秀眼谩生千媚，钗玉重，髻云低。',50,'宋词/ci.song.0.json','["秀眼谩生千媚，钗玉重，髻云低。", "寂寂挹妆羞泪，怨分携。", "鸳帐愿从今夜，梦长连晓鸡。", "小逐画船风月，渡江西。"]'),
('song-ci-393','定西番','张先','宋','宋词','song-ci','定西番','[]','焊拨紫槽金衬，双秀萼，两回鸾。',50,'宋词/ci.song.0.json','["焊拨紫槽金衬，双秀萼，两回鸾。", "齐学汉宫妆样，竞蝉娟。", "三十六弦蝉闹，小弦蜂作团。", "听尽昭君幽怨，莫重弹。"]'),
('song-ci-394','望江南・忆江南','张先','宋','宋词','song-ci','望江南・忆江南','[]','青楼宴，靓女荐瑶杯。',64,'宋词/ci.song.0.json','["青楼宴，靓女荐瑶杯。", "一曲白云江月满，际天拖练夜潮来。", "人物误瑶台。", "醺醺酒，拂拂上双腮。", "媚脸已非朱淡粉，香红全胜雪笼梅。", "标格外尘埃。"]'),
('song-ci-395','少年游慢','张先','宋','宋词','song-ci','少年游慢','[]','春城三二月。',102,'宋词/ci.song.0.json','["春城三二月。", "禁柳飘绵未歇。", "仙篽生香，轻云凝紫，临层阙。", "歌掌明珠滑。", "酒脸红霞发。", "华省名高，少年得意时节。", "画刻三题彻。", "梯汉同登蟾窟。", "玉殿初宣，银袍齐脱，生仙骨。", "花探都门晓，马跃芳衢阔。", "宴罢东风，鞭梢一行飞雪。"]'),
('song-ci-396','翦牡丹','张先','宋','宋词','song-ci','翦牡丹','[]','野绿连空，天青垂水，素色溶漾都净。',122,'宋词/ci.song.0.json','["野绿连空，天青垂水，素色溶漾都净。", "柔柳摇摇，坠轻絮无影。", "汀洲日落人归，修巾薄袂，撷香拾翠相竞。", "如解凌波，泊烟渚春暝。", "采绦朱索新整。", "宿绣屏、画船风定。", "金凤响双槽，弹出今古幽思谁省。", "玉盘大小乱珠迸。", "酒上妆面，花艳媚相并。", "重听。", "尽汉妃一曲，江空月静。"]'),
('song-ci-397','画堂春','张先','宋','宋词','song-ci','画堂春','[]','外潮莲子长参差。',57,'宋词/ci.song.0.json','["外潮莲子长参差。", "霁山青处鸥飞。", "水天溶漾画桡迟。", "人影鉴中移。", "桃叶浅声双唱，杏红深色轻衣。", "小荷障面避斜晖。", "分得翠阴归。"]'),
('song-ci-398','芳草渡・系裙腰','张先','宋','宋词','song-ci','芳草渡・系裙腰','[]','双门晓锁响朱扉。',72,'宋词/ci.song.0.json','["双门晓锁响朱扉。", "千骑拥、万人随。", "风乌弄影画船移。", "歌时泪，和别怨，作秋悲。", "寒潮小，渡淮迟。", "吴越路、渐天涯。", "宋王台上为相思。", "江云下，日西尽，雁南飞。"]'),
('song-ci-399','芳草渡・系裙腰','张先','宋','宋词','song-ci','芳草渡・系裙腰','[]','主人宴客玉楼西。',71,'宋词/ci.song.0.json','["主人宴客玉楼西。", "风飘雪、忽氛霏。", "唐昌花蕊渐平枝。", "浮光里，寒声聚，队禽栖。", "惊晓日，喜春迟。", "野桥时伴梅飞。", "山明日远霁云披。", "溪上月，堂下水，并春晖。"]'),
('song-ci-400','御街行','张先','宋','宋词','song-ci','御街行','[]','夭非花艳轻非雾。',92,'宋词/ci.song.0.json','["夭非花艳轻非雾。", "来夜半、天明去。", "来如春梦不多时，去似朝云何处。", "远鸡栖燕，落星沈月，紞紞城头鼓。", "参差渐辨西池树。", "珠阁斜开户。", "绿苔深径少人行，苔上屐痕无数。", "馀香遗粉，剩衾闲枕，天把多情付。"]'),
('song-ci-401','苏幕遮','张先','宋','宋词','song-ci','苏幕遮','[]','柳飞绵，花实少。',76,'宋词/ci.song.0.json','["柳飞绵，花实少。", "镂板音清，浅发江南调。", "斜日两竿留碧□。", "马足重重，又近青门道。", "去尘浓，人散了。", "回首旗亭，渐渐红裳小。", "莫讶安仁头白早。", "天若有情，天也终须老。"]'),
('song-ci-402','武陵春','张先','宋','宋词','song-ci','武陵春','[]','每见韶娘梳鬓好，钗燕傍云飞。',56,'宋词/ci.song.0.json','["每见韶娘梳鬓好，钗燕傍云飞。", "谁掬彤霞露染衣。", "□玉透柔肌。", "梅花瘦雪梨花雨，心眼未芳菲。", "看著娇妆听柳枝。", "人意觉春归。"]'),
('song-ci-403','醉落魄・一斛珠','张先','宋','宋词','song-ci','醉落魄・一斛珠','[]','山围画障。',67,'宋词/ci.song.0.json','["山围画障。", "风溪弄月清溶漾。", "玉楼苕馆人相望。", "下若醲醅，竞欲金钗当。", "使君劝醉青娥唱。", "分明仙曲云中响。", "南园百卉千家赏。", "和气兼春，不独花枝上。"]'),
('song-ci-404','长相思','张先','宋','宋词','song-ci','长相思','[]','粉艳明。',44,'宋词/ci.song.0.json','["粉艳明。", "秋水盈。", "柳样纤柔花样轻。", "笑前双靥生。", "寒江平。", "江橹鸣。", "谁道潮沟非远行。", "回头千里情。"]'),
('song-ci-405','更漏子','张先','宋','宋词','song-ci','更漏子','[]','杜陵春，秦树晚。',58,'宋词/ci.song.0.json','["杜陵春，秦树晚。", "伤别更堪临远。", "南去信，欲凭谁。", "归鸿多北归。", "小桃枝，红蓓发。", "今夜昔时风月。", "休苦意，说相思。", "少情人不知。"]'),
('song-ci-406','浣溪沙','张先','宋','宋词','song-ci','浣溪沙','[]','楼倚春江百尺高。',48,'宋词/ci.song.0.json','["楼倚春江百尺高。", "烟中还未见归桡。", "几时期信似江潮。", "花片片飞风弄蝶，柳阴阴下水平桥。", "日长才过又今宵。"]'),
('song-ci-407','醉桃源・阮郎归','张先','宋','宋词','song-ci','醉桃源・阮郎归','[]','仙郎何日是来期。',56,'宋词/ci.song.0.json','["仙郎何日是来期。", "无心云胜伊。", "行云犹解傍山飞。", "郎行去不归。", "强匀画，又芳菲。", "春深轻薄衣。", "桃花无语伴相思。", "阴阴月上时。"]'),
('song-ci-408','行香子','张先','宋','宋词','song-ci','行香子','[]','舞雪歌云。',84,'宋词/ci.song.0.json','["舞雪歌云。", "闲淡妆匀。", "蓝溪水、深染轻裙。", "酒香醺脸，粉色生春。", "更巧谈话，美情性，好精神。", "江空无畔，凌波何处，月桥边、青柳朱门。", "断钟残角，又送黄昏。", "奈心中事，眼中泪，意中人。"]'),
('song-ci-409','熙州慢','张先','宋','宋词','song-ci','熙州慢','[]','武林乡，占第一湖山，咏画争巧。',116,'宋词/ci.song.0.json','["武林乡，占第一湖山，咏画争巧。", "鹫石飞来，倚翠楼烟霭，清猿啼晓。", "况值禁垣师帅，惠政流入欢谣。", "朝暮万景，寒潮弄月，乱峰回照。", "天使寻春不早。", "并行乐，免有花愁花笑。", "持酒更听，红儿肉声长调。", "潇湘故人未归，但目送游云孤鸟。", "际天杪。", "离情尽寄芳草。"]'),
('song-ci-410','虞美人','张先','宋','宋词','song-ci','虞美人','[]','恩如明月家家到。',66,'宋词/ci.song.0.json','["恩如明月家家到。", "无处无清照。", "一帆秋色共云遥。", "眼力不知人远、上江桥。", "愿君书札来双鲤。", "古汴东流水。", "宋王台畔楚宫西。", "正是节趣归路、近沙堤。"]'),
('song-ci-411','泛清苕','张先','宋','宋词','song-ci','泛清苕','[]','绿净无痕，过晓霁清苕，镜里游人。',134,'宋词/ci.song.0.json','["绿净无痕，过晓霁清苕，镜里游人。", "红柱巧，彩船稳，当筵主、秘馆词臣。", "吴娃劝饮韩娥唱，竞艳容、左右皆春。", "学为行雨，傍画桨，从教水溅罗裙。", "溪烟混月黄昏。", "渐楼台上下，火影星分。", "飞槛倚，斗牛近，响箫鼓、远破重云。", "归轩未至千家待，掩半妆、翠箔朱门。", "衣香拂面，扶醉卸簪花，满袖馀煴。"]'),
('song-ci-412','惜琼花','张先','宋','宋词','song-ci','惜琼花','[]','汀苹白。',74,'宋词/ci.song.0.json','["汀苹白。", "苕水碧。", "每逢花驻乐，随处欢席。", "别时携手看春色。", "萤火而今，飞破秋夕。", "旱河流，如带窄。", "任身轻似叶，何计归得。", "断云孤鹜青山极。", "楼上徘徊，无尽相忆。"]'),
('song-ci-413','河满子','张先','宋','宋词','song-ci','河满子','[]','溪女送花随处，沙鸥避乐分行。',86,'宋词/ci.song.0.json','["溪女送花随处，沙鸥避乐分行。", "游舸已如图障里，小屏犹画潇湘。", "人面新生酒艳，日痕更欲春长。", "衣上交枝斗色，钗头比翼相双。", "片段落霞明水底，风纹时动妆光。", "宾从夜归无月，千灯万火河塘。"]'),
('song-ci-414','劝金船','张先','宋','宋词','song-ci','劝金船','[]','流泉宛转双开窦。',110,'宋词/ci.song.0.json','["流泉宛转双开窦。", "带染轻纱皱。", "何人暗得金船酒。", "拥罗绮前后。", "绿定见花影，并照与、艳妆争秀。", "行尽曲名，休更再歌杨柳。", "光生飞动摇琼甃。", "隔障笙箫奏。", "须知短景欢无足，又还过清昼。", "翰阁迟归来，传骑恨、留住难久。", "异日凤凰池上，为谁思旧。"]'),
('song-ci-415','庆同天・河传','张先','宋','宋词','song-ci','庆同天・河传','[]','海宇，称庆。',66,'宋词/ci.song.0.json','["海宇，称庆。", "复生元圣。", "风入南薰。", "拜恩遥阙，衣上晓色犹春。", "望尧云。", "游钧广乐人疑梦。", "仙声共。", "日转旗光动。", "无疆帝算，何独待祝华封。", "与天同。"]'),
('song-ci-416','江城子','张先','宋','宋词','song-ci','江城子','[]','小圆珠串静慵拈。',43,'宋词/ci.song.0.json','["小圆珠串静慵拈。", "夜厌厌。", "下重帘。", "曲屏斜烛，心事入眉尖。", "金字半开香穗小，愁不寐，恨西蟾。"]'),
('song-ci-417','雨中花令','张先','宋','宋词','song-ci','雨中花令','[]','近鬓彩钿云雁细。',76,'宋词/ci.song.0.json','["近鬓彩钿云雁细。", "好客艳、花枝争媚。", "学双燕、同栖还并翅。", "我合著、你难分离。", "这佛面、前生应布施。", "你更看、蛾眉下秋水。", "似赛九底、见他三五二。", "正闷里、也须欢喜。"]'),
('song-ci-418','汉宫春','张先','宋','宋词','song-ci','汉宫春','[]','红粉苔墙。',118,'宋词/ci.song.0.json','["红粉苔墙。", "透新春消息，梅粉先芳。", "奇葩异卉，汉家宫额涂黄。", "何人斗巧，运紫檀、翦出蜂房。", "应为是、中央正色，东君别与清香。", "仙姿自称霓裳。", "更孤标俊格，非雪凌霜。", "黄昏院落，为谁密解罗囊。", "银瓶注水，浸数枝、小阁幽窗。", "春睡起，纤条在手，厌厌宿酒残妆。"]'),
('song-ci-419','青门引・青门饮','张先','宋','宋词','song-ci','青门引・青门饮','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','乍暖还轻冷。',61,'宋词/ci.song.0.json','["乍暖还轻冷。", "风雨晚来方定。", "庭轩寂寞近清明，残花中酒，又是去年病。", "楼头画角风吹醒。", "入夜重门静。", "那堪更被明月，隔墙送过秋千影。"]'),
('song-ci-420','满江红','张先','宋','宋词','song-ci','满江红','[]','飘尽寒梅，笑粉蝶游蜂未觉。',113,'宋词/ci.song.0.json','["飘尽寒梅，笑粉蝶游蜂未觉。", "渐迤逦、水明山秀，暖生帘幕。", "过雨小桃红未透，舞烟新柳青犹弱。", "记画桥深处水边亭，曾偷约。", "多少恨，今犹昨。", "愁和闷，都忘却。", "拼从前烂醉，被花迷著。", "晴鸽试铃风力软，雏莺弄舌春寒薄。", "但只愁、锦绣闹妆时，东风恶。"]'),
('song-ci-421','西江月','张先','宋','宋词','song-ci','西江月','[]','肃肃秺侯清慎，温温契苾知诗。',58,'宋词/ci.song.0.json','["肃肃秺侯清慎，温温契苾知诗。", "能推恻隐救民饥。", "况乃义方教子。", "宪府两飞鹗荐，士林竞赋怀辞。", "天门正美可前知。", "入侍钧天从此。"]'),
('song-ci-422','塞垣春','张先','宋','宋词','song-ci','塞垣春','[]','野树秋声满。',119,'宋词/ci.song.0.json','["野树秋声满。", "对雨壁、风灯乱。", "云低翠帐，烟销素被，签动重幔。", "甚客怀、先自无消遣。", "更篱落、秋虫叹。", "叹樊川、风流减。", "旧欢难得重见。", "停酒说扬州，平山月、应照棋观。", "绿绮为谁弹，空传广陵散。", "但光纱短帽，窄袖轻衫，犹记竹西庭院。", "老鹤何时去，认琼花一面。"]'),
('song-ci-423','浪淘沙','张先','宋','宋词','song-ci','浪淘沙','[]','肠断送韶华。',64,'宋词/ci.song.0.json','["肠断送韶华。", "为惜杨花。", "雪球摇曳逐风斜。", "容易著人容易去，飞过谁家。", "聚散苦咨嗟。", "无计留他。", "行人洒泪滴流霞。", "今日画堂歌舞地，明日天涯。"]'),
('song-ci-424','望江南・忆江南','张先','宋','宋词','song-ci','望江南・忆江南','[]','香闺内、空自想佳期。',64,'宋词/ci.song.0.json','["香闺内、空自想佳期。", "独步花阴情绪乱，谩将珠泪两行垂。", "胜会在何时。", "厌厌病，此夕最难持。", "一点芳心无托处，荼縻架上月迟迟。", "惆怅有谁知。"]'),
('song-ci-425','碧牡丹','张先','宋','宋词','song-ci','碧牡丹','[]','步帐摇红绮。',93,'宋词/ci.song.0.json','["步帐摇红绮。", "晓月堕，沈烟砌。", "缓板香檀，唱彻伊家新制。", "怨入眉头，敛黛峰横翠。", "芭蕉寒，雨声碎。", "镜华翳。", "闲照孤鸾戏。", "思量去时容易。", "钿盒瑶钗，至今冷落轻弃。", "望极蓝桥，但暮云千里。", "几重山，几重水。"]'),
('song-ci-426','山亭宴','张先','宋','宋词','song-ci','山亭宴','[]','碧波落日寒烟聚，望遥山、迷离红树。',124,'宋词/ci.song.0.json','["碧波落日寒烟聚，望遥山、迷离红树。", "小艇载人来，约尊酒、商量歧路。", "衰柳断桥西，共携手、攀条无语。", "水际见鷖凫，一对对、眠沙溆。", "西陵松柏青如故。", "翦烟花、幽兰啼露。", "油壁间花骢，那禁得、风吹细雨。", "饶他此后更思量，总莫似、当筵情绪。", "镜面绿波平，照几度、人来去。"]'),
('song-ci-427','谒金门','晏殊','宋','宋词','song-ci','谒金门','[]','秋露坠。',53,'宋词/ci.song.0.json','["秋露坠。", "滴尽楚兰红泪。", "往事旧欢何限意。", "思量如梦寐。", "人貌老于前岁。", "风月宛然无异。", "座有嘉宾尊有桂。", "莫辞终夕醉。"]'),
('song-ci-428','破阵子','晏殊','宋','宋词','song-ci','破阵子','[]','海上蟠桃易熟，人间好月长圆。',72,'宋词/ci.song.0.json','["海上蟠桃易熟，人间好月长圆。", "惟有掰钗分钿侣，离别常多会面难。", "此情须问天。", "蜡烛到明垂泪，熏炉尽日生烟。", "一点凄凉愁绝意，谩道秦筝有剩弦。", "何曾为细传。"]'),
('song-ci-429','破阵子','晏殊','宋','宋词','song-ci','破阵子','[]','燕子欲归时节，高楼昨夜西风。',72,'宋词/ci.song.0.json','["燕子欲归时节，高楼昨夜西风。", "求得人间成小会，试把金尊傍菊丛。", "歌长粉面红。", "斜日更穿帘幕，微凉渐入梧桐。", "多少襟怀言不尽，写向蛮笺曲调中。", "此情千万重。"]'),
('song-ci-430','破阵子','晏殊','宋','宋词','song-ci','破阵子','[]','忆得去年今日，黄花已满东篱。',72,'宋词/ci.song.0.json','["忆得去年今日，黄花已满东篱。", "曾与玉人临小槛，共折香英泛酒卮。", "长条插鬓垂。", "人貌不应迁换，珍丛又睹芳菲。", "重把一尊寻旧径，所惜光阴去似飞。", "风飘露冷时。"]'),
('song-ci-431','破阵子','晏殊','宋','宋词','song-ci','破阵子','[]','湖上西风斜日，荷花落尽红英。',72,'宋词/ci.song.0.json','["湖上西风斜日，荷花落尽红英。", "金菊满丛珠颗细，海燕辞巢翅羽轻。", "年年岁岁情。", "美酒一杯新熟，高歌数阕堪听。", "不向尊前同一醉，可奈光阴似水声。", "迢迢去未停。"]'),
('song-ci-432','浣溪沙','晏殊','宋','宋词','song-ci','浣溪沙','[]','阆苑瑶台风露秋。',48,'宋词/ci.song.0.json','["阆苑瑶台风露秋。", "整鬟凝思捧觥筹。", "欲归临别强迟留。", "月好谩成孤枕梦，酒阑空得两眉愁。", "此时情绪悔风流。"]'),
('song-ci-433','浣溪沙','晏殊','宋','宋词','song-ci','浣溪沙','[]','三月和风满上林。',48,'宋词/ci.song.0.json','["三月和风满上林。", "牡丹妖艳直千金。", "恼人天气又春阴。", "为我转回红脸面，向谁分付紫檀心。", "有情须殢酒杯深。"]'),
('song-ci-434','浣溪沙','晏殊','宋','宋词','song-ci','浣溪沙','[]','青杏园林著酒香。',48,'宋词/ci.song.0.json','["青杏园林著酒香。", "佳人初试薄罗裳。", "柳丝无力燕飞忙。", "乍雨乍晴花自落，闲愁闲闷日偏长。", "为谁消瘦减容光。"]'),
('song-ci-435','浣溪沙','晏殊','宋','宋词','song-ci','浣溪沙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','一曲新词酒一杯。',48,'宋词/ci.song.0.json','["一曲新词酒一杯。", "去年天气旧亭台。", "夕阳西下几时回。", "无可奈何花落去，似曾相识燕归来。", "小园香径独徘徊。"]'),
('song-ci-436','浣溪沙','晏殊','宋','宋词','song-ci','浣溪沙','[]','红蓼花香夹岸稠。',48,'宋词/ci.song.0.json','["红蓼花香夹岸稠。", "绿波春水向东流。", "小船轻舫好追游。", "渔父酒醒重拨棹，鸳鸯飞去却回头。", "一杯销尽两眉愁。"]'),
('song-ci-437','浣溪沙','晏殊','宋','宋词','song-ci','浣溪沙','[]','淡淡梳妆薄薄衣。',48,'宋词/ci.song.0.json','["淡淡梳妆薄薄衣。", "天仙模样好容仪。", "旧欢前事入颦眉。", "闲役梦魂孤烛暗，恨无消息画帘垂。", "且留双泪说相思。"]'),
('song-ci-438','浣溪沙','晏殊','宋','宋词','song-ci','浣溪沙','[]','小阁重帘有燕过。',48,'宋词/ci.song.0.json','["小阁重帘有燕过。", "晚花红片落庭莎。", "曲阑干影入凉波。", "一霎好风生翠幕，几回疏雨滴圆荷。", "酒醒人散得愁多。"]'),
('song-ci-439','浣溪沙','晏殊','宋','宋词','song-ci','浣溪沙','[]','宿酒才醒厌玉卮。',48,'宋词/ci.song.0.json','["宿酒才醒厌玉卮。", "水沈香冷懒熏衣。", "早梅先绽日边枝。", "寒雪寂寥初散后，春风悠扬欲来时。", "小屏闲放画帘垂。"]'),
('song-ci-440','浣溪沙','晏殊','宋','宋词','song-ci','浣溪沙','[]','绿叶红花媚晓烟。',48,'宋词/ci.song.0.json','["绿叶红花媚晓烟。", "黄蜂金蕊欲披莲。", "水风深处懒回船。", "可惜异香珠箔外，不辞清唱玉尊前。", "使星归觐九重天。"]'),
('song-ci-441','浣溪沙','晏殊','宋','宋词','song-ci','浣溪沙','[]','湖上西风急暮蝉。',48,'宋词/ci.song.0.json','["湖上西风急暮蝉。", "夜来清露湿红莲。", "少留归骑促歌筵。", "为别莫辞金盏酒，入朝须近玉炉烟。", "不知重会是何年。"]'),
('song-ci-442','浣溪沙','晏殊','宋','宋词','song-ci','浣溪沙','[]','杨柳阴中驻彩旌。',48,'宋词/ci.song.0.json','["杨柳阴中驻彩旌。", "芰荷香里劝金觥。", "小词流入管弦声。", "只有醉饮宽别恨，不须朝暮促归程。", "雨条烟叶系人情。"]'),
('song-ci-443','浣溪沙','晏殊','宋','宋词','song-ci','浣溪沙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','一向年光有限身。',48,'宋词/ci.song.0.json','["一向年光有限身。", "等闲离别易消魂。", "酒筵歌席莫辞频。", "满目山河空念远，落花风雨更伤春。", "不如怜取眼前人。"]'),
('song-ci-444','浣溪沙','晏殊','宋','宋词','song-ci','浣溪沙','[]','玉碗冰寒滴露华。',48,'宋词/ci.song.0.json','["玉碗冰寒滴露华。", "粉融香雪透轻纱。", "晚来妆面胜荷花。", "鬓亸欲迎眉际月，酒红初上脸边霞。", "一场春梦日西斜。"]'),
('song-ci-445','更漏子','晏殊','宋','宋词','song-ci','更漏子','[]','蕣华浓，山翠浅。',58,'宋词/ci.song.0.json','["蕣华浓，山翠浅。", "一寸秋波如剪。", "红日永，绮筵开。", "暗随仙驭来。", "遏云声，回雪袖。", "占断晓莺春柳。", "才送目，又颦眉。", "此情谁得知。"]'),
('song-ci-446','更漏子','晏殊','宋','宋词','song-ci','更漏子','[]','塞鸿高，仙露满。',58,'宋词/ci.song.0.json','["塞鸿高，仙露满。", "秋入银河清浅。", "逢好客，且开眉。", "盛年能几时。", "宝筝调，罗袖软。", "拍碎画堂檀板。", "须尽醉，莫推辞。", "人生多别离。"]'),
('song-ci-447','更漏子','晏殊','宋','宋词','song-ci','更漏子','[]','雪藏梅，烟著柳。',58,'宋词/ci.song.0.json','["雪藏梅，烟著柳。", "依约上春时候。", "初送雁，欲问莺。", "绿池波浪生。", "探花开，留客醉。", "忆得去年情味。", "金盏酒，玉炉香。", "任他红日长。"]'),
('song-ci-448','更漏子','晏殊','宋','宋词','song-ci','更漏子','[]','菊花残，梨叶堕。',58,'宋词/ci.song.0.json','["菊花残，梨叶堕。", "可惜良辰虚过。", "新酒熟，绮筵开。", "不辞红玉杯。", "蜀弦高，羌管脆。", "慢飐舞娥香袂。", "君莫笑，醉乡人。", "熙熙长似春。"]'),
('song-ci-449','鹊踏枝・蝶恋花','晏殊','宋','宋词','song-ci','鹊踏枝・蝶恋花','[]','槛菊愁烟兰泣露。',70,'宋词/ci.song.0.json','["槛菊愁烟兰泣露。", "罗幕轻寒，燕子双飞去。", "明月不谙离恨苦。", "斜光到晓穿朱户。", "昨夜西风凋碧树。", "独上高楼，望尽天涯路。", "欲寄彩笺兼尺素。", "山长水阔知何处。"]'),
('song-ci-450','鹊踏枝・蝶恋花','晏殊','宋','宋词','song-ci','鹊踏枝・蝶恋花','[]','紫府群仙名籍秘。',70,'宋词/ci.song.0.json','["紫府群仙名籍秘。", "五色斑龙，暂降人间世。", "海变桑田都不记。", "蟠桃一熟三千岁。", "露滴彩旌云绕袂。", "谁信壶中，别有笙歌地。", "门外落花随水逝。", "相看莫惜尊前醉。"]'),
('song-ci-451','点绛唇','晏殊','宋','宋词','song-ci','点绛唇','[]','露下风高，井梧宫簟生秋意。',50,'宋词/ci.song.0.json','["露下风高，井梧宫簟生秋意。", "画堂筵启。", "一曲呈珠缀。", "天外行云，欲去凝香袂。", "炉烟起。", "断肠声里。", "敛尽双蛾翠。"]'),
('song-ci-452','凤衔杯','晏殊','宋','宋词','song-ci','凤衔杯','[]','青苹昨夜秋风起。',70,'宋词/ci.song.0.json','["青苹昨夜秋风起。", "无限个、露莲相倚。", "独凭朱阑、愁望晴天际。", "空目断、遥山翠。", "彩笺长，锦书细。", "谁信道、两情难寄。", "可惜良辰好景、欢娱地。", "只恁空憔悴。"]'),
('song-ci-453','凤衔杯','晏殊','宋','宋词','song-ci','凤衔杯','[]','留花不住怨花飞。',72,'宋词/ci.song.0.json','["留花不住怨花飞。", "向南园、情绪依依。", "可惜倒红斜白、一枝枝。", "经宿雨、又离披。", "凭朱槛，把金卮。", "对芳丛、惆怅多时。", "何况旧欢新恨、阻心期。", "空满眼、是相思。"]'),
('song-ci-454','凤衔杯','晏殊','宋','宋词','song-ci','凤衔杯','[]','柳条花颣恼青春。',72,'宋词/ci.song.0.json','["柳条花颣恼青春。", "更那堪、飞絮纷纷。", "一曲细丝清脆、倚朱唇。", "斟绿酒、掩红巾。", "追往事，惜芳辰。", "暂时间、留住行云。", "端的自家心下、眼中人。", "到处里、觉尖新。"]'),
('song-ci-455','清平乐','晏殊','宋','宋词','song-ci','清平乐','[]','春花秋草。',54,'宋词/ci.song.0.json','["春花秋草。", "只是催人老。", "总把千山眉黛扫。", "未抵别愁多少。", "劝君绿酒金杯。", "莫嫌丝管声催。", "兔走乌飞不住，人生几度三台。"]'),
('song-ci-456','清平乐','晏殊','宋','宋词','song-ci','清平乐','[]','秋光向晚。',54,'宋词/ci.song.0.json','["秋光向晚。", "小阁初开宴。", "林叶殷红犹未遍。", "雨后青苔满院。", "萧娘劝我金卮。", "殷勤更唱新词。", "暮去朝来节老，人生不饮何为。"]'),
('song-ci-457','清平乐','晏殊','宋','宋词','song-ci','清平乐','[]','春来秋去。',54,'宋词/ci.song.0.json','["春来秋去。", "往事知何处。", "燕子归飞兰泣露。", "光景千留不住。", "酒阑人散忡忡。", "闲阶独倚梧桐。", "记得去年今日，依前黄叶西风。"]'),
('song-ci-458','清平乐','晏殊','宋','宋词','song-ci','清平乐','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','金风细细。',54,'宋词/ci.song.0.json','["金风细细。", "叶叶梧桐坠。", "绿酒初尝人易醉。", "一枕小窗浓睡。", "紫微朱槿花残。", "斜阳却照阑干。", "双燕欲归时节，银屏昨夜微寒。"]'),
('song-ci-459','清平乐','晏殊','宋','宋词','song-ci','清平乐','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','红笺小字。',54,'宋词/ci.song.0.json','["红笺小字。", "说尽平生意。", "鸿雁在云鱼在水。", "惆怅此情难寄。", "斜阳独倚西楼。", "遥山恰对帘钩。", "人面不知何处，绿波依旧东流。"]'),
('song-ci-460','红窗听','晏殊','宋','宋词','song-ci','红窗听','[]','淡薄梳妆轻结束。',64,'宋词/ci.song.0.json','["淡薄梳妆轻结束。", "天意与、脸红眉绿。", "断环书素传情久，许双飞同宿。", "一饷无端分比目。", "谁知道、风前月底，相看未足。", "此心终拟，觅鸾弦重续。"]'),
('song-ci-461','红窗听','晏殊','宋','宋词','song-ci','红窗听','[]','记得香闺临别语。',64,'宋词/ci.song.0.json','["记得香闺临别语。", "彼此有、万重心诉。", "淡云轻霭知多少，隔桃源无处。", "梦觉相思天欲曙。", "依前是、银屏画烛，宵长岁暮。", "此时何计，托鸳鸯飞去。"]'),
('song-ci-462','采桑子','晏殊','宋','宋词','song-ci','采桑子','[]','春风不负东君信，遍拆群芳。',52,'宋词/ci.song.0.json','["春风不负东君信，遍拆群芳。", "燕子双双。", "依旧衔泥入杏梁。", "须知一盏花前酒，占得韶光。", "莫话匆忙。", "梦里浮生足断肠。"]'),
('song-ci-463','采桑子','晏殊','宋','宋词','song-ci','采桑子','[]','红英一树春来早，独占芳时。',52,'宋词/ci.song.0.json','["红英一树春来早，独占芳时。", "我有心期。", "把酒攀条惜绛蕤。", "无端一夜狂风雨，暗落繁枝。", "蝶怨莺悲。", "满眼春愁说向谁。"]'),
('song-ci-464','采桑子','晏殊','宋','宋词','song-ci','采桑子','[]','阳和二月芳菲遍，暖景溶溶。',52,'宋词/ci.song.0.json','["阳和二月芳菲遍，暖景溶溶。", "戏蝶游蜂。", "深入千花粉艳中。", "何人解系天边日，占取春风。", "免使繁红。", "一片西飞一片东。"]'),
('song-ci-465','采桑子','晏殊','宋','宋词','song-ci','采桑子','[]','樱桃谢了梨花发，红白相催。',52,'宋词/ci.song.0.json','["樱桃谢了梨花发，红白相催。", "燕子归来。", "几处风帘绣户开。", "人生乐事知多少，且酌金杯。", "管咽弦哀。", "慢引萧娘舞袖回。"]'),
('song-ci-466','采桑子','晏殊','宋','宋词','song-ci','采桑子','[]','古罗衣上金针样，绣出芳妍。',52,'宋词/ci.song.0.json','["古罗衣上金针样，绣出芳妍。", "玉砌朱阑。", "紫艳红英照日鲜。", "佳人画阁新妆了，对立丛边。", "试摘婵娟。", "贴向眉心学翠钿。"]'),
('song-ci-467','采桑子','晏殊','宋','宋词','song-ci','采桑子','[]','时光只解催人老，不信多情。',52,'宋词/ci.song.0.json','["时光只解催人老，不信多情。", "长恨离亭。", "泪滴春衫酒易醒。", "梧桐昨夜西风急，淡月胧明。", "好梦频惊。", "何处高楼雁一声。"]'),
('song-ci-468','采桑子','晏殊','宋','宋词','song-ci','采桑子','[]','林间摘遍双双叶，寄与相思。',52,'宋词/ci.song.0.json','["林间摘遍双双叶，寄与相思。", "朱槿开时。", "尚有山榴一两枝。", "荷花欲绽金莲子，半落红衣。", "晚雨微微。", "待得空梁宿燕归。"]'),
('song-ci-469','喜迁莺','晏殊','宋','宋词','song-ci','喜迁莺','[]','风转蕙，露催莲。',57,'宋词/ci.song.0.json','["风转蕙，露催莲。", "莺语尚绵蛮。", "尧蓂随月欲团圆。", "真驭降荷兰。", "褰油幕。", "调清乐。", "四海一家同乐。", "千官心在玉炉香。", "圣寿祝天长。"]'),
('song-ci-470','喜迁莺','晏殊','宋','宋词','song-ci','喜迁莺','[]','歌敛黛，舞萦风。',57,'宋词/ci.song.0.json','["歌敛黛，舞萦风。", "迟日象筵中。", "分行珠翠簇繁红。", "云髻袅珑璁。", "金炉暖。", "龙香远。", "共祝尧龄万万。", "曲终休解画罗衣。", "留伴彩云飞。"]'),
('song-ci-471','喜迁莺','晏殊','宋','宋词','song-ci','喜迁莺','[]','花不尽，柳无穷。',57,'宋词/ci.song.0.json','["花不尽，柳无穷。", "应与我情同。", "觥船一棹百分空。", "何处不相逢。", "朱弦悄。", "知音少。", "天若有情应老。", "劝君看取利名场。", "今古梦茫茫。"]'),
('song-ci-472','喜迁莺','晏殊','宋','宋词','song-ci','喜迁莺','[]','烛飘花，香掩烬。',57,'宋词/ci.song.0.json','["烛飘花，香掩烬。", "中夜酒初醒。", "画楼残点两三声。", "窗外月胧明。", "晓帘垂，惊鹊去。", "好梦不知何处。", "南园春色已归来。", "庭树有寒梅。"]'),
('song-ci-473','喜迁莺','晏殊','宋','宋词','song-ci','喜迁莺','[]','曙河低，斜月淡。',57,'宋词/ci.song.0.json','["曙河低，斜月淡。", "帘外早凉天。", "玉楼清唱倚朱弦。", "馀韵入疏烟。", "脸霞轻，眉翠重。", "欲舞钗钿摇动。", "人人如意祝炉香。", "为寿百千长。"]'),
('song-ci-474','撼庭秋','晏殊','宋','宋词','song-ci','撼庭秋','[]','别来音信千里。',59,'宋词/ci.song.0.json','["别来音信千里。", "怅此情难寄。", "碧纱秋月，梧桐夜雨，几回无寐。", "楼高目断，天遥云黯，只堪憔悴。", "念兰堂红烛，心长焰短，向人垂泪。"]'),
('song-ci-475','少年游','晏殊','宋','宋词','song-ci','少年游','[]','重阳过后，西风渐紧，庭树叶纷纷。',62,'宋词/ci.song.0.json','["重阳过后，西风渐紧，庭树叶纷纷。", "朱阑向晓，芙蓉妖艳，特地斗芳新。", "霜前月下，斜红淡蕊，明媚欲回春。", "莫将琼萼等闲分。", "留赠意中人。"]'),
('song-ci-476','少年游','晏殊','宋','宋词','song-ci','少年游','[]','霜华满树，兰凋蕙惨，秋艳入芙蓉。',62,'宋词/ci.song.0.json','["霜华满树，兰凋蕙惨，秋艳入芙蓉。", "胭脂嫩脸，金黄轻蕊，犹自怨西风。", "前欢往事，当歌对酒，无限到心中。", "更凭朱槛忆芳容。", "肠断一枝红。"]'),
('song-ci-477','少年游','晏殊','宋','宋词','song-ci','少年游','[]','芙蓉花发去年枝。',60,'宋词/ci.song.0.json','["芙蓉花发去年枝。", "双燕欲归飞。", "兰堂风软，金炉香暖，新曲动帘帷。", "家人拜上千春寿，深意满琼卮。", "绿鬓朱颜，道家装束，长似少年时。"]'),
('song-ci-478','少年游','晏殊','宋','宋词','song-ci','少年游','[]','谢家庭槛晓无尘。',60,'宋词/ci.song.0.json','["谢家庭槛晓无尘。", "芳宴祝良辰。", "风流妙舞，樱桃清唱，依约驻行云。", "榴花一盏浓香满，为寿百千春。", "岁岁年年，共欢同乐，嘉庆与时新。"]'),
('song-ci-479','酒泉子','晏殊','宋','宋词','song-ci','酒泉子','[]','三月暖风，开却好花无限了，当年丛下落纷纷。',53,'宋词/ci.song.0.json','["三月暖风，开却好花无限了，当年丛下落纷纷。", "最愁人。", "长安多少利名身。", "若有一杯香桂酒，莫辞花下醉芳茵。", "且留春。"]'),
('song-ci-480','酒泉子','晏殊','宋','宋词','song-ci','酒泉子','[]','春色初来，遍拆红芳千万树，流莺粉蝶斗翻飞。',53,'宋词/ci.song.0.json','["春色初来，遍拆红芳千万树，流莺粉蝶斗翻飞。", "恋香枝。", "劝君莫惜缕金衣。", "把酒看花须强饮，明朝后日渐离披。", "惜芳时。"]'),
('song-ci-481','木兰花・玉楼春','晏殊','宋','宋词','song-ci','木兰花・玉楼春','[]','东风昨夜回梁苑。',64,'宋词/ci.song.0.json','["东风昨夜回梁苑。", "日脚依稀添一线。", "旋开杨柳绿蛾眉，暗拆海棠红粉面。", "无情一去云中雁。", "有意归来梁上燕。", "有情无意且休论，莫向酒杯容易散。"]'),
('song-ci-482','木兰花・玉楼春','晏殊','宋','宋词','song-ci','木兰花・玉楼春','[]','帘旌浪卷金泥凤。',64,'宋词/ci.song.0.json','["帘旌浪卷金泥凤。", "宿醉醒来长瞢鬆。", "海棠开后晓寒轻，流絮飞时春睡重。", "美酒一杯谁与共。", "往事旧欢时节动。", "不如怜取眼前人，免更劳魂兼役梦。"]'),
('song-ci-483','木兰花・玉楼春','晏殊','宋','宋词','song-ci','木兰花・玉楼春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','燕鸿过后莺归去。',64,'宋词/ci.song.0.json','["燕鸿过后莺归去。", "细算浮生千万绪。", "长於春梦几多时，散似秋云无觅处。", "闻琴解佩神仙侣。", "挽断罗衣留不住。", "劝君莫作独醒人，烂醉花间应有数。"]'),
('song-ci-484','木兰花・玉楼春','晏殊','宋','宋词','song-ci','木兰花・玉楼春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','池塘水绿风微暖。',64,'宋词/ci.song.0.json','["池塘水绿风微暖。", "记得玉真初见面。", "重头歌韵响铮琮，入破舞腰红乱旋。", "玉钩阑下香阶畔。", "醉后不知斜日晚。", "当时共我赏花人，点检如今无一半。"]'),
('song-ci-485','木兰花・玉楼春','晏殊','宋','宋词','song-ci','木兰花・玉楼春','[]','玉楼朱阁横金锁。',64,'宋词/ci.song.0.json','["玉楼朱阁横金锁。", "寒食清明春欲破。", "窗间斜月两眉愁，帘外落花双泪堕。", "朝云聚散真无那。", "百岁相看能几个。", "别来将为不牵情，万转千回思想过。"]'),
('song-ci-486','木兰花・玉楼春','晏殊','宋','宋词','song-ci','木兰花・玉楼春','[]','朱帘半下香销印。',64,'宋词/ci.song.0.json','["朱帘半下香销印。", "二月东风催柳信。", "琵琶旁畔且寻思，鹦鹉前头休借问。", "惊鸿去后生离恨。", "红日长时添酒困。", "未知心在阿谁边，满眼泪珠言不尽。"]'),
('song-ci-487','木兰花・玉楼春','晏殊','宋','宋词','song-ci','木兰花・玉楼春','[]','杏梁归燕双回首。',64,'宋词/ci.song.0.json','["杏梁归燕双回首。", "黄蜀葵花开应候。", "画堂元是降生辰，玉盏更斟长命酒。", "炉中百和添香兽。", "帘外青蛾回舞袖。", "此时红粉感恩人，拜向月宫千岁寿。"]'),
('song-ci-488','木兰花・玉楼春','晏殊','宋','宋词','song-ci','木兰花・玉楼春','[]','紫薇朱槿繁开后。',64,'宋词/ci.song.0.json','["紫薇朱槿繁开后。", "枕簟微凉生玉漏。", "玳筵初启日穿帘，檀板欲开香满袖。", "红衫侍女频倾酒。", "龟鹤仙人来献寿。", "欢声喜气逐时新，青鬓玉颜长似旧。"]'),
('song-ci-489','木兰花・玉楼春','晏殊','宋','宋词','song-ci','木兰花・玉楼春','[]','春葱指甲轻拢拈。',64,'宋词/ci.song.0.json','["春葱指甲轻拢拈。", "五彩条垂双袖卷。", "雪香浓透紫檀槽，胡语急随红玉腕。", "当头一曲情无限。", "入破铮琮金凤战。", "百分芳酒祝长春，再拜敛容抬粉面。"]'),
('song-ci-490','木兰花・玉楼春','晏殊','宋','宋词','song-ci','木兰花・玉楼春','[]','红条约束琼肌稳。',64,'宋词/ci.song.0.json','["红条约束琼肌稳。", "拍碎香檀催急衮。", "垅头呜咽水声繁，叶下间关莺语近。", "美人才子传芳信。", "明月清风伤别恨。", "未知何处有知音，长为此情言不尽。"]'),
('song-ci-491','迎春乐','晏殊','宋','宋词','song-ci','迎春乐','[]','长安紫陌春归早。',65,'宋词/ci.song.0.json','["长安紫陌春归早。", "亸垂杨、染芳草。", "被啼莺语燕催清晓。", "正好梦、频惊觉。", "当此际、青楼临大道。", "幽会处、两情多少。", "莫惜明珠百琲，占取长年少。"]'),
('song-ci-492','诉衷情','晏殊','宋','宋词','song-ci','诉衷情','[]','青梅煮酒斗时新。',54,'宋词/ci.song.0.json','["青梅煮酒斗时新。", "天气欲残春。", "东城南陌花下，逢著意中人。", "回绣袂，展香茵。", "叙情亲。", "此情拼作，千尺游丝，惹住朝云。"]'),
('song-ci-493','诉衷情','晏殊','宋','宋词','song-ci','诉衷情','[]','东风杨柳欲青青。',54,'宋词/ci.song.0.json','["东风杨柳欲青青。", "烟淡雨初晴。", "恼他香阁浓睡，撩乱有啼莺。", "眉叶细，舞腰轻。", "宿妆成。", "一春芳意，三月和风，牵系人情。"]'),
('song-ci-494','诉衷情','晏殊','宋','宋词','song-ci','诉衷情','[]','芙蓉金菊斗馨香。',54,'宋词/ci.song.0.json','["芙蓉金菊斗馨香。", "天气欲重阳。", "远村秋色如画，红树间疏黄。", "流水淡，碧天长。", "路茫茫。", "凭高目断，鸿雁来时，无限思量。"]'),
('song-ci-495','诉衷情','晏殊','宋','宋词','song-ci','诉衷情','[]','数枝金菊对芙蓉。',54,'宋词/ci.song.0.json','["数枝金菊对芙蓉。", "摇落意重重。", "不知多少幽怨，和露泣西风。", "人散后，月明中。", "夜寒浓。", "谢娘愁卧，潘令闲眠，心事无穷。"]'),
('song-ci-496','诉衷情','晏殊','宋','宋词','song-ci','诉衷情','[]','露莲双脸远山眉。',54,'宋词/ci.song.0.json','["露莲双脸远山眉。", "偏与淡妆宜。", "小庭帘幕春晚，闲共柳丝垂。", "人别后，月圆时。", "信迟迟。", "心心念念，说尽无凭，只是相思。"]'),
('song-ci-497','诉衷情','晏殊','宋','宋词','song-ci','诉衷情','[]','秋风吹绽北池莲。',54,'宋词/ci.song.0.json','["秋风吹绽北池莲。", "曙云楼阁鲜。", "画堂今日嘉会，齐拜玉炉烟。", "斟美酒，祝芳筵。", "奉觥船。", "宜春耐夏，多福庄严，富贵长年。"]'),
('song-ci-498','诉衷情','晏殊','宋','宋词','song-ci','诉衷情','[]','世间荣贵月中人。',54,'宋词/ci.song.0.json','["世间荣贵月中人。", "嘉庆在今辰。", "兰堂帘幕高卷，清唱遏行云。", "持玉盏，敛红巾。", "祝千春。", "榴花寿酒，金鸭炉香，岁岁长新。"]'),
('song-ci-499','诉衷情','晏殊','宋','宋词','song-ci','诉衷情','[]','海棠珠缀一重重。',54,'宋词/ci.song.0.json','["海棠珠缀一重重。", "清晓近帘栊。", "胭脂谁与匀淡，偏向脸边浓。", "看叶嫩，惜花红。", "意无穷。", "如花似叶，岁岁年年，共占春风。"]'),
('song-ci-500','胡捣练','晏殊','宋','宋词','song-ci','胡捣练','[]','小桃花与早梅花，尽是芳妍品格。',56,'宋词/ci.song.0.json','["小桃花与早梅花，尽是芳妍品格。", "未上东风先拆。", "分付春消息。", "佳人钗上玉尊前，朵朵秾香堪惜。", "谁把彩豪描得。", "免恁轻抛掷。"]'),
('song-ci-501','人娇','晏殊','宋','宋词','song-ci','人娇','[]','二月春风，正是杨花满路。',84,'宋词/ci.song.0.json','["二月春风，正是杨花满路。", "那堪更、别离情绪。", "罗巾掩泪，任粉痕沾污。", "争奈向、千留万留不住。", "玉酒频倾，宿眉愁聚。", "空肠断、宝筝弦柱。", "人间后会，又不知何处。", "魂梦里、也须时时飞去。"]'),
('song-ci-502','人娇','晏殊','宋','宋词','song-ci','人娇','[]','玉树微凉，渐觉银河影转。',84,'宋词/ci.song.0.json','["玉树微凉，渐觉银河影转。", "林叶静、疏红欲遍。", "朱帘细雨，尚迟留归燕。", "嘉庆日、多少世人良愿。", "楚竹惊鸾，秦筝起雁。", "萦舞袖、急翻罗荐。", "云回一曲，更轻栊檀板。", "香炷远、同祝寿期无限。"]'),
('song-ci-503','人娇','晏殊','宋','宋词','song-ci','人娇','[]','一叶秋高，向夕红兰露坠。',84,'宋词/ci.song.0.json','["一叶秋高，向夕红兰露坠。", "风月好、乍凉天气。", "长生此日，见人中嘉瑞。", "斟寿酒、重唱妙声珠缀。", "凤莞移宫，钿衫回袂。", "帘影动、鹊炉香细。", "南真宝箓，赐玉京千岁。", "良会永、莫惜流霞同醉。"]'),
('song-ci-504','踏莎行','晏殊','宋','宋词','song-ci','踏莎行','[]','细草愁烟，幽花怯露。',68,'宋词/ci.song.0.json','["细草愁烟，幽花怯露。", "凭阑总是销魂处。", "日高深院静无人，时时海燕双飞去。", "带缓罗衣，香残蕙炷。", "天长不禁迢迢路。", "垂杨只解惹春风，何曾系得行人住。"]'),
('song-ci-505','踏莎行','晏殊','宋','宋词','song-ci','踏莎行','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','祖席离歌，长亭别宴。',68,'宋词/ci.song.0.json','["祖席离歌，长亭别宴。", "香尘已隔犹回面。", "居人匹马映林嘶，行人去棹依波转。", "画阁魂消，高楼目断。", "斜阳只送平波远。", "无穷无尽是离愁，天涯地角寻思遍。"]'),
('song-ci-506','踏莎行','晏殊','宋','宋词','song-ci','踏莎行','[]','碧海无波，瑶台有路。',68,'宋词/ci.song.0.json','["碧海无波，瑶台有路。", "思量便合双飞去。", "当时轻别意中人，山长水远知何处。", "绮席凝尘，香闺掩雾。", "红笺小字凭谁附。", "高楼目尽欲黄昏，梧桐叶上萧萧雨。"]'),
('song-ci-507','踏莎行','晏殊','宋','宋词','song-ci','踏莎行','[]','绿树归莺，雕梁别燕。',68,'宋词/ci.song.0.json','["绿树归莺，雕梁别燕。", "春光一去如流电。", "当歌对酒莫沈吟，人生有限情无限。", "弱袂萦春，修蛾写怨。", "秦筝宝柱频移雁。", "尊中绿醑意中人，花朝月夜长相见。"]'),
('song-ci-508','踏莎行','晏殊','宋','宋词','song-ci','踏莎行','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','小径红稀，芳郊绿遍。',68,'宋词/ci.song.0.json','["小径红稀，芳郊绿遍。", "高台树色阴阴见。", "春风不解禁杨花，濛濛乱扑行人面。", "翠叶藏莺，朱帘隔燕。", "炉香静逐游丝转。", "一场愁梦酒醒时，斜阳却照深深院。"]'),
('song-ci-509','渔家傲','晏殊','宋','宋词','song-ci','渔家傲','[]','画鼓声中昏又晓。',72,'宋词/ci.song.0.json','["画鼓声中昏又晓。", "时光只解催人老。", "求得浅欢风日好。", "齐揭调。", "神仙一曲渔家傲。", "绿水悠悠天杳杳。", "浮生岂得长年少。", "莫惜醉来开口笑。", "须信道。", "人间万事何时了。"]'),
('song-ci-510','渔家傲','晏殊','宋','宋词','song-ci','渔家傲','[]','荷叶荷花相间斗。',72,'宋词/ci.song.0.json','["荷叶荷花相间斗。", "红娇绿嫩新妆就。", "昨日小池疏雨后。", "铺锦绣。", "行人过去频回首。", "倚遍朱阑凝望久。", "鸳鸯浴处波文皱。", "谁唤谢娘斟美酒。", "萦舞袖。", "当筵劝我千长寿。"]'),
('song-ci-511','渔家傲','晏殊','宋','宋词','song-ci','渔家傲','[]','荷叶初开犹半卷。',72,'宋词/ci.song.0.json','["荷叶初开犹半卷。", "荷花欲拆犹微绽。", "此叶此花真可羡。", "秋水畔。", "青凉伞映红妆面。", "美酒一杯留客宴。", "拈花摘叶情无限。", "争奈世人多聚散。", "频祝愿。", "如花似叶长相见。"]'),
('song-ci-512','渔家傲','晏殊','宋','宋词','song-ci','渔家傲','[]','杨柳风前香百步。',72,'宋词/ci.song.0.json','["杨柳风前香百步。", "盘心碎点真珠露。", "疑是水仙开洞府。", "妆景趣。", "红幢绿盖朝天路。", "小鸭飞来稠闹处。", "三三两两能言语。", "饮散短亭人欲去。", "留不住。", "黄昏更下萧萧雨。"]'),
('song-ci-513','渔家傲','晏殊','宋','宋词','song-ci','渔家傲','[]','粉笔丹青描未得。',72,'宋词/ci.song.0.json','["粉笔丹青描未得。", "金针彩线功难敌。", "谁傍暗香轻采摘。", "风淅淅。", "船头触散双鸂鶒。", "夜雨染成天水碧。", "朝阳借出胭脂色。", "欲落又开人共惜。", "秋气逼。", "盘中已见新莲菂。"]'),
('song-ci-514','渔家傲','晏殊','宋','宋词','song-ci','渔家傲','[]','叶下鵁鶄眠未稳。',72,'宋词/ci.song.0.json','["叶下鵁鶄眠未稳。", "风翻露飐香成阵。", "仙女出游知远近。", "羞借问。", "饶将绿扇遮红粉。", "一掬蕊黄沾雨润。", "天人乞与金英嫩。", "试折乱条醒酒困。", "应有恨。", "芳心拗尽丝无尽。"]'),
('song-ci-515','渔家傲','晏殊','宋','宋词','song-ci','渔家傲','[]','罨画溪边停彩舫。',72,'宋词/ci.song.0.json','["罨画溪边停彩舫。", "仙娥绣被呈新样。", "飒飒风声来一饷。", "愁四望。", "残红片片随波浪。", "琼脸丽人青步障。", "风牵一袖低相向。", "应有锦鳞闲倚傍。", "秋水上。", "时时绿柄轻摇扬。"]'),
('song-ci-516','渔家傲','晏殊','宋','宋词','song-ci','渔家傲','[]','宿蕊斗攒金粉闹。',72,'宋词/ci.song.0.json','["宿蕊斗攒金粉闹。", "青房暗结蜂儿小。", "敛面似啼开似笑。", "天与貌。", "人间不是铅华少。", "叶软香清无限好。", "风头日脚乾催老。", "待得玉京仙子到。", "凭向道。", "红颜只合长年少。"]'),
('song-ci-517','渔家傲','晏殊','宋','宋词','song-ci','渔家傲','[]','脸傅朝霞衣剪翠。',72,'宋词/ci.song.0.json','["脸傅朝霞衣剪翠。", "重重占断秋江水。", "一曲采莲风细细。", "人未醉。", "鸳鸯不合惊飞起。", "欲摘嫩条嫌绿刺。", "闲敲画扇偷金蕊。", "半夜月明珠露坠。", "多少意。", "红腮点点相思泪。"]'),
('song-ci-518','渔家傲','晏殊','宋','宋词','song-ci','渔家傲','[]','越女采莲江北岸。',72,'宋词/ci.song.0.json','["越女采莲江北岸。", "轻桡短棹随风便。", "人貌与花相斗艳。", "流水慢。", "时时照影看妆面。", "莲叶层层张绿伞。", "莲房个个垂金盏。", "一把藕丝牵不断。", "红日晚。", "回头欲去心撩乱。"]'),
('song-ci-519','渔家傲','晏殊','宋','宋词','song-ci','渔家傲','[]','粉面啼红腰束素。',72,'宋词/ci.song.0.json','["粉面啼红腰束素。", "当年拾翠曾相遇。", "密意深情谁与诉。", "空怨慕。", "西池夜夜风兼露。", "池上夕阳笼碧树。", "池中短棹惊微雨。", "水泛落英何处去。", "人不语。", "东流到了无停住。"]'),
('song-ci-520','渔家傲','晏殊','宋','宋词','song-ci','渔家傲','[]','幽鹭慢来窥品格。',72,'宋词/ci.song.0.json','["幽鹭慢来窥品格。", "双鱼岂解传消息。", "绿柄嫩香频采摘。", "心似织。", "条条不断谁牵役。", "粉泪暗和清露滴。", "罗衣染尽秋江色。", "对面不言情脉脉。", "烟水隔。", "无人说似长相忆。"]'),
('song-ci-521','渔家傲','晏殊','宋','宋词','song-ci','渔家傲','[]','楚国细腰元自瘦。',72,'宋词/ci.song.0.json','["楚国细腰元自瘦。", "文君腻脸谁描就。", "日夜声声催箭漏。", "昏复昼。", "红颜岂得长如旧。", "醉折嫩房和蕊嗅。", "天丝不断清香透。", "却傍小阑凝坐久。", "风满袖。", "西池月上人归后。"]'),
('song-ci-522','渔家傲','晏殊','宋','宋词','song-ci','渔家傲','[]','嫩绿堪裁红欲绽。',72,'宋词/ci.song.0.json','["嫩绿堪裁红欲绽。", "蜻蜓点水鱼游畔。", "一霎雨声香四散。", "风飐乱。", "高低掩映千千万。", "总是凋零终有恨。", "能无眼下生留恋。", "何似折来妆粉面。", "勤看玩。", "胜如落尽秋江岸。"]'),
('song-ci-523','雨中花・夜行船','晏殊','宋','宋词','song-ci','雨中花・夜行船','[]','剪翠妆红欲就。',61,'宋词/ci.song.0.json','["剪翠妆红欲就。", "折得清香满袖。", "一对鸳鸯眠未足，叶下长相守。", "莫傍细条寻嫩藕。", "怕绿刺、罥衣伤手。", "可惜许、月明风露好，恰在人归后。"]'),
('song-ci-524','瑞鹧鸪','晏殊','宋','宋词','song-ci','瑞鹧鸪','[]','越娥红泪泣朝云。',75,'宋词/ci.song.0.json','["越娥红泪泣朝云。", "越梅从此学妖嚬。", "腊月初头、庾岭繁开后，特染妍华赠世人。", "前溪昨夜深深雪，朱颜不掩天真。", "何时驿使西归，寄与相思客，一枝新。", "报道江南别样春。"]'),
('song-ci-525','瑞鹧鸪','晏殊','宋','宋词','song-ci','瑞鹧鸪','[]','江南残腊欲归时。',75,'宋词/ci.song.0.json','["江南残腊欲归时。", "有梅红亚雪中枝。", "一夜前村、间破瑶英拆，端的千花冷未知。", "丹青改样匀朱粉，雕梁欲画犹疑。", "何妨与向冬深，密种秦人路，夹仙溪。", "不待妖桃客自迷。"]'),
('song-ci-526','望仙门','晏殊','宋','宋词','song-ci','望仙门','[]','紫薇枝上露华浓。',55,'宋词/ci.song.0.json','["紫薇枝上露华浓。", "起秋风。", "管弦声细出帘栊。", "象筵中。", "仙酒斟云液，仙歌转绕梁虹。", "此时佳会庆相逢。", "庆相逢。", "欢醉且从容。"]'),
('song-ci-527','望仙门','晏殊','宋','宋词','song-ci','望仙门','[]','玉壶清漏起微凉。',55,'宋词/ci.song.0.json','["玉壶清漏起微凉。", "好秋光。", "金杯重叠满琼浆。", "会仙乡。", "新曲调丝管，新声更飐霓裳。", "博山炉暖泛浓香。", "泛浓香。", "为寿百千长。"]'),
('song-ci-528','望仙门','晏殊','宋','宋词','song-ci','望仙门','[]','玉池波浪碧如鳞。',57,'宋词/ci.song.0.json','["玉池波浪碧如鳞。", "露莲新。", "清歌一曲翠眉嚬。", "舞华茵。", "满酌兰英酒，须知献寿千春。", "太平无事荷君恩。", "荷君恩。", "齐唱《望仙门》。"]'),
('song-ci-529','长生乐','晏殊','宋','宋词','song-ci','长生乐','[]','玉露金风月正圆。',90,'宋词/ci.song.0.json','["玉露金风月正圆。", "台榭早凉天。", "画堂嘉会，组绣列芳筵。", "洞府星辰龟鹤，来添福寿。", "欢声喜色，同入金炉泛浓烟。", "清歌妙舞，急管繁弦。", "榴花满酌觥船。", "人尽祝、富贵又长年。", "莫教红日西晚，留著醉神仙。"]'),
('song-ci-530','长生乐','晏殊','宋','宋词','song-ci','长生乐','[]','阆苑神仙平地见。',89,'宋词/ci.song.0.json','["阆苑神仙平地见。", "碧海架蓬瀛。", "洞门相向，倚金铺微明。", "处处天花撩乱，飘散歌声。", "装真筵寿，赐与流霞满瑶觥。", "红鸾翠节，紫凤银笙。", "玉女双来近彩云。", "随步朝夕拜三清。", "为传王母金箓，祝千岁长生。"]'),
('song-ci-531','蝶恋花','晏殊','宋','宋词','song-ci','蝶恋花','[]','一霎秋风惊画扇。',70,'宋词/ci.song.0.json','["一霎秋风惊画扇。", "艳粉娇红，尚拆荷花面。", "草际露垂虫响遍。", "珠帘不下留归燕。", "扫掠亭台开小院。", "四坐清欢，莫放金杯浅。", "龟鹤命长松寿远。", "阳春一曲情千万。"]'),
('song-ci-532','蝶恋花','晏殊','宋','宋词','song-ci','蝶恋花','[]','紫菊初生朱槿坠。',70,'宋词/ci.song.0.json','["紫菊初生朱槿坠。", "月好风清，渐有中秋意。", "更漏乍长天似水。", "银屏展尽遥山翠。", "绣幕卷波香引穗。", "急管繁弦，共庆人间瑞。", "满酌玉杯萦舞袂。", "南春祝寿千千岁。"]'),
('song-ci-533','蝶恋花','晏殊','宋','宋词','song-ci','蝶恋花','[]','帘幕风轻双语燕。',70,'宋词/ci.song.0.json','["帘幕风轻双语燕。", "午醉醒来，柳絮飞撩乱。", "心事一春犹未见。", "馀花落尽青苔院。", "百尺朱楼闲倚遍。", "薄雨浓云，抵死遮人面。", "消息未知归早晚。", "斜阳只送平波远。"]'),
('song-ci-534','蝶恋花','晏殊','宋','宋词','song-ci','蝶恋花','[]','玉碗冰寒消暑气。',70,'宋词/ci.song.0.json','["玉碗冰寒消暑气。", "碧簟纱厨，向午朦胧睡。", "莺舌惺松如会意。", "无端画扇惊飞起。", "雨后初凉生水际。", "人面荷花，的的遥相似。", "眼看红芳犹抱蕊。", "丛中已结新莲子。"]'),
('song-ci-535','蝶恋花','晏殊','宋','宋词','song-ci','蝶恋花','[]','梨叶疏红蝉韵歇。',70,'宋词/ci.song.0.json','["梨叶疏红蝉韵歇。", "银汉风高，玉管声凄切。", "枕簟乍凉铜漏咽。", "谁教社燕轻离别。", "草际蛩吟珠露结。", "宿酒醒来，不记归时节。", "多少衷肠犹未说。", "朱帘一夜朦胧月。"]'),
('song-ci-536','蝶恋花','晏殊','宋','宋词','song-ci','蝶恋花','[]','南雁依稀回侧阵。',70,'宋词/ci.song.0.json','["南雁依稀回侧阵。", "雪霁墙阴，偏觉兰芽嫩。", "中夜梦馀消酒困。", "炉香卷穗灯生晕。", "急景流年都一瞬。", "往事前欢，未免萦方寸。", "腊后花期知渐近。", "寒梅已作东风信。"]'),
('song-ci-537','拂霓裳','晏殊','宋','宋词','song-ci','拂霓裳','[]','庆生辰。',101,'宋词/ci.song.0.json','["庆生辰。", "庆生辰是百千春。", "开雅宴，画堂高会有诸亲。", "钿函封大国，玉色受丝纶。", "感皇恩。", "望九重、天上拜尧云。", "今朝祝寿，祝寿数，比松椿。", "斟美酒，至心如对月中人。", "一声檀板动，一炷蕙香焚。", "祷仙真。", "愿年年今日、喜长新。"]'),
('song-ci-538','拂霓裳','晏殊','宋','宋词','song-ci','拂霓裳','[]','喜秋成。',102,'宋词/ci.song.0.json','["喜秋成。", "见千门万户乐升平。", "金风细，玉池波浪縠文生。", "宿露沾罗幕，微凉入画屏。", "张绮宴，傍熏炉蕙炷、和新声。", "神仙雅会，会此日，象蓬瀛。", "管弦清，旋翻红袖学飞琼。", "光阴无暂住，欢醉有闲情。", "祝辰星。", "愿百千为寿、献瑶觥。"]'),
('song-ci-539','拂霓裳','晏殊','宋','宋词','song-ci','拂霓裳','[]','乐秋天。',101,'宋词/ci.song.0.json','["乐秋天。", "晚荷花缀露珠圆。", "风日好，数行新雁贴寒烟。", "银簧调脆管，琼柱拨清弦。", "捧觥船。", "一声声、齐唱太平年。", "人生百岁，离别易，会逢难。", "无事日，剩呼宾友启芳筵。", "星霜催绿鬓，风露损朱颜。", "惜清欢。", "又何妨、沈醉玉尊前。"]'),
('song-ci-540','菩萨蛮','晏殊','宋','宋词','song-ci','菩萨蛮','[]','芳莲九蕊开新艳。',52,'宋词/ci.song.0.json','["芳莲九蕊开新艳。", "轻红淡白匀双脸。", "一朵近华堂。", "学人宫样妆。", "看时斟美酒。", "共祝千年寿。", "销得曲中夸。", "世间无此花。"]'),
('song-ci-541','菩萨蛮','晏殊','宋','宋词','song-ci','菩萨蛮','[]','秋花最是黄葵好。',52,'宋词/ci.song.0.json','["秋花最是黄葵好。", "天然嫩态迎秋早。", "染得道家衣。", "淡妆梳洗时。", "晓来清露滴。", "一一金杯侧。", "插向绿云鬓。", "便随王母仙。"]'),
('song-ci-542','菩萨蛮','晏殊','宋','宋词','song-ci','菩萨蛮','[]','人人尽道黄葵淡。',52,'宋词/ci.song.0.json','["人人尽道黄葵淡。", "侬家解说黄葵艳。", "可喜万般宜。", "不劳朱粉施。", "摘承金盏酒。", "劝我千长寿。", "擎作女真冠。", "试伊娇面看。"]'),
('song-ci-543','菩萨蛮','晏殊','宋','宋词','song-ci','菩萨蛮','[]','高梧叶下秋光晚。',52,'宋词/ci.song.0.json','["高梧叶下秋光晚。", "珍丛化出黄金盏。", "还似去年时。", "傍阑三两枝。", "人情须耐久。", "花面长依旧。", "莫学蜜蜂儿。", "等闲悠扬飞。"]'),
('song-ci-544','秋蕊香','晏殊','宋','宋词','song-ci','秋蕊香','[]','梅蕊雪残香瘦。',56,'宋词/ci.song.0.json','["梅蕊雪残香瘦。", "罗幕轻寒微透。", "多情只是春杨柳。", "占断可怜时候。", "萧娘劝我杯中酒。", "翻红袖。", "金乌玉兔长飞走。", "争得朱颜依旧。"]'),
('song-ci-545','秋蕊香','晏殊','宋','宋词','song-ci','秋蕊香','[]','向晓雪花呈瑞。',56,'宋词/ci.song.0.json','["向晓雪花呈瑞。", "飞遍玉城瑶砌。", "何人剪碎天边桂。", "散作瑶田琼蕊。", "萧娘敛尽双蛾翠。", "回香袂。", "今朝有酒今朝醉。", "遮莫更长无睡。"]'),
('song-ci-546','相思儿令','晏殊','宋','宋词','song-ci','相思儿令','[]','昨日探春消息，湖上绿波平。',56,'宋词/ci.song.0.json','["昨日探春消息，湖上绿波平。", "无奈绕堤芳草，还向旧痕生。", "有酒且醉瑶觥。", "更何妨、檀板新声。", "谁教杨柳千丝，就中牵系人情。"]'),
('song-ci-547','相思儿令','晏殊','宋','宋词','song-ci','相思儿令','[]','春色渐芳菲也，迟日满烟波。',56,'宋词/ci.song.0.json','["春色渐芳菲也，迟日满烟波。", "正好艳阳时节，争奈落花何。", "醉来拟恣狂歌。", "断肠中、赢得愁多。", "不如归傍纱窗，有人重画双蛾。"]'),
('song-ci-548','滴滴金','晏殊','宋','宋词','song-ci','滴滴金','[]','梅花漏泄春消息。',60,'宋词/ci.song.0.json','["梅花漏泄春消息。", "柳丝长，草芽碧。", "不觉星霜鬓边白。", "念时光堪惜。", "兰堂把酒留嘉客。", "对离筵，驻行色。", "千里音尘便疏隔。", "合有人相忆。"]'),
('song-ci-549','山亭柳','晏殊','宋','宋词','song-ci','山亭柳','[]','家住西秦。',97,'宋词/ci.song.0.json','["家住西秦。", "赌博艺随身。", "花柳上、斗尖新。", "偶学念奴声调，有时高遏行云。", "蜀锦缠头无数，不负辛勤。", "数年来往咸京道，残杯冷炙谩消魂。", "衷肠事、托何人。", "若有知音见采，不辞遍唱《阳春》。", "一曲当筵落泪，重掩罗巾。"]'),
('song-ci-550','睿恩新','晏殊','宋','宋词','song-ci','睿恩新','[]','芙蓉一朵霜秋色。',69,'宋词/ci.song.0.json','["芙蓉一朵霜秋色。", "迎晓露、依依先拆。", "似佳人、独立倾城，傍朱槛、暗传消息。", "静对西风脉脉。", "金蕊绽、粉红如滴。", "向兰堂、莫厌重深，免清夜、微寒渐逼。"]'),
('song-ci-551','睿恩新','晏殊','宋','宋词','song-ci','睿恩新','[]','红丝一曲傍阶砌。',69,'宋词/ci.song.0.json','["红丝一曲傍阶砌。", "珠露下、独呈纤丽。", "剪鲛绡、碎作香英，分彩线、簇成娇蕊。", "向晚群花欲悴。", "放朵朵、似延秋意。", "待佳人、插向钗头，更袅袅、低临凤髻。"]'),
('song-ci-552','玉堂春','晏殊','宋','宋词','song-ci','玉堂春','[]','帝城春暖。',73,'宋词/ci.song.0.json','["帝城春暖。", "御柳暗遮空苑。", "海燕双双，拂扬帘栊。", "女伴相携、共绕林间路，折得樱桃插髻红。", "昨夜临明微雨，新英遍旧丛。", "宝马香车、欲傍西池看，触处杨花满袖风。"]'),
('song-ci-553','玉堂春','晏殊','宋','宋词','song-ci','玉堂春','[]','后园春早。',73,'宋词/ci.song.0.json','["后园春早。", "残雪尚濛烟草。", "数树寒梅，欲绽香英。", "小妹无端、折尽钗头朵，满把金尊细细倾。", "忆得往年同伴，沈吟无限情。", "恼乱东风、莫便吹零落，惜取芳菲眼下明。"]'),
('song-ci-554','玉堂春','晏殊','宋','宋词','song-ci','玉堂春','[]','斗城池馆。',73,'宋词/ci.song.0.json','["斗城池馆。", "二月风和烟暖。", "绣户珠帘，日影初长。", "玉辔金鞍、缭绕沙堤路，几处行人映绿杨。", "小槛朱阑回倚，千花浓露香。", "脆管清弦、欲奏新翻曲，依约林间坐夕阳。"]'),
('song-ci-555','临江仙','晏殊','宋','宋词','song-ci','临江仙','[]','资善堂中三十载，旧人多是凋零。',68,'宋词/ci.song.0.json','["资善堂中三十载，旧人多是凋零。", "与君相见最伤情。", "一尊如旧，聊且话平生。", "此别要知须强饮，雪残风细长亭。", "待君归觐九重城。", "帝宸思旧，朝夕奉皇明。"]'),
('song-ci-556','燕归梁','晏殊','宋','宋词','song-ci','燕归梁','[]','双燕归飞绕画堂。',62,'宋词/ci.song.0.json','["双燕归飞绕画堂。", "似留恋虹梁。", "清风明月好时光。", "更何况、绮筵张。", "云衫侍女，频倾寿酒，加意动笙簧。", "人人心在玉炉香。", "庆佳会、祝延长。"]'),
('song-ci-557','燕归梁','晏殊','宋','宋词','song-ci','燕归梁','[]','金鸭香炉起瑞烟。',62,'宋词/ci.song.0.json','["金鸭香炉起瑞烟。", "呈妙舞开筵。", "阳春一曲动朱弦。", "斟美酒、泛觥船。", "中秋五日，风清露爽，犹是早凉天。", "蟠桃花发一千年。", "祝长寿、比神仙。"]'),
('song-ci-558','望汉月・忆汉月','晏殊','宋','宋词','song-ci','望汉月・忆汉月','[]','千缕万条堪结。',63,'宋词/ci.song.0.json','["千缕万条堪结。", "占断好风良月。", "谢娘春晚先多愁，更撩乱、絮飞如雪。", "短亭相送处，长忆得、醉中攀折。", "年年岁岁好时节。", "怎奈尚、有人离别。"]'),
('song-ci-559','连理枝','晏殊','宋','宋词','song-ci','连理枝','[]','玉字秋风至。',84,'宋词/ci.song.0.json','["玉字秋风至。", "帘幕生凉气。", "朱槿犹开，红莲尚拆，芙蓉含蕊。", "送旧巢归燕拂高檐，见梧桐叶坠。", "嘉宴凌晨启。", "金鸭飘香细。", "凤竹鸾丝，清歌妙舞，尽呈游艺。", "愿百千遐寿比神仙，有年年岁岁。"]'),
('song-ci-560','连理枝','晏殊','宋','宋词','song-ci','连理枝','[]','绿树莺声老。',84,'宋词/ci.song.0.json','["绿树莺声老。", "金井生秋早。", "不寒不暖，裁衣按曲，天时正好。", "况兰堂逢著寿筵开，见炉香缥缈。", "组绣呈纤巧。", "歌舞夸妍妙。", "玉酒频倾，朱弦翠管，移宫易调。", "献金杯重叠祝长生，永消遥奉道。"]'),
('song-ci-561','破阵子','晏殊','宋','宋词','song-ci','破阵子','[]','燕子来时新社，梨花落后清明。',72,'宋词/ci.song.0.json','["燕子来时新社，梨花落后清明。", "池上碧苔三四点，叶底黄鹂一两声。", "日长飞絮轻。", "巧笑东邻女伴，采桑径里逢迎。", "疑怪昨宵春梦好，元是今朝斗草赢。", "笑从双脸生。"]'),
('song-ci-562','玉楼春','晏殊','宋','宋词','song-ci','玉楼春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','绿杨芳草长亭路。',64,'宋词/ci.song.0.json','["绿杨芳草长亭路。", "年少抛人容易去。", "楼头残梦五更钟，花底离情三月雨。", "无情不似多情苦。", "一寸还成千万缕。", "天涯地角有穷时，只有相思无尽处。"]'),
('song-ci-563','失调名','晏殊','宋','宋词','song-ci','失调名','[]','芳草连天碧。',6,'宋词/ci.song.0.json','["芳草连天碧。"]'),
('song-ci-564','临江仙','滕宗谅','宋','宋词','song-ci','临江仙','[]','湖水连天天连水，秋来分外澄清。',70,'宋词/ci.song.0.json','["湖水连天天连水，秋来分外澄清。", "君山自是小蓬瀛。", "气蒸云梦泽，波撼岳阳城。", "帝子有灵能鼓瑟，凄然依旧伤情。", "微闻兰芝动芳馨。", "曲终人不见，江上数峰青。"]'),
('song-ci-565','满江红','张','宋','宋词','song-ci','满江红','[]','无利无名，无荣无辱，无烦无恼。',114,'宋词/ci.song.0.json','["无利无名，无荣无辱，无烦无恼。", "夜灯前、独歌独酌，独吟独笑。", "况值群山初雪满，又兼明月交光好。", "便假饶百岁拟如何，从他老。", "知富贵，谁能保。", "知功业，何时了。", "算箪瓢金玉，所争多少。", "一瞬光阴何足道，但思行乐常不早。", "待春来携酒殢东风，眠芳草。"]'),
('song-ci-566','离亭燕・离亭宴','张','宋','宋词','song-ci','离亭燕・离亭宴','[]','一带江山如画。',84,'宋词/ci.song.0.json','["一带江山如画。", "风物向秋潇洒。", "水浸碧天何处断，翠色冷光相射。", "蓼岸荻花中，隐映竹篱茅舍。", "天际客帆高挂。", "门外酒旗低迓。", "多少六朝兴废事，尽入渔樵闲话。", "怅望倚危栏，红日无言西下。"]'),
('song-ci-567','诉衷情','王益','宋','宋词','song-ci','诉衷情','[]','烧残绛蜡泪成痕。',54,'宋词/ci.song.0.json','["烧残绛蜡泪成痕。", "街鼓报黄昏。", "碧云又阻来信，廊上月侵门。", "愁永夜，拂香裀。", "待谁温。", "梦兰憔悴，掷果凄凉，两处销魂。"]'),
('song-ci-568','鹊桥仙','石延年','宋','宋词','song-ci','鹊桥仙','[]','一分素景，千家新月，凉露楼台遍洗。',34,'宋词/ci.song.0.json','["一分素景，千家新月，凉露楼台遍洗。", "宝奁深夜结蛛丝，紝五孔、金针不寐。"]'),
('song-ci-569','燕归梁','石延年','宋','宋词','song-ci','燕归梁','[]','芳草年年惹恨幽。',62,'宋词/ci.song.0.json','["芳草年年惹恨幽。", "想前事悠悠。", "伤春伤别几时休。", "算从古、为风流。", "春山总把，深匀翠黛，千叠在眉头。", "不知供得几多愁。", "更斜日、凭危楼。"]'),
('song-ci-570','迷仙引','关咏','宋','宋词','song-ci','迷仙引','[]','春阴霁。',153,'宋词/ci.song.0.json','["春阴霁。", "岸柳参差，袅袅金丝细。", "画阁昼眠莺唤起。", "烟光媚。", "燕燕双高，引愁人如醉。", "慵缓步，眉敛金铺倚。", "嘉景易失，懊恼韶光改。", "花空委。", "忍厌厌地。", "施朱粉，临鸾鉴，腻香销减摧桃李。", "独自个凝睇。", "暮云暗、遥山翠。", "天色无情，四远低垂淡如水。", "离恨托、征鸿寄。", "旋娇波、暗落相思泪。", "妆如洗。", "向高楼、日日春风里。", "悔凭阑、芳草人千里。"]'),
('song-ci-571','水调歌头','刘潜','宋','宋词','song-ci','水调歌头','[]','六郡酒泉。',5,'宋词/ci.song.0.json','["六郡酒泉。"]'),
('song-ci-572','六州歌头','刘潜','宋','宋词','song-ci','六州歌头','[]','秦亡草昧，刘项起吞并。',141,'宋词/ci.song.0.json','["秦亡草昧，刘项起吞并。", "驱龙虎。", "鞭寰宇。", "斩长鲸。", "扫欃枪。", "血染彭门战。", "视馀耳，皆鹰犬。", "平祸乱。", "归炎汉。", "势奔倾。", "兵散月明。", "风急旌旗乱，刁斗三更。", "命虞姬相对，泣听楚歌声。", "玉帐魂惊。", "泪盈盈。", "恨花无主。", "凝愁绪。", "挥雪刃，掩泉扃。", "时不利。", "骓不逝。", "困阴陵。", "叱追兵。", "喑呜摧天地，望归路，忍偷生。", "功盖世。"]'),
('song-ci-573','水调歌头','刘潜','宋','宋词','song-ci','水调歌头','[]','落日塞垣路，风劲戛貂裘。',114,'宋词/ci.song.0.json','["落日塞垣路，风劲戛貂裘。", "翩翩数骑闲猎，深入黑山头。", "极目平沙千里，惟见雕弓白羽，铁面骇骅骝。", "隐隐望青冢，特地起闲愁。", "汉天子，方鼎盛，四百州。", "玉颜皓齿，深锁三十六宫秋。", "堂有经纶贤相，边有纵横谋将，不作翠蛾羞。", "戎虏和乐也，圣主永无忧。"]'),
('song-ci-574','蝶恋花','李冠','宋','宋词','song-ci','蝶恋花','[]','遥夜亭皋闲信步。',70,'宋词/ci.song.0.json','["遥夜亭皋闲信步。", "才过清明，渐觉伤春暮。", "数点雨声风约住。", "朦胧淡月云来去。", "桃杏依稀香暗渡。", "谁在秋千，笑里轻轻语。", "一寸相思千万绪。", "人间没个安排处。"]'),
('song-ci-575','六州歌头','李冠','宋','宋词','song-ci','六州歌头','[]','凄凉绣岭，宫殿倚山阿。',142,'宋词/ci.song.0.json','["凄凉绣岭，宫殿倚山阿。", "明皇帝。", "曾游地。", "锁烟萝。", "郁嵯峨。", "忆惜真妃子。", "艳倾国，方姝丽。", "朝复暮。", "嫔嫱妒。", "宠偏颇。", "三尺玉泉新浴，莲羞吐、红浸秋波。", "听花奴，敲羯鼓，酣奏鸣鼍。", "体不胜罗。", "舞婆娑。", "正霓裳曳。", "惊烽燧。", "千万骑。", "拥雕戈。", "情宛转。", "魂空乱。", "蹙双蛾。", "奈兵何。", "痛惜三春暮，委妖丽，马嵬坡。", "平寇乱。"]'),
('song-ci-576','六州歌头','李冠','宋','宋词','song-ci','六州歌头','[]','秦亡草昧，刘项起吞并。',147,'宋词/ci.song.0.json','["秦亡草昧，刘项起吞并。", "鞭寰宇。", "驱龙虎。", "扫欃枪。", "斩长鲸。", "雪染中原战。", "视馀耳，皆鹰犬。", "平祸乱。", "归炎汉。", "势奔倾。", "兵散月明。", "风急旌旗乱，刁斗三更。", "共虞姬相对，泣听楚歌声。", "玉帐魂惊。", "泪盈盈。", "念花无主。", "凝愁苦。", "挥雪刃，掩泉扃。", "时不利。", "骓不逝。", "困阴陵。", "叱追兵。", "呜喑摧天地，望归路，忍偷生。", "功盖世，何处见遗灵。"]'),
('song-ci-577','蝶恋花','李冠','宋','宋词','song-ci','蝶恋花','[]','贴鬓香云双绾绿。',70,'宋词/ci.song.0.json','["贴鬓香云双绾绿。", "柳弱花娇，一点春心足。", "不肯玉箫闲度曲。", "恼人特把青蛾蹙。", "静夜溪桥霜薄屋。", "独影行歌，惊起双鸾宿。", "愁破酒阑闺梦熟。", "月斜窗外风敲竹。"]'),
('song-ci-578','千秋万岁・千秋岁引','李冠','宋','宋词','song-ci','千秋万岁・千秋岁引','[]','杏花好、子细君须辨。',103,'宋词/ci.song.0.json','["杏花好、子细君须辨。", "比早梅深、夭桃浅。", "把鲛绡、淡拂鲜红面。", "蜡融紫萼重重现。", "烟外悄，风中笑，香满院。", "欲绽全开俱可羡。", "粹美妖娆无处选。", "除卿卿似寻常见。", "倚天真、艳冶轻朱粉，分明洗出胭脂面。", "追往事，绕芳榭，千千遍。"]'),
('song-ci-579','菩萨蛮','谢绛','宋','宋词','song-ci','菩萨蛮','[]','娟娟侵鬓妆痕浅。',52,'宋词/ci.song.0.json','["娟娟侵鬓妆痕浅。", "双眸相媚弯如翦。", "一瞬百般宜。", "无论笑与啼。", "酒阑思翠被。", "特故瞢腾地。", "生怕促归轮。", "微波先注人。"]'),
('song-ci-580','夜行船','谢绛','宋','宋词','song-ci','夜行船','[]','昨夜佳期初共。',67,'宋词/ci.song.0.json','["昨夜佳期初共。", "鬓云低、翠翘金凤。", "尊前和笑不成歌，意偷转、眼波微送。", "草草不容成楚梦。", "渐寒深、翠帘霜重。", "相看送到断肠时，月西斜、画楼钟动。"]'),
('song-ci-581','诉衷情','谢绛','宋','宋词','song-ci','诉衷情','[]','银缸夜永影长孤。',54,'宋词/ci.song.0.json','["银缸夜永影长孤。", "香草续残炉。", "倚屏脉脉无语，粉泪不成珠。", "双粲枕，百娇壶。", "忆当初。", "君恩莫似，秋叶无情，欲向人疏。"]'),
('song-ci-582','失调名','宋祁','宋','宋词','song-ci','失调名','[]','因为衔泥污锦衣。',16,'宋词/ci.song.0.json','["因为衔泥污锦衣。", "垂下珠帘不敢归。"]'),
('song-ci-583','浪淘沙近・浪淘沙','宋祁','宋','宋词','song-ci','浪淘沙近・浪淘沙','[]','少年不管。',68,'宋词/ci.song.0.json','["少年不管。", "流光如箭。", "因循不觉韶光换。", "至如今，始惜月满、花满、酒满。", "扁舟欲解垂杨岸。", "尚同欢宴。", "日斜歌阕将分散。", "倚兰桡，望水远、天远、人远。"]'),
('song-ci-584','蝶恋花','宋祁','宋','宋词','song-ci','蝶恋花','[]','雨过蒲萄新涨绿。',70,'宋词/ci.song.0.json','["雨过蒲萄新涨绿。", "苍玉盘倾，堕碎珠千斛。", "姬监拥前红簇簇。", "温泉初试真妃浴。", "驿使南来丹荔熟。", "故翦轻绡，一色颁时服。", "娇汗易晞凝醉玉。", "青凉不用香绵扑。"]'),
('song-ci-585','玉楼春','宋祁','宋','宋词','song-ci','玉楼春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','东城渐觉风光好。',64,'宋词/ci.song.0.json','["东城渐觉风光好。", "縠皱波纹迎客棹。", "绿杨烟外晓寒轻，红杏枝头春意闹。", "浮生长恨欢娱少。", "肯爱千金轻一笑。", "为君持酒劝斜阳，且向花间留晚照。"]'),
('song-ci-586','蝶恋花','宋祁','宋','宋词','song-ci','蝶恋花','[]','绣幕茫茫罗帐卷。',70,'宋词/ci.song.0.json','["绣幕茫茫罗帐卷。", "春睡腾腾，困入娇波慢。", "隐隐枕痕留玉脸。", "腻云斜溜钗头燕。", "远梦无端欢又散。", "泪落胭脂，界破蜂黄浅。", "整了翠鬟匀了面。", "芳心一寸情何限。"]'),
('song-ci-587','鹧鸪天','宋祁','宋','宋词','song-ci','鹧鸪天','[]','画毂雕鞍狭路逢。',64,'宋词/ci.song.0.json','["画毂雕鞍狭路逢。", "一声肠断绣帘中。", "身无彩凤双飞翼，心有灵犀一点通。", "金作屋，玉为笼。", "车如流水马游龙。", "刘郎已恨蓬山远，更隔蓬山几万重。"]'),
('song-ci-588','好事近','宋祁','宋','宋词','song-ci','好事近','[]','睡起玉屏风，吹去乱红犹落。',53,'宋词/ci.song.0.json','["睡起玉屏风，吹去乱红犹落。", "天气骤生轻暖，衬沈香帷箔。", "珠帘约住海棠风，愁拖两眉角。", "昨夜一庭明月，冷秋千红索。"]'),
('song-ci-589','木兰花令','贾昌朝','宋','宋词','song-ci','木兰花令','[]','都城水绿嬉游处。',64,'宋词/ci.song.0.json','["都城水绿嬉游处。", "仙棹往来人笑语。", "红随远浪泛桃花，雪散平堤飞柳絮。", "东君欲共春归去。", "一阵狂风和骤雨。", "碧油红旆锦障泥，斜日画桥芳草路。"]'),
('song-ci-590','水调歌头','尹洙','宋','宋词','song-ci','水调歌头','["\u592a\u6e56"]','万倾太湖上，朝暮浸寒光。',114,'宋词/ci.song.0.json','["万倾太湖上，朝暮浸寒光。", "吴王去后，台榭千古锁悲凉。", "谁信蓬山仙子，天与经纶才器，等闲厌名缰。", "敛翼下霄汉，雅意在沧浪。", "晚秋里，烟寂静，雨微凉。", "危亭好景，佳树修竹绕回塘。", "不用移舟酌酒，自有青山渌水，掩映似潇湘。", "莫问平生意，别有好思量。"]'),
('song-ci-591','苏幕遮','梅尧臣','宋','宋词','song-ci','苏幕遮','[]','露堤平，烟墅杳。',76,'宋词/ci.song.0.json','["露堤平，烟墅杳。", "乱碧萋萋，雨后江天晓。", "独有庾郎年最少。", "窣地春袍，嫩色宜相照。", "接长亭，迷远道。", "堪怨王孙，不记归期早。", "落尽梨花春又了。", "满地残阳，翠色和烟老。"]'),
('song-ci-592','玉楼春','梅尧臣','宋','宋词','song-ci','玉楼春','[]','天然不比花含粉。',64,'宋词/ci.song.0.json','["天然不比花含粉。", "约月眉黄春色嫩。", "小桥低映欲迷人，闲倚东风无奈困。", "烟姿最与章台近。", "冉冉千丝谁结恨。", "狂莺来往恋芳阴，不道风流真能尽。"]'),
('song-ci-593','江南好・忆江南','叶清臣','宋','宋词','song-ci','江南好・忆江南','[]','丞相有才裨造化，圣皇宽诏养疏顽。',22,'宋词/ci.song.0.json','["丞相有才裨造化，圣皇宽诏养疏顽。", "赢取十年闲。"]'),
('song-ci-594','贺圣朝','叶清臣','宋','宋词','song-ci','贺圣朝','[]','满斟绿醑留君住。',58,'宋词/ci.song.0.json','["满斟绿醑留君住。", "莫匆匆归去。", "三分春色二分愁，更一分风雨。", "花开花谢、都来几许。", "且高歌休诉。", "不知来岁牡丹时，再相逢何处。"]'),
('song-ci-595','折红梅','吴感','宋','宋词','song-ci','折红梅','[]','喜冰澌初泮，微和渐入、东郊时节。',134,'宋词/ci.song.0.json','["喜冰澌初泮，微和渐入、东郊时节。", "春消息，夜来顿觉，红梅数枝争发。", "玉溪仙馆，不是个、寻常标格。", "化工别与、一种风情，似匀点胭脂，染成香雪。", "重吟细阅。", "比繁杏夭桃，品格真别。", "只愁共、彩云易散，冷落谢池风月。", "凭谁向说。", "三弄处、龙吟休咽。", "大家留取，时倚阑干，闻有花堪折，劝君须折。"]'),
('song-ci-596','映山红','文彦博','宋','宋词','song-ci','映山红','[]','遂请后。',13,'宋词/ci.song.0.json','["遂请后。", "愿频醉、石楼溪口。"]'),
('song-ci-597','西湖念语','欧阳修','宋','宋词','song-ci','西湖念语','["\u897f\u6e56"]','昔者王子猷之爱竹，造门不问于主人，陶渊明之卧舆，遇酒便留于道士。',178,'宋词/ci.song.0.json','["昔者王子猷之爱竹，造门不问于主人，陶渊明之卧舆，遇酒便留于道士。", "况西湖之胜概，擅东颍之佳名。", "虽美景良辰，固多于高会。", "而清风明月，幸属于闲人。", "并游或结于良朋，乘兴有时而独往。", "鸣蛙暂听，安问属官而属私。", "曲水临流，自可一觞而一咏。", "至欢然而会意，亦傍若于无人。", "乃知偶来常胜於特来，前言可信。", "所有虽非于己有，其得已多。", "因翻旧阕之辞，写以新声之调，敢阵薄伎，聊佐清欢。"]'),
('song-ci-598','采桑子','欧阳修','宋','宋词','song-ci','采桑子','["\u897f\u6e56"]','轻舟短棹西湖好，绿水逶迤。',52,'宋词/ci.song.0.json','["轻舟短棹西湖好，绿水逶迤。", "芳草长堤。", "隐隐笙歌处处随。", "无风水面琉璃滑，不觉船移。", "微动涟漪。", "惊起沙禽掠岸飞。"]'),
('song-ci-599','采桑子','欧阳修','宋','宋词','song-ci','采桑子','["\u897f\u6e56"]','春深雨过西湖好，百卉争妍。',52,'宋词/ci.song.0.json','["春深雨过西湖好，百卉争妍。", "蝶乱蜂喧。", "晴日催花暖欲然。", "兰桡画舸悠悠去，疑是神仙。", "返照波间。", "水阔风高扬管弦。"]'),
('song-ci-600','采桑子','欧阳修','宋','宋词','song-ci','采桑子','["\u897f\u6e56"]','画船载酒西湖好，急管繁弦。',52,'宋词/ci.song.0.json','["画船载酒西湖好，急管繁弦。", "玉盏催传。", "稳泛平波任醉眠。", "行云却在行舟下，空水澄鲜。", "俯仰留连。", "疑是湖中别有天。"]'),
('song-ci-601','采桑子','欧阳修','宋','宋词','song-ci','采桑子','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u897f\u6e56"]','群芳过后西湖好，狼籍残红。',52,'宋词/ci.song.0.json','["群芳过后西湖好，狼籍残红。", "飞絮濛濛。", "垂柳阑干尽日风。", "笙歌散尽游人去，始觉春空。", "垂下帘栊。", "双燕归来细雨中。"]'),
('song-ci-602','采桑子','欧阳修','宋','宋词','song-ci','采桑子','["\u897f\u6e56"]','何人解赏西湖好，佳景无时。',52,'宋词/ci.song.0.json','["何人解赏西湖好，佳景无时。", "飞盖相追。", "贪向花间醉玉卮。", "谁知闲凭阑干处，芳草斜晖。", "水远烟微。", "一点沧洲白鹭飞。"]'),
('song-ci-603','采桑子','欧阳修','宋','宋词','song-ci','采桑子','["\u897f\u6e56"]','清明上巳西湖好，满目繁华。',52,'宋词/ci.song.0.json','["清明上巳西湖好，满目繁华。", "争道谁家。", "绿柳朱轮走钿车。", "游人日暮相将去，醒醉喧哗。", "路转堤斜。", "直到城头总是花。"]'),
('song-ci-604','采桑子','欧阳修','宋','宋词','song-ci','采桑子','["\u897f\u6e56"]','荷花开后西湖好，载酒来时。',52,'宋词/ci.song.0.json','["荷花开后西湖好，载酒来时。", "不用旌旗。", "前后红幢绿盖随。", "画船撑入花深处，香泛金卮。", "烟雨微微。", "一片笙歌醉里归。"]'),
('song-ci-605','采桑子','欧阳修','宋','宋词','song-ci','采桑子','["\u897f\u6e56"]','天容水色西湖好，云物俱鲜。',52,'宋词/ci.song.0.json','["天容水色西湖好，云物俱鲜。", "鸥鹭闲眠。", "应惯寻常听管弦。", "风清月白偏宜夜，一片琼田。", "谁羡骖鸾。", "人在舟中便是仙。"]'),
('song-ci-606','采桑子','欧阳修','宋','宋词','song-ci','采桑子','["\u897f\u6e56"]','残霞夕照西湖好，花坞苹汀。',52,'宋词/ci.song.0.json','["残霞夕照西湖好，花坞苹汀。", "十顷波平。", "野岸无人舟自横。", "西南月上浮云散，轩槛凉生。", "莲芰香清。", "水面风来酒面醒。"]'),
('song-ci-607','采桑子','欧阳修','宋','宋词','song-ci','采桑子','["\u897f\u6e56"]','平生为爱西湖好，来拥朱轮。',52,'宋词/ci.song.0.json','["平生为爱西湖好，来拥朱轮。", "富贵浮云。", "俯仰流年二十春。", "归来恰似辽东鹤，城郭人民。", "触目皆新。", "谁识当年旧主人。"]'),
('song-ci-608','采桑子','欧阳修','宋','宋词','song-ci','采桑子','[]','画楼钟动君休唱，往事无踪。',52,'宋词/ci.song.0.json','["画楼钟动君休唱，往事无踪。", "聚散匆匆。", "今日欢娱几客同。", "去年绿鬓今年白，不觉衰容。", "明月清风。", "把酒何人忆谢公。"]'),
('song-ci-609','采桑子','欧阳修','宋','宋词','song-ci','采桑子','[]','十年一别流光速，白首相逢。',52,'宋词/ci.song.0.json','["十年一别流光速，白首相逢。", "莫话衰翁。", "但斗尊前语笑同。", "劝君满酌君须醉，尽日从容。", "画鹢牵风。", "即去朝天沃舜聪。"]'),
('song-ci-610','采桑子','欧阳修','宋','宋词','song-ci','采桑子','[]','十年前是尊前客，月白风清。',52,'宋词/ci.song.0.json','["十年前是尊前客，月白风清。", "忧患凋零。", "老去光阴速可惊。", "鬓华虽改心无改，试把金觥。", "旧曲重听。", "犹是当年醉里声。"]'),
('song-ci-611','朝中措','欧阳修','宋','宋词','song-ci','朝中措','[]','平山阑槛倚晴空。',57,'宋词/ci.song.0.json','["平山阑槛倚晴空。", "山色有无中。", "手种堂前垂柳，别来几度春风。", "文章太守，挥毫万字，一饮千锺。", "行乐直须年少，尊前看取衰翁。"]'),
('song-ci-612','长相思','欧阳修','宋','宋词','song-ci','长相思','[]','苹满溪。',44,'宋词/ci.song.0.json','["苹满溪。", "柳绕堤。", "相送行人溪水西。", "回时陇月低。", "烟霏霏。", "风凄凄。", "重倚朱门听马嘶。", "寒鸥相对飞。"]'),
('song-ci-613','长相思','欧阳修','宋','宋词','song-ci','长相思','["\u957f\u6c5f"]','花似伊。',44,'宋词/ci.song.0.json','["花似伊。", "柳似伊。", "花柳青春人别离。", "低头双泪垂。", "长江东。", "长江西。", "两岸鸳鸯两处飞。", "相逢知几时。"]'),
('song-ci-614','长相思','欧阳修','宋','宋词','song-ci','长相思','[]','深花枝。',44,'宋词/ci.song.0.json','["深花枝。", "浅花枝。", "深浅花枝相并时。", "花枝难似伊。", "玉如肌。", "柳如眉。", "爱著鹅黄金缕衣。", "啼妆更为谁。"]'),
('song-ci-615','诉衷情','欧阳修','宋','宋词','song-ci','诉衷情','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','清晨帘幕卷轻霜。',55,'宋词/ci.song.0.json','["清晨帘幕卷轻霜。", "呵手试梅妆。", "都缘自有离恨，故画作远山长。", "思往事，惜流芳。", "易成伤。", "拟歌先敛，欲笑还颦，最断人肠。"]'),
('song-ci-616','踏莎行','欧阳修','宋','宋词','song-ci','踏莎行','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','候馆梅残，溪桥柳细。',68,'宋词/ci.song.0.json','["候馆梅残，溪桥柳细。", "草熏风暖摇征辔。", "离愁渐远渐无穷，迢迢不断如春水。", "寸寸柔肠，盈盈粉泪。", "楼高莫近危阑倚。", "平芜尽处是春山，行人更在春山外。"]'),
('song-ci-617','踏莎行','欧阳修','宋','宋词','song-ci','踏莎行','[]','雨霁风光，春分天气。',68,'宋词/ci.song.0.json','["雨霁风光，春分天气。", "千花百卉争明媚。", "画梁新燕一双双，玉笼鹦鹉愁孤睡。", "薜荔依墙，莓苔满地。", "青楼几处歌声丽。", "蓦然旧事心上来，无言敛皱眉山翠。"]'),
('song-ci-618','望江南・忆江南','欧阳修','宋','宋词','song-ci','望江南・忆江南','[]','江南蝶，斜日一双双。',64,'宋词/ci.song.0.json','["江南蝶，斜日一双双。", "身似何郎全傅粉，心如韩寿爱偷香。", "天赋与轻狂。", "微雨后，薄翅腻烟光。", "才伴游蜂来小院，又随飞絮过东墙。", "长是为花忙。"]'),
('song-ci-619','减字木兰花','欧阳修','宋','宋词','song-ci','减字木兰花','[]','留春不住。',52,'宋词/ci.song.0.json','["留春不住。", "燕老莺慵无觅处。", "说似残春。", "一老应无却少人。", "风和月好。", "办得黄金须买笑。", "爱惜芳时。", "莫待无花空折枝。"]'),
('song-ci-620','减字木兰花','欧阳修','宋','宋词','song-ci','减字木兰花','[]','伤怀离抱。',52,'宋词/ci.song.0.json','["伤怀离抱。", "天若有情天亦老。", "此意如何。", "细似轻丝渺似波。", "扁舟岸侧。", "枫叶荻花秋索索。", "细想前欢。", "须著人间比梦间。"]'),
('song-ci-621','减字木兰花','欧阳修','宋','宋词','song-ci','减字木兰花','[]','楼台向晓。',52,'宋词/ci.song.0.json','["楼台向晓。", "淡月低云天气好。", "翠幕风微。", "宛转梁州入破时。", "香生舞袂。", "楚女腰肢天与细。", "汗粉重匀。", "酒后轻寒不著人。"]'),
('song-ci-622','减字木兰花','欧阳修','宋','宋词','song-ci','减字木兰花','[]','画堂雅宴。',52,'宋词/ci.song.0.json','["画堂雅宴。", "一抹朱弦初入遍。", "慢拈轻笼。", "玉指纤纤嫩剥葱。", "拨头憁利。", "怨月愁花无限意。", "红粉轻盈。", "倚暖香檀曲未成。"]'),
('song-ci-623','减字木兰花','欧阳修','宋','宋词','song-ci','减字木兰花','[]','歌檀敛袂。',52,'宋词/ci.song.0.json','["歌檀敛袂。", "缭绕雕梁尘暗起。", "柔润清圆。", "百琲明珠一线穿。", "樱唇玉齿。", "天上仙音心下事。", "留往行云。", "满坐迷魂酒半醺。"]'),
('song-ci-624','生查子','欧阳修','宋','宋词','song-ci','生查子','[]','去年元夜时，花市灯如昼。',48,'宋词/ci.song.0.json','["去年元夜时，花市灯如昼。", "月到柳梢头，人约黄昏后。", "今年元夜时，月与灯依旧。", "不见去年人，泪满春衫袖。"]'),
('song-ci-625','生查子','欧阳修','宋','宋词','song-ci','生查子','[]','含羞整翠鬟，得意频相顾。',48,'宋词/ci.song.0.json','["含羞整翠鬟，得意频相顾。", "雁柱十三弦，一一春莺语。", "娇云容易飞，梦断知何处。", "深院锁黄昏，阵阵芭蕉雨。"]'),
('song-ci-626','清商怨','欧阳修','宋','宋词','song-ci','清商怨','[]','关河愁思望处满。',52,'宋词/ci.song.0.json','["关河愁思望处满。", "渐素秋向晚。", "雁过南云，行人回泪眼。", "双鸾衾裯悔展。", "夜又永、枕孤人远。", "梦未成归，梅花闻塞管。"]'),
('song-ci-627','阮郎归','欧阳修','宋','宋词','song-ci','阮郎归','[]','刘郎何日是来时。',56,'宋词/ci.song.0.json','["刘郎何日是来时。", "无心云胜伊。", "行云犹解傍山飞。", "郎行去不归。", "强匀画，又芳菲。", "春深轻薄衣。", "桃花无语伴相思。", "阴阴月上时。"]'),
('song-ci-628','阮郎归','欧阳修','宋','宋词','song-ci','阮郎归','[]','落花浮水树临池。',56,'宋词/ci.song.0.json','["落花浮水树临池。", "年前心眼期。", "见来无事去还思。", "而今花又飞。", "浅螺黛，淡燕脂。", "闲妆取次宜。", "隔帘风雨闭门时。", "此情风月知。"]'),
('song-ci-629','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','帘幕东风寒料峭。',70,'宋词/ci.song.0.json','["帘幕东风寒料峭。", "雪里香梅，先报春来早。", "红蜡枝头双燕小。", "金刀剪彩呈纤巧。", "旋暖金炉薰蕙藻。", "酒入横波，困不禁烦恼。", "绣被五更春睡好。", "罗帏不觉纱窗晓。"]'),
('song-ci-630','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','南雁依稀回侧阵。',70,'宋词/ci.song.0.json','["南雁依稀回侧阵。", "雪霁墙阴，遍觉兰芽嫩。", "中夜梦馀消酒困。", "炉香卷穗灯生晕。", "急景流年都一瞬。", "往事前欢，未免萦芳寸。", "腊后花期知渐近。", "东风已作寒梅信。"]'),
('song-ci-631','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','腊雪初销梅蕊绽。',70,'宋词/ci.song.0.json','["腊雪初销梅蕊绽。", "梅雪相和，喜鹊穿花转。", "睡起夕阳迷醉眼。", "新愁长向东风乱。", "瘦觉玉肌罗带缓。", "红杏梢头，二月春犹浅。", "望极不来芳信断。", "音书纵有争如见。"]'),
('song-ci-632','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','海燕双来归画栋。',70,'宋词/ci.song.0.json','["海燕双来归画栋。", "帘影无风，花影频移动。", "半醉腾腾春睡重。", "绿鬟堆枕香云拥。", "翠被双盘金缕凤。", "忆得前春，有个人人共。", "花里黄莺时一弄。", "日斜惊起相思梦。"]'),
('song-ci-633','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','面旋落花风荡漾。',70,'宋词/ci.song.0.json','["面旋落花风荡漾。", "柳重烟深，雪絮飞来往。", "雨后轻寒犹未放。", "春愁酒病成惆怅。", "枕畔屏山围碧浪。", "翠被华灯，夜夜空相向。", "寂寞起来褰绣幌。", "月明正在梨花上。"]'),
('song-ci-634','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','帘幕风轻双语燕。',70,'宋词/ci.song.0.json','["帘幕风轻双语燕。", "午后醒来，柳絮飞撩乱。", "心事一春犹未见。", "红英落尽青苔院。", "百尺朱楼闲倚遍。", "薄雨浓云，抵死遮人面。", "羌管不须吹别怨。", "无肠更为新声断。"]'),
('song-ci-635','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','永日环堤乘彩舫。',70,'宋词/ci.song.0.json','["永日环堤乘彩舫。", "烟草萧疏，恰似晴江上。", "水浸碧天风皱浪。", "菱花荇蔓随双桨。", "红粉佳人翻丽唱。", "惊起鸳鸯，两两飞相向。", "且把金尊倾美酿。", "休思往事成惆怅。"]'),
('song-ci-636','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','越女采莲秋水畔。',70,'宋词/ci.song.0.json','["越女采莲秋水畔。", "窄袖轻罗，暗露双金钏。", "照影摘花花似面。", "芳心只共丝争乱。", "鸂鶒滩头风浪晚。", "雾重烟轻，不见来时伴。", "隐隐歌声归棹远。", "离愁引著江南岸。"]'),
('song-ci-637','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','水浸秋天风皱浪。',70,'宋词/ci.song.0.json','["水浸秋天风皱浪。", "缥缈仙舟，只似秋天上。", "和露采莲愁一饷。", "看花却是啼妆样。", "折得莲茎丝未放。", "莲断丝牵，特地成惆怅。", "归棹莫随花荡漾。", "江头有个人相望。"]'),
('song-ci-638','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','梨叶初红婵韵歇。',70,'宋词/ci.song.0.json','["梨叶初红婵韵歇。", "银汉风高，玉管声凄切。", "枕簟乍凉铜漏彻。", "谁教社燕轻离别。", "草际虫吟秋露结。", "宿酒醒来，不记归时节。", "多少衷肠犹未说。", "珠帘夜夜朦胧月。"]'),
('song-ci-639','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','独倚危楼风细细。',70,'宋词/ci.song.0.json','["独倚危楼风细细。", "望极离愁，黯黯生天际。", "草色山光残照里。", "无人会得凭阑意。", "也拟疏狂图一醉。", "对酒当歌，强饮还无味。", "衣带渐宽都不悔。", "况伊销得人憔悴。"]'),
('song-ci-640','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','帘下清歌帘外宴。',70,'宋词/ci.song.0.json','["帘下清歌帘外宴。", "虽爱新声，不见如花面。", "牙板数敲珠一串。", "梁尘暗落琉璃盏。", "桐树花深孤凤怨。", "渐遏遥天，不放行云散。", "坐上少年听未惯。", "玉山将倒肠先断。"]'),
('song-ci-641','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','翠苑红芳晴满目。',70,'宋词/ci.song.0.json','["翠苑红芳晴满目。", "绮席流莺，上下长相逐。", "紫陌闲随金轹辘。", "马蹄踏遍春郊绿。", "一觉年华春梦促。", "往事悠悠，百种寻思足。", "烟雨满楼山断续。", "人闲倚遍阑干曲。"]'),
('song-ci-642','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','小院深深门掩亚。',70,'宋词/ci.song.0.json','["小院深深门掩亚。", "寂寞珠帘，画阁重重下。", "欲近禁烟微雨罢。", "绿杨深处秋千挂。", "傅粉狂游犹未舍。", "不念芳时，眉黛无人画。", "薄幸未归春去也。", "杏花零落香红谢。"]'),
('song-ci-643','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','欲过清明烟雨细。',70,'宋词/ci.song.0.json','["欲过清明烟雨细。", "小槛临窗，点点残花坠。", "梁燕语多惊晓睡。", "银屏一半堆香被。", "新岁风光如旧岁。", "所恨征轮，渐渐程迢递。", "纵有远情难写寄。", "何妨解有相思泪。"]'),
('song-ci-644','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','画阁归来春又晚。',70,'宋词/ci.song.0.json','["画阁归来春又晚。", "燕子双飞，柳软桃花浅。", "细雨满天风满院。", "愁眉敛尽无人见。", "独倚阑干心绪乱。", "芳草芊绵，尚忆江南岸。", "风月无情人暗换。", "旧游如梦空肠断。"]'),
('song-ci-645','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','["\u897f\u6e56"]','尝爱西湖春色早。',70,'宋词/ci.song.0.json','["尝爱西湖春色早。", "腊雪方销，已见桃开小。", "顷刻光阴都过了。", "如今绿暗红英少。", "且趁馀花谋一笑。", "况有笙歌，艳态相萦绕。", "老去风情应不到。", "凭君剩把芳尊倒。"]'),
('song-ci-646','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','一派潺湲流碧涨。',72,'宋词/ci.song.0.json','["一派潺湲流碧涨。", "新亭四面山相向。", "翠竹岭头明月上。", "迷俯仰。", "月轮正在泉中漾。", "更待高秋天气爽。", "菊花香里开新酿。", "酒美宾嘉真胜赏。", "红粉唱。", "山深分外歌声响。"]'),
('song-ci-647','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','十月小春梅蕊绽。',72,'宋词/ci.song.0.json','["十月小春梅蕊绽。", "红炉画阁新妆遍。", "锦帐美人贪睡暖。", "羞起晚。", "玉壶一夜冰澌满。", "楼上四垂帘不卷。", "天寒山色偏宜远。", "风急雁行吹字断。", "红日短。", "江天雪意云撩乱。"]'),
('song-ci-648','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','四纪才名天下重。',72,'宋词/ci.song.0.json','["四纪才名天下重。", "三朝构厦为梁栋。", "定册功成身退勇。", "辞荣宠。", "归来白首笙歌拥。", "顾我薄才无可用。", "君恩近许归田垅。", "今日一觞难得共。", "聊对捧。", "官奴为我高歌送。"]'),
('song-ci-649','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','暖日迟迟花袅袅。',72,'宋词/ci.song.0.json','["暖日迟迟花袅袅。", "人将红粉争花好。", "花不能言惟解笑。", "金壶倒。", "花开未老人年少。", "车马九门来扰扰。", "行人莫羡长安道。", "丹禁漏声衢鼓报。", "催昏晓。", "长安城里人先老。"]'),
('song-ci-650','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','红粉墙头花几树。',72,'宋词/ci.song.0.json','["红粉墙头花几树。", "落花片片和惊絮。", "墙外有楼花有主。", "寻花去。", "隔墙遥见秋千侣。", "绿索红旗双彩柱。", "行人只得偷回顾。", "肠断楼南金锁户。", "天欲暮。", "流莺飞到秋千处。"]'),
('song-ci-651','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','妾本钱塘苏小妹。',72,'宋词/ci.song.0.json','["妾本钱塘苏小妹。", "芙蓉花共门相对。", "昨日为逢青伞盖。", "慵不采。", "今朝斗觉凋零晒。", "愁倚画楼无计奈。", "乱红飘过秋塘外。", "料得明年秋色在。", "香可爱。", "其如镜里花颜改。"]'),
('song-ci-652','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','花底忽闻敲两桨。',72,'宋词/ci.song.0.json','["花底忽闻敲两桨。", "逡巡女伴来寻访。", "酒盏旋将荷叶当。", "莲舟荡。", "时时盏里生红浪。", "花气酒香清厮酿。", "花腮酒面红相向。", "醉倚绿阴眠一饷。", "惊起望。", "船头阁在沙滩上。"]'),
('song-ci-653','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','叶有清风花有露。',72,'宋词/ci.song.0.json','["叶有清风花有露。", "叶笼花罩鸳鸯侣。", "白锦顶丝红锦羽。", "莲女妒。", "惊飞不许长相聚。", "日脚沈红天色暮。", "青凉伞上微微雨。", "早是水寒无宿处。", "须回步。", "枉教雨里分飞去。"]'),
('song-ci-654','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','荷叶田田青照水。',72,'宋词/ci.song.0.json','["荷叶田田青照水。", "孤舟挽在花阴底。", "昨夜萧萧疏雨坠。", "愁不寐。", "朝来又觉西风起。", "雨摆风摇金蕊碎。", "合欢枝上香房翠。", "莲子与人长厮类。", "无好意。", "年年苦在中心里。"]'),
('song-ci-655','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','叶重如将青玉亚。',72,'宋词/ci.song.0.json','["叶重如将青玉亚。", "花轻疑是红绡挂。", "颜色清新香脱洒。", "堪长价。", "牡丹怎得称王者。", "雨笔露笺匀彩画。", "日炉风炭薰兰麝。", "天与多情丝一把。", "谁厮惹。", "千条万缕萦心下。"]'),
('song-ci-656','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','粉蕊丹青描不得。',72,'宋词/ci.song.0.json','["粉蕊丹青描不得。", "金针线线功难敌。", "谁傍暗香轻采摘。", "风淅淅。", "船头触散双鸂鶒。", "夜雨染成天水碧。", "朝阳借出胭脂色。", "欲落又开人共惜。", "秋气逼。", "盘中已见新荷的。"]'),
('song-ci-657','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','幽鹭谩来窥品格。',72,'宋词/ci.song.0.json','["幽鹭谩来窥品格。", "双鱼岂解传消息。", "绿柄嫩香频采摘。", "心似织。", "条条不断谁牵役。", "珠泪暗和清露滴。", "罗衣染尽秋江色。", "对面不言情脉脉。", "烟水隔。", "无人说似长相忆。"]'),
('song-ci-658','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','楚国细腰元自瘦。',72,'宋词/ci.song.0.json','["楚国细腰元自瘦。", "文君腻脸谁描就。", "日夜鼓声催箭漏。", "昏复昼。", "红颜岂得长如旧。", "醉拆嫩房红蕊嗅。", "天丝不断清香透。", "却傍小阑凝望久。", "风满袖。", "西池月上人归后。"]'),
('song-ci-659','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','喜鹊填河仙浪浅。',72,'宋词/ci.song.0.json','["喜鹊填河仙浪浅。", "云軿早在星桥畔。", "街鼓黄昏霞尾暗。", "炎光敛。", "金钩侧倒天西面。", "一别经年今始见。", "新欢往恨知何限。", "天上佳期贪眷恋。", "良宵短。", "人间不合催银箭。"]'),
('song-ci-660','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','乞巧楼头云幔卷。',72,'宋词/ci.song.0.json','["乞巧楼头云幔卷。", "浮花催洗严妆面。", "花上蛛丝寻得遍。", "颦笑浅。", "双眸望月牵红线。", "奕奕天河光不断。", "有人正在长生殿。", "暗付金钗清夜半。", "千秋愿。", "年年此会长相见。"]'),
('song-ci-661','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','别恨长长欢计短。',72,'宋词/ci.song.0.json','["别恨长长欢计短。", "疏锺促漏真堪怨。", "此会此情都未半。", "星初转。", "鸾琴凤乐匆匆卷。", "河鼓无言西北盼。", "香蛾有恨东南远。", "脉脉横波珠泪满。", "归心乱。", "离肠便逐星桥断。"]'),
('song-ci-662','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','九日欢游何处好。',72,'宋词/ci.song.0.json','["九日欢游何处好。", "黄花万蕊雕阑绕。", "通体清香无俗调。", "天气好。", "烟滋露结功多少。", "日脚清寒高下照。", "宝钉密缀圆斜小。", "落叶西园风袅袅。", "催秋老。", "丛边莫厌金尊倒。"]'),
('song-ci-663','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','青女霜前催得绽。',72,'宋词/ci.song.0.json','["青女霜前催得绽。", "金钿乱散枝头遍。", "落帽台高开雅宴。", "芳尊满。", "挼花吹在流霞面。", "桃李三春虽可羡。", "莺来蝶去芳心乱。", "争似仙潭秋水岸。", "香不断。", "年年自作茱萸伴。"]'),
('song-ci-664','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','露裛娇黄风摆翠。',72,'宋词/ci.song.0.json','["露裛娇黄风摆翠。", "人间晚秀非无意。", "仙格淡妆天与丽。", "谁可比。", "女真装束真相似。", "筵上佳人牵翠袂。", "纤纤玉手挼新蕊。", "美酒一杯花影腻。", "邀客醉。", "红琼共作熏熏媚。"]'),
('song-ci-665','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','对酒当歌劳客劝。',72,'宋词/ci.song.0.json','["对酒当歌劳客劝。", "惜花只惜年华晚。", "寒艳冷香秋不管。", "情眷眷。", "凭栏尽日愁无限。", "思抱芳期随塞雁。", "悔无深意传双燕。", "怅望一枝难寄远。", "人不见。", "楼头望断相思眼。"]'),
('song-ci-666','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','风迟日媚烟光好。',64,'宋词/ci.song.0.json','["风迟日媚烟光好。", "绿树依依芳意早。", "年华容易即凋零，春色只宜长恨少。", "池塘隐隐惊雷晓。", "柳眼未开梅萼小。", "尊前贪爱物华新，不道物新人渐老。"]'),
('song-ci-667','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','西亭饮散清歌阕。',64,'宋词/ci.song.0.json','["西亭饮散清歌阕。", "花外迟迟宫漏发。", "涂金烛引紫骝嘶，柳曲西头归路别。", "佳辰只恐幽期阔。", "密赠殷勤衣上结。", "翠屏魂梦莫相寻，禁断六街清夜月。"]'),
('song-ci-668','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','春山敛黛低歌扇。',64,'宋词/ci.song.0.json','["春山敛黛低歌扇。", "暂解吴钩登祖宴。", "画楼钟动已魂销，何况马嘶芳草岸。", "青门柳色随人远。", "望欲断时肠已断。", "洛城春色待君来，莫到落花飞似霰。"]'),
('song-ci-669','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','尊前拟把归期说。',64,'宋词/ci.song.0.json','["尊前拟把归期说。", "未语春容先惨咽。", "人生自是有情痴，此恨不关风与月。", "离歌且莫翻新阕。", "一曲能教肠寸结。", "直须看尽洛城花，始共春风容易别。"]'),
('song-ci-670','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','洛阳正值芳菲节。',64,'宋词/ci.song.0.json','["洛阳正值芳菲节。", "秾艳清香相间发。", "游丝有意苦相萦，垂柳无端争赠别。", "杏花红处青山缺。", "山畔行人山下歇。", "今宵谁肯远相随，惟有寂寥孤馆月。"]'),
('song-ci-671','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','残春一夜狂风雨。',64,'宋词/ci.song.0.json','["残春一夜狂风雨。", "断送红飞花落树。", "人心花意待留春，春色无情容易去。", "高楼把酒愁独语。", "借问春归何处所。", "暮云空阔不知音，惟有绿杨芳草路。"]'),
('song-ci-672','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','常忆洛阳风景媚。',64,'宋词/ci.song.0.json','["常忆洛阳风景媚。", "烟暖风和添酒味。", "莺啼宴席似留人，花出墙头如有意。", "别来已隔千山翠。", "望断危楼斜日坠。", "关心只为牡丹红，一片春愁来梦里。"]'),
('song-ci-673','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','池塘水绿春微暖。',64,'宋词/ci.song.0.json','["池塘水绿春微暖。", "记得玉真初见面。", "从头歌韵响铮鏦，入破舞腰红乱旋。", "玉钩帘下香阶畔。", "醉后不知红日晚。", "当时共我赏花人，点检如今无一半。"]'),
('song-ci-674','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','两翁相遇逢佳节。',64,'宋词/ci.song.0.json','["两翁相遇逢佳节。", "正值柳绵飞似雪。", "便须豪饮敌青春，莫对新花羞白发。", "人生聚散如弦筈。", "老去风情尤惜别。", "大家金盏倒垂莲，一任西楼低晓月。"]'),
('song-ci-675','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','["\u897f\u6e56"]','西湖南北烟波阔。',64,'宋词/ci.song.0.json','["西湖南北烟波阔。", "风里丝簧声韵咽。", "舞馀裙带绿双垂，酒入香腮红一抹。", "杯深不觉琉璃滑。", "贪看六么花十八。", "明朝车马各西东，惆怅画桥风与月。"]'),
('song-ci-676','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','燕鸿过后春归去。',64,'宋词/ci.song.0.json','["燕鸿过后春归去。", "细算浮生千万绪。", "来如春梦几多时，去似朝云无觅处。", "闻琴解珮神仙侣。", "挽断罗衣留不住。", "劝君莫作独醒人，烂醉花间应有数。"]'),
('song-ci-677','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','蝶飞芳草花飞路。',64,'宋词/ci.song.0.json','["蝶飞芳草花飞路。", "把酒已嗟春色暮。", "当时枝上落残花，今日水流何处去。", "楼前独绕鸣蝉树。", "忆把芳条吹暖絮。", "红莲绿芰亦芳菲，不奈金风兼玉露。"]'),
('song-ci-678','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','别后不知君远近。',64,'宋词/ci.song.0.json','["别后不知君远近。", "触目凄凉多少闷。", "渐行渐远渐无书，水阔鱼沈何处问。", "夜深风竹敲秋韵。", "万叶千声皆是恨。", "故欹单枕梦中寻，梦又不成灯又尽。"]'),
('song-ci-679','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','红条约束琼肌稳。',64,'宋词/ci.song.0.json','["红条约束琼肌稳。", "拍碎香檀催急衮。", "陇头呜咽水声繁，叶下间关莺语近。", "美人才子传芳信。", "明月清风伤别恨。", "未知何处有知音，常为此情留此恨。"]'),
('song-ci-680','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','檀槽碎响金丝拨。',64,'宋词/ci.song.0.json','["檀槽碎响金丝拨。", "露湿浔阳江上月。", "不知商妇为谁愁，一曲行人留夜发。", "画堂花月新声别。", "红蕊调长弹未彻。", "暗将深意祝胶弦，唯愿弦弦无断绝。"]'),
('song-ci-681','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','春葱指甲轻拢拈。',64,'宋词/ci.song.0.json','["春葱指甲轻拢拈。", "五彩垂条双袖卷。", "雪香浓透紫檀槽，胡语急随红玉腕。", "当头一曲情何限。", "入破铮鏦金凤战。", "百分芳酒祝长春，再拜敛容抬粉面。"]'),
('song-ci-682','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','金花盏面红烟透。',64,'宋词/ci.song.0.json','["金花盏面红烟透。", "舞急香茵随步皱。", "青春才子有新词，红粉佳人重劝酒。", "也知自为伤春瘦。", "归骑休交银烛候。", "拟将沈醉为清欢，无奈醒来还感旧。"]'),
('song-ci-683','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','雪云乍变春云簇。',64,'宋词/ci.song.0.json','["雪云乍变春云簇。", "渐觉年华堪送目。", "北枝梅蕊犯寒开，南浦波纹如酒绿。", "芳菲次第还相续。", "不奈情多无处足。", "尊前百计得春归，莫为伤春歌黛蹙。"]'),
('song-ci-684','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','黄金弄色轻於粉。',64,'宋词/ci.song.0.json','["黄金弄色轻於粉。", "濯濯春条如水嫩。", "为缘力薄未禁风，不奈多娇长似困。", "腰柔乍怯人相近。", "眉小未知春有恨。", "劝君著意惜芳菲，莫待行人攀折尽。"]'),
('song-ci-685','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','珠帘半下香销印。',64,'宋词/ci.song.0.json','["珠帘半下香销印。", "二月东风催柳信。", "琵琶傍畔且寻思，鹦鹉前头休借问。", "惊鸿过后生离恨。", "红日长时添酒困。", "未知心在阿谁边，满眼泪珠言不尽。"]'),
('song-ci-686','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','沈沈庭院莺吟弄。',64,'宋词/ci.song.0.json','["沈沈庭院莺吟弄。", "日暖烟和春气重。", "绿杨娇眼为谁回，芳草深心空自动。", "倚阑无语伤离凤。", "一片风情无处用。", "寻思还有旧家心，蝴蝶时时来役梦。"]'),
('song-ci-687','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','去时梅萼初凝粉。',64,'宋词/ci.song.0.json','["去时梅萼初凝粉。", "不觉小桃风力损。", "梨花最晚又凋零，何事归期无定准。", "阑干倚遍重来凭。", "泪粉偷将红袖印。", "蜘蛛喜鹊误人多，似此无凭安足信。"]'),
('song-ci-688','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','酒美春浓花世界。',64,'宋词/ci.song.0.json','["酒美春浓花世界。", "得意人人千万态。", "莫教辜负艳阳天，过了堆金何处买。", "已去少年无计奈。", "且愿芳心长恁在。", "闲愁一点上心来，算得东风吹不解。"]'),
('song-ci-689','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','湖边柳外楼高处。',64,'宋词/ci.song.0.json','["湖边柳外楼高处。", "望断云山多少路。", "阑干倚遍使人愁，又是天涯初日暮。", "轻无管系狂无数。", "水畔花飞风里絮。", "算伊浑似薄情郎，去便不来来便去。"]'),
('song-ci-690','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','南园粉蝶能无数。',64,'宋词/ci.song.0.json','["南园粉蝶能无数。", "度翠穿红来复去。", "倡条冶叶恣留连，飘荡轻於花上絮。", "朱阑夜夜风兼露。", "宿粉栖香无定所。", "多情翻却似无情，赢得百花无限妒。"]'),
('song-ci-691','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','江南三月春光老。',64,'宋词/ci.song.0.json','["江南三月春光老。", "月落禽啼天未晓。", "露和啼血染花红，恨过千家烟树杪。", "云垂玉枕屏山小。", "梦欲成时惊觉了。", "人心应不似伊心，若解思归归合早。"]'),
('song-ci-692','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','东风本是开花信。',64,'宋词/ci.song.0.json','["东风本是开花信。", "及至花时风更紧。", "吹开吹谢苦匆匆，春意到头无处问。", "把酒临风千万恨。", "欲扫残红犹未忍。", "夜来风雨转离披，满眼凄凉愁不尽。"]'),
('song-ci-693','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','阴阴树色笼晴昼。',64,'宋词/ci.song.0.json','["阴阴树色笼晴昼。", "清淡园林春过后。", "杏腮轻粉日催红，池面绿罗风卷皱。", "佳人向晚新妆就。", "圆腻歌喉珠欲溜。", "当筵莫放酒杯迟，乐事良辰难入手。"]'),
('song-ci-694','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','芙蓉斗晕燕支浅。',64,'宋词/ci.song.0.json','["芙蓉斗晕燕支浅。", "留著晚花开小宴。", "画船红日晚风清，柳色溪光晴照暖。", "美人争劝梨花盏。", "舞困玉腰裙缕慢。", "莫交银烛促归期，已祝斜阳休更晚。"]'),
('song-ci-695','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','正月斗杓初转势。',72,'宋词/ci.song.0.json','["正月斗杓初转势。", "金刀剪彩功夫异。", "称庆高堂欢幼稚。", "看柳意。", "偏从东面春风至。", "十四新蟾圆尚未。", "楼前乍看红灯试。", "冰散绿池泉细细。", "鱼欲戏。", "园林已是花天气。"]'),
('song-ci-696','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','二月春耕昌杏密。',72,'宋词/ci.song.0.json','["二月春耕昌杏密。", "百花次第争先出。", "惟有海棠梨第一。", "深浅拂。", "天生红粉真无匹。", "画栋归来巢未失。", "双双款语怜飞乙。", "留客醉花迎晓日。", "金盏溢。", "却忧风雨飘零疾。"]'),
('song-ci-697','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','三月清明天婉娩。',72,'宋词/ci.song.0.json','["三月清明天婉娩。", "晴川祓禊归来晚。", "况是踏青来处远。", "犹不倦。", "秋千别闭深庭院。", "更值牡丹开欲遍。", "酴醿压架清香散。", "花底一尊谁解劝。", "增眷恋。", "东风回晚无情绊。"]'),
('song-ci-698','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','四月园林春去后。',72,'宋词/ci.song.0.json','["四月园林春去后。", "深深密幄阴初茂。", "折得花枝犹在手。", "香满袖。", "叶间梅子青如豆。", "风雨时时添气候。", "成行新笋霜筠厚。", "题就送春诗几首。", "聊对酒。", "樱桃色照银盘溜。"]'),
('song-ci-699','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','五月榴花妖艳烘。',72,'宋词/ci.song.0.json','["五月榴花妖艳烘。", "绿杨带雨垂垂重。", "五色新丝缠角粽。", "金盘送。", "生绡画扇盘双凤。", "正是浴兰时节动。", "菖蒲酒美清尊共。", "叶里黄骊时一弄。", "犹瞢忪。", "等闲惊破纱窗梦。"]'),
('song-ci-700','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','六月炎天时霎雨。',72,'宋词/ci.song.0.json','["六月炎天时霎雨。", "行云涌出奇峰露。", "沼上嫩莲腰束素。", "风兼露。", "梁王宫阕无烦暑。", "畏日亭亭残蕙炷。", "傍帘乳燕双飞去。", "碧碗敲冰倾玉处。", "朝与暮。", "故人风快凉轻度。"]'),
('song-ci-701','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','七月新秋风露早。',72,'宋词/ci.song.0.json','["七月新秋风露早。", "渚莲尚拆庭梧老。", "是处瓜华时节好。", "金尊倒。", "人间采缕争祈巧。", "万叶敲声凉乍到。", "百虫啼晚烟如扫。", "箭漏初长天杳杳。", "人语悄。", "那堪夜雨催清晓。"]'),
('song-ci-702','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','八月秋高风历乱。',72,'宋词/ci.song.0.json','["八月秋高风历乱。", "衰兰败芷红莲岸。", "皓月十分光正满。", "清光畔。", "年年常愿琼筵看。", "社近愁看归去燕。", "江天空阔云容漫。", "宋玉当时情不浅。", "成幽怨。", "乡关千里危肠断。"]'),
('song-ci-703','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','九月霜秋秋已尽。',72,'宋词/ci.song.0.json','["九月霜秋秋已尽。", "烘林败叶红相映。", "惟有东篱黄菊盛。", "遗金粉。", "人家帘幕重阳近。", "晓日阴阴晴未定。", "授衣时节轻寒嫩。", "新雁一声风又劲。", "云欲凝。", "雁来应有吾乡信。"]'),
('song-ci-704','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','十月小春梅蕊绽。',72,'宋词/ci.song.0.json','["十月小春梅蕊绽。", "红炉画阁新妆遍。", "鸳帐美人贪睡暖。", "梳洗懒。", "玉壶一夜轻澌满。", "楼上四垂帘不卷。", "天寒山色偏宜远。", "风急雁行吹字断。", "红日晚。", "江天雪意云撩乱。"]'),
('song-ci-705','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','十一月新阳排寿宴。',73,'宋词/ci.song.0.json','["十一月新阳排寿宴。", "黄锺应管添宫线。", "猎猎寒威云不卷。", "风头转。", "时看雪霰吹人面。", "南至迎长知漏箭。", "书云纪候冰生妍。", "腊近探春春尚远。", "闲庭院。", "梅花落尽千千片。"]'),
('song-ci-706','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','十二月严凝天地闭。',73,'宋词/ci.song.0.json','["十二月严凝天地闭。", "莫嫌台榭无花卉。", "惟有酒能欺雪意。", "增豪气。", "直教耳热笙歌沸。", "陇上雕鞍惟数骑。", "猎围半合新霜里。", "霜重鼓声寒不起。", "千人指。", "马前一雁寒空坠。"]'),
('song-ci-707','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','正月新阳生翠琯。',72,'宋词/ci.song.0.json','["正月新阳生翠琯。", "花苞柳线春犹浅。", "帘幕千重方半卷。", "池冰泮。", "东风吹水琉璃软。", "渐好凭阑醒醉眼。", "陇梅暗落芳英断。", "初日已知长一线。", "清宵短。", "梦魂怎奈珠宫远。"]'),
('song-ci-708','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','二月春期看已半。',72,'宋词/ci.song.0.json','["二月春期看已半。", "江边春色青犹短。", "天气养花红日暖。", "深深院。", "真珠帘额初飞燕。", "渐觉衔杯心绪懒。", "酒侵花脸娇波慢。", "一捻闲愁无处遣。", "牵不断。", "游丝百尺随风远。"]'),
('song-ci-709','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','三月芳菲看欲暮。',72,'宋词/ci.song.0.json','["三月芳菲看欲暮。", "胭脂泪洒梨花雨。", "宝马绣轩南陌路。", "笙歌举。", "踏青斗草人无数。", "强欲留春春不住。", "东皇肯信韶容故。", "安得此身如柳絮。", "随风去。", "穿帘透幕寻朱户。"]'),
('song-ci-710','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','四月芳林何悄悄。',72,'宋词/ci.song.0.json','["四月芳林何悄悄。", "绿阴满地青梅小。", "南陌采桑何窈窕。", "争语笑。", "乱丝满腹吴蚕老。", "宿酒半醒新睡觉。", "雏莺相语匆匆晓。", "惹得此情萦寸抱。", "休临眺。", "楼头一望皆芳草。"]'),
('song-ci-711','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','五月薰风才一信。',72,'宋词/ci.song.0.json','["五月薰风才一信。", "初荷出水清香嫩。", "乳燕学飞帘额峻。", "谁借问。", "东邻期约尝佳酝。", "漏短日长人乍困。", "裙腰减尽柔肌损。", "一撮眉尖千叠恨。", "慵整顿。", "黄梅雨细多闲闷。"]'),
('song-ci-712','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','六月炎蒸何太盛。',72,'宋词/ci.song.0.json','["六月炎蒸何太盛。", "海榴灼灼红相映。", "天外奇峰千掌迥。", "风影定。", "汉宫圆扇初成咏。", "珠箔初褰深院静。", "绛绡衣窄冰肤莹。", "睡起日高堆酒兴。", "厌厌病。", "宿酲和梦何时醒。"]'),
('song-ci-713','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','七月芙蓉生翠水。',72,'宋词/ci.song.0.json','["七月芙蓉生翠水。", "明霞拂脸新妆媚。", "疑是楚宫歌舞妓。", "争宠丽。", "临风起舞夸腰细。", "乌鹊桥边新雨霁。", "长河清水冰无地。", "此夕有人千里外。", "经年岁。", "犹嗟不及牵牛会。"]'),
('song-ci-714','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','八月微凉生枕簟。',72,'宋词/ci.song.0.json','["八月微凉生枕簟。", "金盘露洗秋光淡。", "池上月华开宝鉴。", "波潋滟。", "故人千里应凭槛。", "蝉树无情风苒苒。", "燕归碧海珠帘揜。", "沈臂冒霜潘鬓减。", "愁黯黯。", "年年此夕多悲感。"]'),
('song-ci-715','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','九月重阳还又到。',72,'宋词/ci.song.0.json','["九月重阳还又到。", "东篱菊放金钱小。", "月下风前愁不少。", "谁语笑。", "吴娘捣练腰肢袅。", "槁叶半轩慵更扫。", "凭阑岂是闲临眺。", "欲向南云新雁道。", "休草草。", "来时觅取伊消耗。"]'),
('song-ci-716','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','十月轻寒生晚暮。',72,'宋词/ci.song.0.json','["十月轻寒生晚暮。", "霜华暗卷楼南树。", "十二阑干堪倚处。", "聊一顾。", "乱山衰草还家路。", "悔别情怀多感慕。", "胡笳不管离心苦。", "犹喜清宵长数鼓。", "双绣户。", "梦魂尽远还须去。"]'),
('song-ci-717','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','律应黄锺寒气苦。',72,'宋词/ci.song.0.json','["律应黄锺寒气苦。", "冰生玉水云如絮。", "千里乡关空倚慕。", "无尺素。", "双鱼不食南鸿渡。", "把酒遣愁愁已去。", "风吹酒力愁还聚。", "却忆兽炉追旧处。", "头懒举。", "炉灰剔尽痕无数。"]'),
('song-ci-718','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','腊月年光如激浪。',72,'宋词/ci.song.0.json','["腊月年光如激浪。", "冻云欲折寒根向。", "谢女雪诗真绝唱。", "无比况。", "长堤柳絮飞来往。", "便好开尊夸酒量。", "酒阑莫遣笙歌放。", "此去青春都一饷。", "休怅望。", "瑶林即日堪寻访。"]'),
('song-ci-719','南歌子','欧阳修','宋','宋词','song-ci','南歌子','[]','凤髻金泥带，龙纹玉掌梳。',62,'宋词/ci.song.0.json','["凤髻金泥带，龙纹玉掌梳。", "走来窗下笑相扶。", "爱道画眉深浅、入时无。", "弄笔偎人久，描花试手初。", "等闲妨了绣功夫。", "笑问双鸳鸯字、怎生书。"]'),
('song-ci-720','御街行','欧阳修','宋','宋词','song-ci','御街行','[]','夭非华艳轻非雾。',92,'宋词/ci.song.0.json','["夭非华艳轻非雾。", "来夜半、天明去。", "来如春梦不多时，去似朝云何处。", "乳鸡酒燕，落星沈月，紞紞城头鼓。", "参差渐辨西池树。", "朱阁斜欹户。", "绿苔深径少人行，苔上屐痕无数。", "遗香馀粉，剩衾闲枕，天把多情赋。"]'),
('song-ci-721','桃源忆故人','欧阳修','宋','宋词','song-ci','桃源忆故人','[]','梅梢弄粉香犹嫩。',56,'宋词/ci.song.0.json','["梅梢弄粉香犹嫩。", "欲寄江南春信。", "别后寸肠萦损。", "说与伊争稳。", "小炉独守寒灰尽。", "忍泪低头画尽。", "眉上万重新恨。", "竟日无人问。"]'),
('song-ci-722','桃源忆故人','欧阳修','宋','宋词','song-ci','桃源忆故人','[]','莺愁燕苦春归去。',56,'宋词/ci.song.0.json','["莺愁燕苦春归去。", "寂寂花飘红雨。", "碧草绿杨歧路。", "况是长亭暮。", "少年行客情难诉。", "泣对东风无语。", "目断两三烟树。", "翠隔江淹浦。"]'),
('song-ci-723','临江仙','欧阳修','宋','宋词','song-ci','临江仙','[]','柳外轻雷池上雨，雨声滴碎荷声。',68,'宋词/ci.song.0.json','["柳外轻雷池上雨，雨声滴碎荷声。", "小楼西角断虹明。", "阑干倚处，待得月华生。", "燕子飞来窥画栋，玉钩垂下帘旌。", "凉波不动簟纹平。", "水精双枕，傍有堕钗横。"]'),
('song-ci-724','临江仙','欧阳修','宋','宋词','song-ci','临江仙','[]','记得金銮同唱第，春风上国繁华。',68,'宋词/ci.song.0.json','["记得金銮同唱第，春风上国繁华。", "如今薄宦老天涯。", "十年歧路，空负曲江花。", "闻说阆山通阆苑，楼高不见君家。", "孤城寒日等闲斜。", "离愁难尽，红树远连霞。"]'),
('song-ci-725','圣无忧・乌夜啼','欧阳修','宋','宋词','song-ci','圣无忧・乌夜啼','[]','世路风波险，十年一别须臾。',55,'宋词/ci.song.0.json','["世路风波险，十年一别须臾。", "人生聚散长如此，相见且欢娱。", "好酒能消光景，春风不染髭鬚。", "为公一醉花前倒，红袖莫来扶。"]'),
('song-ci-726','浪淘沙','欧阳修','宋','宋词','song-ci','浪淘沙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','把酒祝东风。',64,'宋词/ci.song.0.json','["把酒祝东风。", "且共从容。", "垂杨紫陌洛城东。", "总是当时携手处，游遍芳丛。", "聚散苦匆匆。", "此恨无穷。", "今年花胜去年红。", "可惜明年花更好，知与谁同。"]'),
('song-ci-727','浪淘沙','欧阳修','宋','宋词','song-ci','浪淘沙','[]','花外倒金翘。',64,'宋词/ci.song.0.json','["花外倒金翘。", "饮散无憀。", "柔桑蔽日柳迷条。", "此地年时会一醉，还是春朝。", "今日举轻桡。", "帆影飘飘。", "长亭回首短亭遥。", "过尽长亭人更远，特地魂销。"]'),
('song-ci-728','浪淘沙','欧阳修','宋','宋词','song-ci','浪淘沙','[]','五岭麦秋残。',64,'宋词/ci.song.0.json','["五岭麦秋残。", "荔子初丹。", "绛纱囊里水晶丸。", "可惜天教生处远，不近长安。", "往事忆开元。", "妃子偏怜。", "一从魂散马嵬关。", "只有红尘无驿使，满眼骊山。"]'),
('song-ci-729','浪淘沙','欧阳修','宋','宋词','song-ci','浪淘沙','[]','万恨苦绵绵。',64,'宋词/ci.song.0.json','["万恨苦绵绵。", "旧约前欢。", "桃花溪畔柳阴间。", "几度日高春垂重，绣户深关。", "楼外夕阳闲。", "独自凭阑。", "一重水隔一重山。", "水阔山高人不见，有泪无言。"]'),
('song-ci-730','浪淘沙','欧阳修','宋','宋词','song-ci','浪淘沙','[]','今日北池游。',64,'宋词/ci.song.0.json','["今日北池游。", "漾漾轻舟。", "波光潋滟柳条柔。", "如此春来春又去，白了人头。", "好妓好歌喉。", "不醉难休。", "劝君满满酌金瓯。", "纵使花时常病酒，也是风流。"]'),
('song-ci-731','定风波','欧阳修','宋','宋词','song-ci','定风波','[]','把酒花前欲问他。',73,'宋词/ci.song.0.json','["把酒花前欲问他。", "对花何吝醉颜酡。", "春到几人能烂赏。", "何况。", "无情风雨等闲多。", "艳树香丛都几许。", "朝暮。", "惜红愁粉奈情何。", "好是金船浮玉浪。", "相向。", "十分深送一声歌。"]'),
('song-ci-732','定风波','欧阳修','宋','宋词','song-ci','定风波','[]','把酒花前欲问伊。',73,'宋词/ci.song.0.json','["把酒花前欲问伊。", "忍嫌金盏负春时。", "红颜不能旬日看。", "宜算。", "须知开谢只相随。", "蝶去蝶来犹解恋。", "难见。", "回头还是度年期。", "莫候饮阑花已尽。", "方信。", "无人堪与补残枝。"]'),
('song-ci-733','定风波','欧阳修','宋','宋词','song-ci','定风波','[]','把酒花前欲问公。',73,'宋词/ci.song.0.json','["把酒花前欲问公。", "对花何事诉金锺。", "为问去年春甚处。", "虚度。", "莺声撩乱一场空。", "今岁春来须爱惜。", "难得。", "须知花面不长红。", "待得酒醒君不见。", "千片。", "不随流水即随风。"]'),
('song-ci-734','定风波','欧阳修','宋','宋词','song-ci','定风波','[]','把酒花前欲问君。',73,'宋词/ci.song.0.json','["把酒花前欲问君。", "世间何计可留春。", "纵使青春留得住。", "虚语。", "无情花对有情人。", "任是好花须落去。", "自古。", "红颜能得几时新。", "暗想浮生何时好。", "唯有。", "清歌一曲倒金尊。"]'),
('song-ci-735','定风波','欧阳修','宋','宋词','song-ci','定风波','[]','过尽韶华不可添。',73,'宋词/ci.song.0.json','["过尽韶华不可添。", "小楼红日下层檐。", "春睡觉来情绪恶。", "寂寞。", "杨花缭乱拂珠帘。", "早是闲愁依旧在。", "无奈。", "那堪更被宿酲兼。", "把酒送春惆怅甚。", "长恁。", "年年三月病厌厌。"]'),
('song-ci-736','定风波','欧阳修','宋','宋词','song-ci','定风波','[]','对酒追欢莫负春。',73,'宋词/ci.song.0.json','["对酒追欢莫负春。", "春光归去可饶人。", "昨日红芳今绿树。", "已暮。", "残花飞絮两纷纷。", "粉面丽姝歌窈窕。", "清妙。", "尊前信任醉醺醺。", "不是狂心贪燕乐。", "自觉。", "年来白发满头新。"]'),
('song-ci-737','蓦山溪','欧阳修','宋','宋词','song-ci','蓦山溪','[]','新正初破，三五银蟾满。',102,'宋词/ci.song.0.json','["新正初破，三五银蟾满。", "纤手染香罗，剪红莲、满城开遍。", "楼台上下，歌管咽春风，驾香轮，停宝马，只待金乌晚。", "帝城今夜，罗绮谁为伴。", "应卜紫姑神，问归期、相思望断。", "天涯情绪，对酒且开颜，春宵短。", "春寒浅。", "莫待金杯暖。"]'),
('song-ci-738','浣溪沙','欧阳修','宋','宋词','song-ci','浣溪沙','[]','云曳香绵彩柱高。',48,'宋词/ci.song.0.json','["云曳香绵彩柱高。", "绛旗风飐出花梢。", "一梭红带往来抛。", "束素美人羞不打，却嫌裙慢褪纤腰。", "日斜深院影空摇。"]'),
('song-ci-739','浣溪沙','欧阳修','宋','宋词','song-ci','浣溪沙','[]','堤上游人逐画船。',48,'宋词/ci.song.0.json','["堤上游人逐画船。", "拍堤春水四垂天。", "绿杨楼外出秋千。", "白发戴花君莫笑，六么催拍盏频传。", "人生何处似尊前。"]'),
('song-ci-740','浣溪沙','欧阳修','宋','宋词','song-ci','浣溪沙','[]','湖上朱桥响画轮。',48,'宋词/ci.song.0.json','["湖上朱桥响画轮。", "溶溶春水浸春云。", "碧琉璃滑净无尘。", "当路游丝萦醉客，隔花啼鸟唤行人。", "日斜归去奈何春。"]'),
('song-ci-741','浣溪沙','欧阳修','宋','宋词','song-ci','浣溪沙','[]','叶底青青杏子垂。',48,'宋词/ci.song.0.json','["叶底青青杏子垂。", "枝头薄薄柳绵飞。", "日高深院晚莺啼。", "堪恨风流成薄幸，断无消息道归期。", "托腮无语翠眉低。"]'),
('song-ci-742','浣溪沙','欧阳修','宋','宋词','song-ci','浣溪沙','[]','青杏园林著酒香。',48,'宋词/ci.song.0.json','["青杏园林著酒香。", "佳人初著薄罗裳。", "柳丝摇曳燕飞忙。", "乍雨乍晴花自落，闲愁闲闷昼偏长。", "为谁消瘦损容光。"]'),
('song-ci-743','浣溪沙','欧阳修','宋','宋词','song-ci','浣溪沙','[]','红粉佳人白玉杯。',48,'宋词/ci.song.0.json','["红粉佳人白玉杯。", "木兰船稳棹歌催。", "绿荷风里笑声来。", "细雨轻烟笼草树，斜桥曲水绕楼台。", "夕阳高处画屏开。"]'),
('song-ci-744','浣溪沙','欧阳修','宋','宋词','song-ci','浣溪沙','[]','翠袖娇鬟舞石州。',48,'宋词/ci.song.0.json','["翠袖娇鬟舞石州。", "两行红粉一时羞。", "新声难逐管弦愁。", "白发主人年未老，清时贤相望偏优。", "一尊风月为公留。"]'),
('song-ci-745','浣溪沙','欧阳修','宋','宋词','song-ci','浣溪沙','[]','灯尽垂花月似霜。',48,'宋词/ci.song.0.json','["灯尽垂花月似霜。", "薄帘映月两交光。", "酒醺红粉自生香。", "双手舞馀拖翠袖，一声歌已釂金觞。", "休回娇眼断人肠。"]'),
('song-ci-746','浣溪沙','欧阳修','宋','宋词','song-ci','浣溪沙','[]','十载相逢酒一卮。',48,'宋词/ci.song.0.json','["十载相逢酒一卮。", "故人才见便开眉。", "老来游旧更同谁。", "浮世歌欢真易失，宦途离合信难期。", "尊前莫惜醉如泥。"]'),
('song-ci-747','御带花','欧阳修','宋','宋词','song-ci','御带花','[]','青春何处风光好，帝里偏爱元夕。',122,'宋词/ci.song.0.json','["青春何处风光好，帝里偏爱元夕。", "万重绘彩，构一屏峰岭，半空金碧。", "宝檠银釭，耀绛幕、龙虎腾掷。", "沙堤远，雕轮绣毂，争走五王宅。", "雍容熙熙昼，会乐府神姬，海洞仙客。", "拽香摇翠，称执手行歌，锦街天陌。", "月淡寒轻，渐向晓、漏声寂寂。", "当年少，狂心未已，不醉怎归得。"]'),
('song-ci-748','虞美人','欧阳修','宋','宋词','song-ci','虞美人','[]','炉香昼永龙烟白。',68,'宋词/ci.song.0.json','["炉香昼永龙烟白。", "风动金鸾额。", "画屏寒掩小山川。", "睡容初起枕痕圆。", "坠花钿。", "楼高不及烟霄半。", "望尽相思眼。", "艳阳刚爱挫愁人。", "故生芳草碧连云。", "怨王孙。"]'),
('song-ci-749','鹤冲天','欧阳修','宋','宋词','song-ci','鹤冲天','[]','梅谢粉，柳拖金。',57,'宋词/ci.song.0.json','["梅谢粉，柳拖金。", "香满旧园林。", "养花天气半晴阴。", "花好却愁深。", "花无数。", "愁无数。", "花好却愁春去。", "戴花持酒祝东风。", "千万莫匆匆。"]'),
('song-ci-750','夜行船','欧阳修','宋','宋词','song-ci','夜行船','[]','忆昔西都欢纵。',67,'宋词/ci.song.0.json','["忆昔西都欢纵。", "自别后、有谁能共。", "伊川山水洛川花，细寻思、旧游如梦。", "今日相逢情愈重。", "愁闻唱、画楼锺动。", "白发天涯逢此景，倒金尊、殢谁相送。"]'),
('song-ci-751','夜行船','欧阳修','宋','宋词','song-ci','夜行船','[]','满眼东风飞絮。',67,'宋词/ci.song.0.json','["满眼东风飞絮。", "催行色、短亭春暮。", "落花流水草连云，看看是、断肠南浦。", "檀板未终人去去。", "扁舟在、绿杨深处。", "手把金尊难为别，更那听、乱莺疏雨。"]'),
('song-ci-752','洛阳春・一落萦','欧阳修','宋','宋词','song-ci','洛阳春・一落萦','[]','红纱未晓黄鹂语。',58,'宋词/ci.song.0.json','["红纱未晓黄鹂语。", "蕙炉销兰炷。", "锦屏罗幕护春寒，昨夜三更雨。", "绣帘闲倚吹轻絮。", "敛眉山无绪。", "看花拭泪向归鸿，问来处、逢郎否。"]'),
('song-ci-753','雨中花・夜行船','欧阳修','宋','宋词','song-ci','雨中花・夜行船','[]','千古都门行路。',62,'宋词/ci.song.0.json','["千古都门行路。", "能使离歌声苦。", "送尽行人，花残春晚，又到君东去。", "醉藉落花吹暖絮。", "多少曲堤芳树。", "且携手留连，良辰美景，留作相思处。"]'),
('song-ci-754','越溪春','欧阳修','宋','宋词','song-ci','越溪春','[]','三月十三寒食日，春色遍天涯。',89,'宋词/ci.song.0.json','["三月十三寒食日，春色遍天涯。", "越溪阆苑繁华地，傍禁垣、珠翠烟霞。", "红粉墙头，秋千影里，临水人家。", "归来晚驻香车。", "银箭透窗纱。", "有时三点两点雨霁，朱门柳细风斜。", "沈麝不烧金鸭冷，笼月照梨花。"]'),
('song-ci-755','贺圣朝影・添声杨柳枝','欧阳修','宋','宋词','song-ci','贺圣朝影・添声杨柳枝','[]','白雪梨花红粉桃。',48,'宋词/ci.song.0.json','["白雪梨花红粉桃。", "露华高。", "垂杨慢舞绿丝绦。", "草如袍。", "风过小池轻浪起，似江皋。", "千金莫惜买香醪。", "且陶陶。"]'),
('song-ci-756','洞天春','欧阳修','宋','宋词','song-ci','洞天春','[]','莺啼绿树声早。',57,'宋词/ci.song.0.json','["莺啼绿树声早。", "槛外残红未扫。", "露点真珠遍芳草。", "正帘帏清晓。", "秋千宅院悄悄。", "又是清明过了。", "燕蝶轻狂，柳丝撩乱，春心多少。"]'),
('song-ci-757','忆汉月','欧阳修','宋','宋词','song-ci','忆汉月','[]','红艳几枝轻袅。',59,'宋词/ci.song.0.json','["红艳几枝轻袅。", "新被东风开了。", "倚烟啼露为谁娇，故惹蝶怜蜂恼。", "多情游赏处，留恋向、绿丛千绕。", "酒阑欢罢不成归，肠断月斜春老。"]'),
('song-ci-758','清平乐','欧阳修','宋','宋词','song-ci','清平乐','[]','小庭春老。',54,'宋词/ci.song.0.json','["小庭春老。", "碧砌红萱草。", "长忆小阑闲共绕。", "携手绿丛含笑。", "别来音信全乖。", "旧期前事堪猜。", "门掩日斜人静，落花愁点青苔。"]'),
('song-ci-759','凉州令・梁州令','欧阳修','宋','宋词','song-ci','凉州令・梁州令','[]','翠树芳条飐。',123,'宋词/ci.song.0.json','["翠树芳条飐。", "的的裙腰初染。", "佳人携手弄芳菲，绿阴红影，共展双纹簟。", "插花照影窥鸾鉴。", "只恐芳容减。", "不堪零落春晚，青苔雨后深红点。", "一去门闲掩。", "重来却寻朱槛。", "离离秋实弄轻霜，娇红脉脉，似见胭脂脸。", "人非事往眉空敛。", "谁把佳期赚。", "芳心只愿长依旧，春风更放明年艳。"]'),
('song-ci-760','南乡子','欧阳修','宋','宋词','song-ci','南乡子','[]','翠密红繁。',64,'宋词/ci.song.0.json','["翠密红繁。", "水国凉生未是寒。", "雨打荷花珠不定，轻翻。", "冷泼鸳鸯锦翅斑。", "尽日凭阑。", "弄蕊拈花仔细看。", "偷得袅蹄新铸样，无端。", "藏在红房艳粉间。"]'),
('song-ci-761','南乡子','欧阳修','宋','宋词','song-ci','南乡子','[]','雨后斜阳。',64,'宋词/ci.song.0.json','["雨后斜阳。", "细细风来细细香。", "风定波平花映水，休藏。", "照出轻盈半面妆。", "路隔秋江。", "莲子深深隐翠房。", "意在莲心无问处，难忘。", "泪裛红腮不记行。"]'),
('song-ci-762','鹊桥仙','欧阳修','宋','宋词','song-ci','鹊桥仙','[]','月波清霁，烟容明淡，灵汉旧期还至。',68,'宋词/ci.song.0.json','["月波清霁，烟容明淡，灵汉旧期还至。", "鹊迎桥路接天津，映夹岸、星榆点缀。", "云屏未卷，仙鸡催晓，肠断去年情味。", "多应天意不教长，恁恐把、欢娱容易。"]'),
('song-ci-763','圣无忧・乌夜啼','欧阳修','宋','宋词','song-ci','圣无忧・乌夜啼','[]','珠帘卷，暮云愁。',57,'宋词/ci.song.0.json','["珠帘卷，暮云愁。", "垂杨暗锁青楼。", "烟雨濛濛如画，轻风吹旋收。", "香断锦屏新别，人闲玉簟初秋。", "多少旧欢新恨，书杳杳、梦悠悠。"]'),
('song-ci-764','摸鱼儿','欧阳修','宋','宋词','song-ci','摸鱼儿','[]','卷绣帘、梧桐秋院落，一霎雨添新绿。',140,'宋词/ci.song.0.json','["卷绣帘、梧桐秋院落，一霎雨添新绿。", "对小池闲立残妆浅，向晚水纹如縠。", "凝远目。", "恨人去寂寂，凤枕孤难宿。", "倚阑不足。", "看燕拂风檐，蝶翻露草，两两长相逐。", "双眉促。", "可惜年华婉娩，西风初弄庭菊。", "况伊家年少，多情未已难拘束。", "那堪更趁凉景，追寻甚处垂杨曲。", "佳期过尽，但不说归来，多应忘了，云屏去时祝。"]'),
('song-ci-765','少年游','欧阳修','宋','宋词','song-ci','少年游','[]','去年秋晚此园中。',62,'宋词/ci.song.0.json','["去年秋晚此园中。", "携手玩芳丛。", "拈花嗅蕊，恼烟撩雾，拼醉倚西风。", "今年重对芳丛处，追往事、又成空。", "敲遍阑干，向人无语，惆怅满枝红。"]'),
('song-ci-766','少年游','欧阳修','宋','宋词','song-ci','少年游','[]','肉红圆样浅心黄。',62,'宋词/ci.song.0.json','["肉红圆样浅心黄。", "枝上巧如装。", "雨轻烟重，无憀天气，啼破晓来妆。", "寒轻贴体风头冷，忍抛弃、向秋光。", "不会深心，为谁惆怅，回面恨斜阳。"]'),
('song-ci-767','少年游','欧阳修','宋','宋词','song-ci','少年游','[]','玉壶冰莹兽炉灰。',60,'宋词/ci.song.0.json','["玉壶冰莹兽炉灰。", "人起绣帘开。", "春从一夜，六花开尽，不待剪刀催。", "洛阳城阙中天起，高下遍楼台。", "絮乱风轻，拂鞍沾袖，归路似章街。"]'),
('song-ci-768','鹧鸪天','欧阳修','宋','宋词','song-ci','鹧鸪天','[]','学画宫眉细细长。',64,'宋词/ci.song.0.json','["学画宫眉细细长。", "芙蓉出水斗新妆。", "只知一笑能倾国，不信相看有断肠。", "双黄鹄，两鸳鸯。", "迢迢云水恨难忘。", "早知今日长相忆，不及从初莫作双。"]'),
('song-ci-769','千秋岁','欧阳修','宋','宋词','song-ci','千秋岁','["\u957f\u6c5f"]','罗衫满袖，尽是忆伊泪。',87,'宋词/ci.song.0.json','["罗衫满袖，尽是忆伊泪。", "残妆粉，馀香被。", "手把金尊酒，未饮先如醉。", "但向道，厌厌成病皆因你。", "离思迢迢远，一似长江水。", "去不断，来无际。", "红笺著意写，不尽相思意。", "为个甚，相思只在心儿里。"]'),
('song-ci-770','千秋岁','欧阳修','宋','宋词','song-ci','千秋岁','[]','画堂人静，翡翠帘前月。',87,'宋词/ci.song.0.json','["画堂人静，翡翠帘前月。", "鸾帷凤枕虚铺设。", "风流难管束，一去音书歇。", "到而今，高梧冷落西风切。", "未语先垂泪，滴尽相思血。", "魂欲断，情难绝。", "都来些子事，更与何人说。", "为个甚，心头见底多离别。"]'),
('song-ci-771','醉蓬莱','欧阳修','宋','宋词','song-ci','醉蓬莱','[]','见羞容敛翠，嫩脸匀红，素腰袅娜。',121,'宋词/ci.song.0.json','["见羞容敛翠，嫩脸匀红，素腰袅娜。", "红药阑边，恼不教伊过。", "半掩娇羞，语声低颤，问道有人知麽。", "强整罗裙，偷回波眼，佯行佯坐。", "更问假如，事还成后，乱了云鬟，被娘猜破。", "我且归家，你而今休呵。", "更为娘行，有些针线，诮未曾收囉。", "却待更阑，庭花影下，重来则个。"]'),
('song-ci-772','于飞乐','欧阳修','宋','宋词','song-ci','于飞乐','[]','宝奁开，美鉴静，一掬清蟾。',93,'宋词/ci.song.0.json','["宝奁开，美鉴静，一掬清蟾。", "新妆脸，旋学花添。", "蜀红衫，双绣蝶、裙缕鹣鹣。", "寻思前事，小屏风、仍画江南。", "怎空教、草解宜男。", "柔桑密、又过春蚕。", "正阴晴天气，更暝色相兼。", "佳期消息，曲房西、碎月筛帘。"]'),
('song-ci-773','鼓笛慢・水龙吟','欧阳修','宋','宋词','song-ci','鼓笛慢・水龙吟','[]','缕金裙窣轻纱，透红莹玉真堪爱。',126,'宋词/ci.song.0.json','["缕金裙窣轻纱，透红莹玉真堪爱。", "多情更把，眼儿斜盼，眉儿敛黛。", "舞态歌阑，困偎香脸，酒红微带。", "便直饶、更有丹青妙手，应难写、天然态。", "长恐有时不见，每饶伊、百般娇呆。", "眼穿肠断，如今千种，思量无奈。", "花谢春归，梦回云散，欲寻难再。", "暗消魂，但觉鸳衾凤枕，有馀香在。"]'),
('song-ci-774','看花回','欧阳修','宋','宋词','song-ci','看花回','[]','晓色初透东窗，醉魂方觉。',123,'宋词/ci.song.0.json','["晓色初透东窗，醉魂方觉。", "恋恋绣衾半拥，动万感脉脉，春思无托。", "追想少年，何处青楼贪欢乐。", "当媚景，恨月愁花，算伊全妄凤帏约。", "空泪滴、真珠暗落。", "又被谁、连宵留著。", "不晓高天甚意，既付与风流，却恁情薄。", "细把身心自解，只与猛拼却。", "又及至、见来了，怎生教人恶。"]'),
('song-ci-775','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','几度兰房听禁漏。',70,'宋词/ci.song.0.json','["几度兰房听禁漏。", "臂上残妆，印得香盈袖。", "酒力融融香汗透。", "春娇入眼横波溜。", "不见些时眉已皱。", "水阔山遥，乍向分飞后。", "大抵有情须感旧。", "肌肤拼为伊销瘦。"]'),
('song-ci-776','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','宝琢珊瑚山样瘦。',70,'宋词/ci.song.0.json','["宝琢珊瑚山样瘦。", "缓髻轻拢，一朵云生袖。", "昨夜佳人初命偶。", "论情旋旋移相就。", "几叠鸳衾红浪皱。", "暗觉金钗，磔磔声相扣。", "一自楚台人梦后。", "凄凉暮雨沾裀绣。"]'),
('song-ci-777','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','一掬天和金粉腻。',70,'宋词/ci.song.0.json','["一掬天和金粉腻。", "莲子心中，自有深深意。", "意密莲深秋正媚。", "将花寄恨无人会。", "桥上少年桥下水。", "小棹归时，不语牵红袂。", "浪溅荷心圆又碎。", "无端欲伴相思泪。"]'),
('song-ci-778','蝶恋花','欧阳修','宋','宋词','song-ci','蝶恋花','[]','百种相思千种恨。',70,'宋词/ci.song.0.json','["百种相思千种恨。", "早是伤春，那更春醪困。", "薄幸辜人终不愤。", "何时枕畔分明问。", "懊恼风流心一寸。", "强醉偷眠，也即依前闷。", "此意为君君不信。", "泪珠滴尽愁难尽。"]'),
('song-ci-779','武陵春','欧阳修','宋','宋词','song-ci','武陵春','[]','宝幄华灯相见夜，妆脸小桃红。',56,'宋词/ci.song.0.json','["宝幄华灯相见夜，妆脸小桃红。", "斗帐香檀翡翠笼。", "携手恨匆匆。", "金泥双结同心带，留与记情浓。", "却望行云十二峰。", "肠断月斜锺。"]'),
('song-ci-780','梁州令','欧阳修','宋','宋词','song-ci','梁州令','[]','红杏墙头树。',125,'宋词/ci.song.0.json','["红杏墙头树。", "紫萼香心初吐。", "新年花发旧时枝，徘徊千绕，独共东风语。", "阳台一梦如云雨。", "为问今何处。", "离情别恨多少，条条结向垂杨缕。", "此事难分付。", "初心本谁先许。", "窃香解佩两沈沈，知他而今，记得当初否。", "谁教薄幸轻相误。", "不信道、相思苦。", "如今却恁空追悔，元来也会忆人去。"]'),
('song-ci-781','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','为爱莲房都一柄。',72,'宋词/ci.song.0.json','["为爱莲房都一柄。", "双苞双蕊双红影。", "雨势断来风色定。", "秋水静。", "仙郎彩女临鸾镜。", "妾有容华君不省。", "花无恩爱犹相并。", "花却有情人薄幸。", "心耿耿。", "因花又染相思病。"]'),
('song-ci-782','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','昨日采花花欲尽。',72,'宋词/ci.song.0.json','["昨日采花花欲尽。", "隔花闻道潮来近。", "风猎紫荷声又紧。", "低难奔。", "莲茎刺惹香腮损。", "一缕艳痕红隐隐。", "新霞点破秋蟾晕。", "罗袖挹残心不稳。", "羞人问。", "归来剩把胭脂衬。"]'),
('song-ci-783','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','一夜越溪秋水满。',72,'宋词/ci.song.0.json','["一夜越溪秋水满。", "荷花开过溪南岸。", "贪采嫩香星眼慢。", "疏回眄。", "郎船不觉来身畔。", "罢采金英收玉腕。", "回身急打船头转。", "荷叶又浓波又浅。", "无方便。", "教人只得抬娇面。"]'),
('song-ci-784','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','近日门前溪水涨。',72,'宋词/ci.song.0.json','["近日门前溪水涨。", "郎船几度偷相访。", "船小难开红斗帐。", "无计向。", "合欢影里空惆怅。", "愿妾身为红菡萏。", "年年生在秋江上。", "重愿郎为花底浪。", "无隔障。", "随风逐雨长来往。"]'),
('song-ci-785','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','妾解清歌并巧笑。',72,'宋词/ci.song.0.json','["妾解清歌并巧笑。", "郎多才俊兼年少。", "何事抛儿行远道。", "无音耗。", "江头又绿王孙草。", "昔日采花呈窈窕。", "玉容长笑花枝老。", "今日采花添懊恼。", "伤怀抱。", "玉容不及花枝好。"]'),
('song-ci-786','一斛珠','欧阳修','宋','宋词','song-ci','一斛珠','[]','今朝祖宴。',67,'宋词/ci.song.0.json','["今朝祖宴。", "可怜明夜孤灯馆。", "酒醒明月空床满。", "翠被重重，不似香肌暖。", "愁肠恰似沈香篆。", "千回万转萦还断。", "梦中若得相寻见。", "却愿春宵，一夜如年远。"]'),
('song-ci-787','惜芳时・思归乐','欧阳修','宋','宋词','song-ci','惜芳时・思归乐','[]','因倚兰台翠云亸。',68,'宋词/ci.song.0.json','["因倚兰台翠云亸。", "睡未足、双眉尚锁。", "潜身走向伊行坐。", "孜孜地、告他梳裹。", "发妆酒冷重温过。", "道要饮、除非伴我。", "丁香嚼碎偎人睡，犹记恨、夜来些个。"]'),
('song-ci-788','洞仙歌令・洞仙歌','欧阳修','宋','宋词','song-ci','洞仙歌令・洞仙歌','[]','楼前乱草，是离人方寸。',101,'宋词/ci.song.0.json','["楼前乱草，是离人方寸。", "倚遍阑干意无尽。", "罗巾掩，宿粉残眉、香未减，人与天涯共远。", "香闺知人否，长是厌厌，拟写相思寄归信。", "未写了，泪成行、早满香笺。", "相思字、一时滴损。", "便直饶、伊家总无情，也拼了一生，为伊成病。"]'),
('song-ci-789','洞仙歌令・洞仙歌','欧阳修','宋','宋词','song-ci','洞仙歌令・洞仙歌','[]','情知须病，奈自家先肯。',102,'宋词/ci.song.0.json','["情知须病，奈自家先肯。", "天甚教伊恁端正。", "忆年时、兰棹独倚春风，相怜处、月影花光相映。", "别来凭谁诉，空寄香笺，拟问前欢甚时更。", "后约与新期，易失难寻，空肠断、损风流心性。", "除只把、芳尊强开颜，奈酒到愁肠，醉了还醒。"]'),
('song-ci-790','鹊踏枝・蝶恋花','欧阳修','宋','宋词','song-ci','鹊踏枝・蝶恋花','[]','一曲尊前开画扇。',70,'宋词/ci.song.0.json','["一曲尊前开画扇。", "暂近还遥，不语仍低面。", "直至情多缘少见。", "千金不直双回眄。", "苦恨行云容易散。", "过尽佳期，争向年芳晚。", "百种寻思千万遍。", "愁肠不似情难断。"]'),
('song-ci-791','品令','欧阳修','宋','宋词','song-ci','品令','[]','渐素景。',62,'宋词/ci.song.0.json','["渐素景。", "金风劲。", "早是凄凉孤冷。", "那堪闻、蛩吟穿金井。", "唤愁绪难整。", "懊恼人人薄幸。", "负云期雨信。", "终日望伊来，无凭准。", "闷损我、也不定。"]'),
('song-ci-792','燕归梁','欧阳修','宋','宋词','song-ci','燕归梁','[]','风摆红藤卷绣帘。',61,'宋词/ci.song.0.json','["风摆红藤卷绣帘。", "宝鉴慵拈。", "日高梳洗几时忺。", "金盆水、弄纤纤。", "髻云谩亸残花淡，和娇媚、瘦岩岩。", "离情更被宿酲兼。", "空惹得、病厌厌。"]'),
('song-ci-793','燕归梁','欧阳修','宋','宋词','song-ci','燕归梁','[]','屏里金炉帐外灯。',62,'宋词/ci.song.0.json','["屏里金炉帐外灯。", "掩春睡腾腾。", "绿云堆枕乱鬅鬙。", "犹依约、那回曾。", "人生少有，相怜到老，宁不被天憎。", "而今前事总无凭。", "空赢得、瘦稜稜。"]'),
('song-ci-794','圣无忧・乌夜啼','欧阳修','宋','宋词','song-ci','圣无忧・乌夜啼','[]','相别重相遇。',55,'宋词/ci.song.0.json','["相别重相遇。", "恬如一梦须臾。", "尊前今日欢娱事，放盏旋成虚。", "莫惜斗量珠玉，随他雪白髭须。", "人间长久身难得，斗在不如吾。"]'),
('song-ci-795','锦香囊','欧阳修','宋','宋词','song-ci','锦香囊','[]','一寸相思无著处。',64,'宋词/ci.song.0.json','["一寸相思无著处。", "甚夜长难度。", "灯花前、几转寒更，桐叶上、数声秋雨。", "真个此心终难负。", "况少年情绪。", "已交共、春茧缠绵，终不学、钿筝移柱。"]'),
('song-ci-796','系裙腰','欧阳修','宋','宋词','song-ci','系裙腰','[]','水轩檐幕透薰风。',72,'宋词/ci.song.0.json','["水轩檐幕透薰风。", "银塘外、柳烟浓。", "方床遍展鱼鳞簟，碧纱笼。", "小墀面、对芙蓉。", "玉人共处霜鸳枕，和娇困、睡朦胧。", "起来意懒含羞态，汗香融。", "系裙腰，映酥胸。"]'),
('song-ci-797','阮郎归','欧阳修','宋','宋词','song-ci','阮郎归','[]','浓香搓粉细腰肢。',56,'宋词/ci.song.0.json','["浓香搓粉细腰肢。", "青螺深画眉。", "玉钗撩乱挽人衣。", "娇多长睡迟。", "绣帘角，月痕低。", "仙郎东路归。", "泪红满面湿胭脂。", "兰房怨别离。"]'),
('song-ci-798','阮郎归','欧阳修','宋','宋词','song-ci','阮郎归','[]','去年今日落花时。',56,'宋词/ci.song.0.json','["去年今日落花时。", "依前又见伊。", "淡匀双脸浅匀眉。", "青衫透玉肌。", "才会面，便相思。", "相思无尽期。", "这回相见好相知。", "相知已是迟。"]'),
('song-ci-799','阮郎归','欧阳修','宋','宋词','song-ci','阮郎归','[]','玉肌花脸柳腰肢。',56,'宋词/ci.song.0.json','["玉肌花脸柳腰肢。", "红妆浅黛眉。", "翠鬟斜亸语声低。", "娇羞云雨时。", "伊怜我，我怜伊。", "心儿与眼儿。", "绣屏深处说深期。", "幽情谁得知。"]'),
('song-ci-800','怨春郎','欧阳修','宋','宋词','song-ci','怨春郎','[]','为伊家，终日闷。',70,'宋词/ci.song.0.json','["为伊家，终日闷。", "受尽恓惶谁问。", "不知不觉上心头，悄一霎身心，顿也没处顿。", "恼愁肠，成寸寸。", "已恁莫把人萦损。", "奈每每人前道著伊，空把相思泪眼和衣搵。"]'),
('song-ci-801','滴滴金','欧阳修','宋','宋词','song-ci','滴滴金','[]','尊前一把横波溜。',54,'宋词/ci.song.0.json','["尊前一把横波溜。", "彼此心儿有。", "曲屏深幌解香罗，花灯微透。", "偎人欲语眉先皱。", "红玉困春酒。", "为问鸳衾这回后。", "几时重又。"]'),
('song-ci-802','卜算子','欧阳修','宋','宋词','song-ci','卜算子','[]','极得醉中眠，迤逦翻成病。',56,'宋词/ci.song.0.json','["极得醉中眠，迤逦翻成病。", "莫是前生负你来，今世里、教孤冷。", "言约全无定。", "是谁先薄幸。", "不惯孤眠惯成双，奈奴子、心肠硬。"]'),
('song-ci-803','感庭秋・撼庭秋','欧阳修','宋','宋词','song-ci','感庭秋・撼庭秋','[]','红笺封了还重拆。',58,'宋词/ci.song.0.json','["红笺封了还重拆。", "这添追忆。", "且教伊见我，别来翠减香销端的。", "渌波平远，暮山重叠，算难凭鳞翼。", "倚危楼极目，无情细草长天色。"]'),
('song-ci-804','满路花・促拍满路花','欧阳修','宋','宋词','song-ci','满路花・促拍满路花','[]','铜荷融烛泪，金兽啮扉环。',102,'宋词/ci.song.0.json','["铜荷融烛泪，金兽啮扉环。", "兰堂春夜疑，惜更残。", "落花风雨，向晓作轻寒。", "金龟朝早，香衾馀暖，殢娇由自慵眠。", "小鬟无事须来唤，呵破点唇檀。", "回身还、却背屏山。", "春禽飞下，帘外日三竿。", "起来云鬓乱，不妆红粉，下阶且上秋千。"]'),
('song-ci-805','好女儿令・好女儿','欧阳修','宋','宋词','song-ci','好女儿令・好女儿','[]','眼细眉长。',74,'宋词/ci.song.0.json','["眼细眉长。", "宫样梳妆。", "靸鞋儿走向花下立著。", "一身绣出，两同心字，浅浅金黄。", "早是肌肤轻渺，抱著了、暖仍香。", "姿姿媚媚端正好，怎教人别后，从头仔细，断得思量。"]'),
('song-ci-806','南乡子','欧阳修','宋','宋词','song-ci','南乡子','[]','浅浅画双眉。',66,'宋词/ci.song.0.json','["浅浅画双眉。", "取次梳妆也便宜。", "洒着胭脂红扑面，须知。", "更有何人得似伊。", "宝帐烛残时。", "好个温柔模样儿。", "月里仙郎清似玉，相期。", "些子精神更与谁。"]'),
('song-ci-807','南乡子','欧阳修','宋','宋词','song-ci','南乡子','[]','好个人人，深点唇儿淡抹腮。',64,'宋词/ci.song.0.json','["好个人人，深点唇儿淡抹腮。", "花下相逢、忙走怕人猜。", "遗下弓弓小绣鞋。", "剗袜重来。", "半亸乌云金凤钗。", "行笑行行连抱得，相挨。", "一向娇痴不下怀。"]'),
('song-ci-808','踏莎行','欧阳修','宋','宋词','song-ci','踏莎行','[]','碧藓回廊，绿杨深院。',68,'宋词/ci.song.0.json','["碧藓回廊，绿杨深院。", "偷期夜入帘犹卷。", "照人无奈月华明，潜身却恨花深浅。", "密约如沈，前欢未便。", "看看掷尽金壶箭。", "阑干敲遍不应人，分明帘下闻裁剪。"]'),
('song-ci-809','踏莎行','欧阳修','宋','宋词','song-ci','踏莎行','[]','云母屏低，流苏帐小。',68,'宋词/ci.song.0.json','["云母屏低，流苏帐小。", "矮床薄被秋将晓。", "乍凉天气未寒时，平明窗外闻啼鸟。", "困殢榴花，香添蕙草。", "佳期须及朱颜好。", "莫言多病为多情，此身甘向情中老。"]'),
('song-ci-810','诉衷情','欧阳修','宋','宋词','song-ci','诉衷情','[]','歌时眉黛舞时腰。',55,'宋词/ci.song.0.json','["歌时眉黛舞时腰。", "无处不娇饶。", "初剪菊、欲登高。", "天气怯鲛绡。", "紫丝障，绿杨桥。", "路迢迢。", "酒阑歌罢，一度归时，一度魂消。"]'),
('song-ci-811','诉衷情','欧阳修','宋','宋词','song-ci','诉衷情','[]','离怀酒病两忡忡。',54,'宋词/ci.song.0.json','["离怀酒病两忡忡。", "倚枕梦无踪。", "可怜有人今夜，胆小怯房空。", "杨柳绿，杏梢红。", "负春风。", "迢迢别恨，脉脉归心，付与征鸿。"]'),
('song-ci-812','恨春迟','欧阳修','宋','宋词','song-ci','恨春迟','[]','欲借江梅荐饮。',70,'宋词/ci.song.0.json','["欲借江梅荐饮。", "望陇驿、音息沈沈。", "住在柳州东，彼此相思，梦回云去难寻。", "归燕来时花期浸。", "淡月坠、将晓还阴。", "争奈多情易感，风信无凭，如何消遣初心。"]'),
('song-ci-813','盐角儿','欧阳修','宋','宋词','song-ci','盐角儿','[]','增之太长，减之太短，出群风格。',63,'宋词/ci.song.0.json','["增之太长，减之太短，出群风格。", "施朱太赤，施粉太白，倾城颜色。", "慧多多，娇的的。", "天付与、教谁怜惜。", "除非我、偎著抱著，更有何人消得。"]'),
('song-ci-814','盐角儿','欧阳修','宋','宋词','song-ci','盐角儿','[]','人生最苦，少年不得，鸳帏相守。',64,'宋词/ci.song.0.json','["人生最苦，少年不得，鸳帏相守。", "西风时节，那堪话别，双蛾频皱。", "暗消魂，重回首。", "奈心儿里、彼此皆有。", "后时我、两个相见，管取一双清瘦。"]'),
('song-ci-815','忆秦娥','欧阳修','宋','宋词','song-ci','忆秦娥','[]','十五六，脱罗裳，长恁黛眉蹙。',58,'宋词/ci.song.0.json','["十五六，脱罗裳，长恁黛眉蹙。", "红玉暖，入人怀，春困熟。", "展香裀，帐前明画烛。", "眼波长，斜浸鬓云绿。", "看不足。", "苦残宵、更漏促。"]'),
('song-ci-816','少年游','欧阳修','宋','宋词','song-ci','少年游','[]','绿云双亸插金翘。',58,'宋词/ci.song.0.json','["绿云双亸插金翘。", "年纪正妖饶。", "汉妃束素，小蛮垂柳，都占洛城腰。", "锦屏春过衣初减，香雪暖凝消。", "试问当筵眼波恨，滴滴为谁娇。"]'),
('song-ci-817','踏莎行慢','欧阳修','宋','宋词','song-ci','踏莎行慢','[]','独自上孤舟。',103,'宋词/ci.song.0.json','["独自上孤舟。", "倚危樯目断。", "难成暮雨，更朝云散。", "凉劲残叶乱。", "新月照、澄波浅。", "今夜里，厌厌离绪难销遣。", "强来就枕，灯残漏永，合相思眼。", "分明梦见如花面。", "依前是、旧庭院。", "新月照，罗幕挂，珠帘卷。", "渐向晓，脉然睡觉如天远。"]'),
('song-ci-818','蕙香囊・鹊桥仙','欧阳修','宋','宋词','song-ci','蕙香囊・鹊桥仙','[]','身作琵琶，调全宫羽，佳人自然用意。',68,'宋词/ci.song.0.json','["身作琵琶，调全宫羽，佳人自然用意。", "宝檀槽在雪胸前，倚香脐、横枕琼臂。", "组带金钩，背垂红绶，纤指转弦韵细。", "愿伊只恁拨梁州，且多时、得在怀里。"]'),
('song-ci-819','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','艳冶风情天与措。',64,'宋词/ci.song.0.json','["艳冶风情天与措。", "清瘦肌肤冰雪妒。", "百年心事一宵同，愁听鸡声窗外度。", "信阻青禽云雨暮。", "海月空惊人两处。", "强将离恨倚江楼，江水不能流恨去。"]'),
('song-ci-820','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','半辐霜绡亲手剪。',64,'宋词/ci.song.0.json','["半辐霜绡亲手剪。", "香染青蛾和泪卷。", "画时横接媚霞长，印处双沾愁黛浅。", "当时付我情何限。", "欲使妆痕长在眼。", "一回忆著一拈看，便似花前重见面。"]'),
('song-ci-821','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','红楼昨夜相将饮。',64,'宋词/ci.song.0.json','["红楼昨夜相将饮。", "月近珠帘花近枕。", "银缸照客酒方酣，玉漏催人街已禁。", "晚潮去棹浮清浸。", "古岸平芜萧索甚。", "大都薄宦足离愁，不放双鸳长恁恁。"]'),
('song-ci-822','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','金雀双鬟年纪小。',64,'宋词/ci.song.0.json','["金雀双鬟年纪小。", "学画蛾眉红淡扫。", "尽人言语尽人怜，不解此情惟解笑。", "稳着舞衣行动俏。", "走向绮筵呈曲妙。", "刘郎大有惜花心，只恨寻花来较早。"]'),
('song-ci-823','玉楼春','欧阳修','宋','宋词','song-ci','玉楼春','[]','夜来枕上争闲事。',64,'宋词/ci.song.0.json','["夜来枕上争闲事。", "推倒屏山褰绣被。", "尽人求守不应人，走向碧纱窗下睡。", "直到起来由自殢。", "向道夜来真个醉。", "大家恶发大家休，毕竟到头谁不是。"]'),
('song-ci-824','定风波','欧阳修','宋','宋词','song-ci','定风波','[]','把酒花前欲问伊。',73,'宋词/ci.song.0.json','["把酒花前欲问伊。", "问伊还记那回时。", "黯淡梨花笼月影。", "人静。", "画堂东畔药阑西。", "及至如今都不认。", "难问。", "有情谁道不相思。", "何事碧窗春睡觉。", "偷照。", "粉痕匀却湿胭脂。"]'),
('song-ci-825','减字木兰花','欧阳修','宋','宋词','song-ci','减字木兰花','[]','去年残腊。',52,'宋词/ci.song.0.json','["去年残腊。", "曾折梅花相对插。", "人面而今。", "空有花开无处寻。", "天天不远。", "把酒拈花重发愿。", "愿得和伊。", "偎雪眠香似旧时。"]'),
('song-ci-826','减字木兰花','欧阳修','宋','宋词','song-ci','减字木兰花','[]','年来方寸。',52,'宋词/ci.song.0.json','["年来方寸。", "十日幽欢千日恨。", "未会此情。", "白尽人头可得平。", "区区堪比。", "水趁浮萍风趁水。", "试望瑶京。", "芳草随人上古城。"]'),
('song-ci-827','迎春乐','欧阳修','宋','宋词','song-ci','迎春乐','[]','薄纱衫子裙腰匝。',64,'宋词/ci.song.0.json','["薄纱衫子裙腰匝。", "步轻轻、小罗靸。", "人前爱把眼儿札。", "香汗透、胭脂蜡。", "良夜永、幽期欢则洽。", "约重会、玉纤频插。", "执手临归，犹且更待留时霎。"]'),
('song-ci-828','一落索','欧阳修','宋','宋词','song-ci','一落索','[]','小桃风撼香红碎。',59,'宋词/ci.song.0.json','["小桃风撼香红碎。", "满帘笼花气。", "看花何事却成愁，悄不会、春风意。", "窗在梧桐叶底。", "更黄昏雨细。", "枕前前事上心来，独自个、怎生睡。"]'),
('song-ci-829','夜行船','欧阳修','宋','宋词','song-ci','夜行船','[]','闲把鸳衾横枕。',67,'宋词/ci.song.0.json','["闲把鸳衾横枕。", "损眉尖、泪痕红沁。", "花时良夜不归来，忍频听、漏移清禁。", "一饷无言都未寝。", "忆当初、是谁先恁。", "及至如今，教人成病，风流万般徒甚。"]'),
('song-ci-830','夜行船','欧阳修','宋','宋词','song-ci','夜行船','[]','轻捧香腮低枕。',67,'宋词/ci.song.0.json','["轻捧香腮低枕。", "眼波媚、向人相浸。", "佯娇佯醉索如今，这风情、怎教人禁。", "却与和衣推未寝。", "低声地、告人休恁。", "月夕花朝，不成虚过，芳年嫁君徒甚。"]'),
('song-ci-831','望江南・忆江南','欧阳修','宋','宋词','song-ci','望江南・忆江南','[]','江南柳，花柳两相柔。',64,'宋词/ci.song.0.json','["江南柳，花柳两相柔。", "花片落时粘酒盏，柳条低处拂人头。", "各自是风流。", "江南月，如镜复如钩。", "似镜不侵红粉面，似钩不挂画帘头。", "长是照离愁。"]'),
('song-ci-832','望江南・忆江南','欧阳修','宋','宋词','song-ci','望江南・忆江南','[]','江南柳，叶小未成阴。',64,'宋词/ci.song.0.json','["江南柳，叶小未成阴。", "人为丝轻那忍折，莺嫌枝嫩不胜吟。", "留著待春深。", "十四五，闲抱琵琶寻。", "阶上簸钱阶下走，恁时相见早留心。", "何况到如今。"]'),
('song-ci-833','宴瑶池・越江吟','欧阳修','宋','宋词','song-ci','宴瑶池・越江吟','[]','恋眼哝心终未改。',66,'宋词/ci.song.0.json','["恋眼哝心终未改。", "向意间长在。", "都缘为、颜色殊常，见馀花、尽无心爱。", "都为是风流㬠。", "至他人、强来厮壤。", "从今后、若得相逢，绣帏里、痛惜娇态。"]'),
('song-ci-834','解仙佩','欧阳修','宋','宋词','song-ci','解仙佩','[]','有个人人牵系。',64,'宋词/ci.song.0.json','["有个人人牵系。", "泪成痕、滴尽罗衣。", "问海约山盟何时。", "镇教人、目断魂飞。", "梦里似偎人睡。", "肌肤依旧骨香腻。", "觉来但堆鸳被。", "想忡忡、那里争知。"]'),
('song-ci-835','渔家傲','欧阳修','宋','宋词','song-ci','渔家傲','[]','战胜归来飞捷奏。',20,'宋词/ci.song.0.json','["战胜归来飞捷奏。", "倾贺酒。", "玉阶遥献南山寿。"]'),
('song-ci-836','少年游','欧阳修','宋','宋词','song-ci','少年游','[]','阑干十二独凭春。',62,'宋词/ci.song.0.json','["阑干十二独凭春。", "晴碧远连云。", "千里万里，二月三月，行色苦愁人。", "谢家池上，江淹浦畔，吟魄与离魂。", "那堪疏雨滴黄昏。", "更特地、忆王孙。"]'),
('song-ci-837','桃源忆故人','欧阳修','宋','宋词','song-ci','桃源忆故人','[]','碧纱影弄东风晓。',56,'宋词/ci.song.0.json','["碧纱影弄东风晓。", "一夜海棠开了。", "枝上数声啼鸟。", "妆点愁多少。", "妒云恨雨腰支袅。", "眉黛不忺重扫。", "薄幸不来春老。", "羞带宜男草。"]'),
('song-ci-838','阮郎归','欧阳修','宋','宋词','song-ci','阮郎归','[]','雪霜林际见依稀。',56,'宋词/ci.song.0.json','["雪霜林际见依稀。", "清香已暗期。", "前村已遍倚南枝。", "群花犹未知。", "情似旧，赏休迟。", "看看陇上吹。", "便从今日赏芳菲。", "韶华取次归。"]'),
('song-ci-839','南乡子','荣','宋','宋词','song-ci','南乡子','[]','江上野梅芳。',66,'宋词/ci.song.0.json','["江上野梅芳。", "粉色盈盈照路傍。", "闲折一枝和雪嗅，思量。", "似个人人玉体香。", "特地起愁肠。", "此恨谁人与寄将。", "山馆寂寥天欲暮，凄凉。", "人转迢迢路转长。"]'),
('song-ci-840','定风波','王琪','宋','宋词','song-ci','定风波','[]','把酒花前欲问天。',73,'宋词/ci.song.0.json','["把酒花前欲问天。", "春来秋去苦茫然。", "风雨满枝花满地。", "何事。", "却教纤草占流年。", "试把钿筝重促柱。", "无绪。", "酒阑清泪滴朱弦。", "赖有玉人相顾好。", "轻笑。", "却疑春色在婵娟。"]'),
('song-ci-841','祝英台・祝英台近','王琪','宋','宋词','song-ci','祝英台・祝英台近','[]','可堪妒柳羞花，下床都懒，便瘦也教春知道。',20,'宋词/ci.song.0.json','["可堪妒柳羞花，下床都懒，便瘦也教春知道。"]'),
('song-ci-842','望江南・忆江南','王琪','宋','宋词','song-ci','望江南・忆江南','[]','江南柳，烟穗拂人轻。',64,'宋词/ci.song.0.json','["江南柳，烟穗拂人轻。", "愁黛空长描不似，舞腰虽瘦学难成。", "天意与风情。", "攀折处，离恨几时平。", "已纵柔条萦客棹，更飞狂絮扑旗亭。", "三月乱莺声。"]'),
('song-ci-843','望江南・忆江南','王琪','宋','宋词','song-ci','望江南・忆江南','[]','江南酒，何处味偏浓。',64,'宋词/ci.song.0.json','["江南酒，何处味偏浓。", "醉卧春风深巷里，晓寻香旆小桥东。", "竹叶满金锺。", "檀板醉，人面粉生红。", "青杏黄梅朱阁上，鲥鱼苦笋玉盘中。", "酩酊任愁攻。"]'),
('song-ci-844','望江南・忆江南','王琪','宋','宋词','song-ci','望江南・忆江南','[]','江南燕，轻扬绣帘风。',64,'宋词/ci.song.0.json','["江南燕，轻扬绣帘风。", "二月池塘新社过，六朝宫殿旧巢空。", "颉颃恣西东。", "王谢宅，曾入绮堂中。", "烟径掠花飞远远，晓窗惊梦语匆匆。", "偏占杏园红。"]'),
('song-ci-845','望江南・忆江南','王琪','宋','宋词','song-ci','望江南・忆江南','[]','江南竹，清润绝纤埃。',64,'宋词/ci.song.0.json','["江南竹，清润绝纤埃。", "深径欲留双凤宿，后庭偏映小桃开。", "风月影徘徊。", "寒玉瘦，霜霰信相催。", "粉泪空流妆点在，羊车曾傍翠枝来。", "龙笛莫轻裁。"]'),
('song-ci-846','望江南・忆江南','王琪','宋','宋词','song-ci','望江南・忆江南','[]','江南草，如种复如描。',64,'宋词/ci.song.0.json','["江南草，如种复如描。", "深映落花莺舌乱，绿迷南浦客魂消。", "日日斗青袍。", "风欲转，柔态不胜娇。", "远翠天涯经夜雨，冷痕沙上带昏潮。", "谁梦与兰苕。"]'),
('song-ci-847','望江南・忆江南','王琪','宋','宋词','song-ci','望江南・忆江南','[]','江南雨，风送满长川。',64,'宋词/ci.song.0.json','["江南雨，风送满长川。", "碧瓦烟昏沈柳岸，红绡香润入梅天。", "飘洒正潇然。", "朝与暮，长在楚峰前。", "寒夜愁敧金带枕，暮江深闭木兰船。", "烟浪远相连。"]'),
('song-ci-848','望江南・忆江南','王琪','宋','宋词','song-ci','望江南・忆江南','["\u6d1e\u5ead\u6e56"]','江南水，江路转平沙。',64,'宋词/ci.song.0.json','["江南水，江路转平沙。", "雨霁高烟收素练，风晴细浪吐寒花。", "迢递送星槎。", "名利客，飘泊未还家。", "西塞山前渔唱远，洞庭波上雁行斜。", "征棹宿天涯。"]'),
('song-ci-849','望江南・忆江南','王琪','宋','宋词','song-ci','望江南・忆江南','[]','江南岸，云树半晴阴。',64,'宋词/ci.song.0.json','["江南岸，云树半晴阴。", "帆去帆来天亦老，潮生潮落日还沈。", "南北别离心。", "兴废事，千古一沾襟。", "山下孤烟渔市晓，柳边疏雨酒家深。", "行客莫登临。"]'),
('song-ci-850','望江南・忆江南','王琪','宋','宋词','song-ci','望江南・忆江南','[]','江南月，清夜满西楼。',64,'宋词/ci.song.0.json','["江南月，清夜满西楼。", "云落开时冰吐鉴，浪花深处玉沈钩。", "圆缺几时休。", "星汉迥，风露入新秋。", "丹桂不知摇落恨，素娥应信别离愁。", "天上共悠悠。"]'),
('song-ci-851','望江南・忆江南','王琪','宋','宋词','song-ci','望江南・忆江南','[]','江南雪，轻素剪云端。',64,'宋词/ci.song.0.json','["江南雪，轻素剪云端。", "琼树忽惊春意早，梅花偏觉晓香寒。", "冷影褫清欢。", "蟾玉迥，清夜好重看。", "谢女联诗衾翠幕，子猷乘兴泛平澜。", "空惜舞英残。"]'),
('song-ci-852','失调名','王琪','宋','宋词','song-ci','失调名','[]','金斗熨秋江。',6,'宋词/ci.song.0.json','["金斗熨秋江。"]'),
('song-ci-853','一络索・一落萦','陈凤仪','宋','宋词','song-ci','一络索・一落萦','[]','蜀江春色浓如雾。',58,'宋词/ci.song.0.json','["蜀江春色浓如雾。", "拥双旌归去。", "海棠也似别君难，一点点、啼红雨。", "此去马蹄何处。", "沙堤新路。", "禁林赐宴赏花时，还忆著、西楼否。"]'),
('song-ci-854','水调歌头','苏舜钦','宋','宋词','song-ci','水调歌头','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','潇洒太湖岸，淡伫洞庭山。',114,'宋词/ci.song.0.json','["潇洒太湖岸，淡伫洞庭山。", "鱼龙隐处，烟雾深锁渺弥间。", "方念陶朱张翰，忽有扁舟急桨，撇浪载鲈还。", "落日暴风雨，归路绕汀湾。", "丈夫志，当景盛，耻疏闲。", "壮年何事憔悴，华发改朱颜。", "拟借寒潭垂钓，又恐鸥鸟相猜，不肯傍青纶。", "刺棹穿芦荻，无语看波澜。"]'),
('song-ci-855','永遇乐','解','宋','宋词','song-ci','永遇乐','[]','风暖莺娇，露浓花重，天气和煦。',128,'宋词/ci.song.0.json','["风暖莺娇，露浓花重，天气和煦。", "院落烟收，垂杨舞困，无奈堆金缕。", "谁家巧纵，青楼弦管，惹起梦云情绪。", "忆当时、纹衾粲枕，未尝暂孤鸳侣。", "芳菲易老，故人难聚。", "到此翻成轻误。", "阆苑仙遥，蛮笺纵写、何计传深诉。", "青山绿水，古今长在，惟有旧欢何处。", "空赢得、斜阳暮草，淡烟细雨。"]'),
('song-ci-856','阳台梦','解','宋','宋词','song-ci','阳台梦','[]','仙姿本寓。',69,'宋词/ci.song.0.json','["仙姿本寓。", "十二峰前住。", "千里行云行雨。", "偶因鹤驭过巫阳。", "邂逅他、楚襄王。", "无端宋玉夸才赋。", "诬诞人心素。", "至今狂客到阳台。", "也有痴心，望妾入、梦中来。"]'),
('song-ci-857','点绛唇','韩琦','宋','宋词','song-ci','点绛唇','[]','病起恹恹，画堂花谢添憔悴。',50,'宋词/ci.song.0.json','["病起恹恹，画堂花谢添憔悴。", "乱红飘砌。", "滴尽胭脂泪。", "惆怅前春，谁向花前醉。", "愁无际。", "武陵回睇。", "人远波空翠。"]'),
('song-ci-858','维扬好','韩琦','宋','宋词','song-ci','维扬好','[]','二十四桥千步柳，春风十里上珠帘。',16,'宋词/ci.song.0.json','["二十四桥千步柳，春风十里上珠帘。"]'),
('song-ci-859','安阳好・忆江南','韩琦','宋','宋词','song-ci','安阳好・忆江南','[]','安阳好，形势魏西州。',64,'宋词/ci.song.0.json','["安阳好，形势魏西州。", "曼衍山川环故国，升平歌吹沸高楼。", "和气镇飞浮。", "笼画陌，乔木几春秋。", "花外轩窗排远岫，竹间门巷带长流。", "风物更清幽。"]'),
('song-ci-860','安阳好・忆江南','韩琦','宋','宋词','song-ci','安阳好・忆江南','[]','安阳好，戟户使君宫。',64,'宋词/ci.song.0.json','["安阳好，戟户使君宫。", "白昼锦衣清宴处，铁楹丹榭画图中。", "壁记旧三公。", "棠讼悄，池馆北园通。", "夏夜泉声来枕簟，春来花气透帘栊。", "行乐兴何穷。"]'),
('song-ci-861','望江南・忆江南','韩琦','宋','宋词','song-ci','望江南・忆江南','[]','维杨好，灵宇有琼花。',64,'宋词/ci.song.0.json','["维杨好，灵宇有琼花。", "千点真珠擎素蕊，一环名玉破香葩。", "芳艳信难加。", "如雪貌，绰约最堪夸。", "疑是八仙乘皓月，羽衣摇曳上云车。", "来会列仙家。"]'),
('song-ci-862','失调名','沈唐','宋','宋词','song-ci','失调名','[]','不是这，下辈无礼，都缘是我，自家遭逢。',19,'宋词/ci.song.0.json','["不是这，下辈无礼，都缘是我，自家遭逢。"]'),
('song-ci-863','雨中花・夜行船','沈唐','宋','宋词','song-ci','雨中花・夜行船','[]','有谁念我、如今霜鬓，远赴边堠。',31,'宋词/ci.song.0.json','["有谁念我、如今霜鬓，远赴边堠。", "……身在碧云西畔，情随陇水东流。"]'),
('song-ci-864','霜叶飞','沈唐','宋','宋词','song-ci','霜叶飞','["\u6d1e\u5ead\u6e56"]','霜林凋晚，危楼迥，登临无限秋思。',134,'宋词/ci.song.0.json','["霜林凋晚，危楼迥，登临无限秋思。", "望中闲想，洞庭波面，乱红初坠。", "更萧索、风吹渭水。", "长安飞舞千门里。", "变景摧芳榭，唯有兰衰暮丛，菊残馀蕊。", "回念花满华堂，美人一去，镇掩香闺经岁。", "又观珠露，碎点苍苔，败梧飘砌。", "谩赢得、相思泪眼，东君早作归来计。", "便莫惜丹青手，重与芳菲，万红千翠。"]'),
('song-ci-865','念奴娇','沈唐','宋','宋词','song-ci','念奴娇','[]','杏花过雨，渐残红零落，胭脂颜色。',121,'宋词/ci.song.0.json','["杏花过雨，渐残红零落，胭脂颜色。", "流水飘香人渐远，难托春心脉脉。", "恨别王孙，墙阴目断，手把青梅摘。", "金鞍何处，绿杨依旧南陌。", "消散云雨须臾，多情因甚，有轻离轻拆。", "燕语千般，争解说、些子伊家消息。", "厚约深盟，除非重见，见了方端的。", "而今无奈，寸肠千恨堆积。"]'),
('song-ci-866','望海潮','沈唐','宋','宋词','song-ci','望海潮','[]','山光凝翠，川容如画，名都自古并州。',129,'宋词/ci.song.0.json','["山光凝翠，川容如画，名都自古并州。", "箫鼓沸天，弓刀似水，连营十万貔貅。", "金骑走长楸。", "少年人一一，锦带吴钩。", "路入榆关，雁飞汾水正宜秋。", "追思昔日风流。", "有儒将醉吟，才子狂游。", "松偃旧亭，城高故国，空馀舞榭歌楼。", "方面倚贤候。", "便恐为霖雨，归去难留。", "好向西溪，恣携弦管宴兰舟。"]'),
('song-ci-867','望南云慢','沈唐','宋','宋词','song-ci','望南云慢','[]','木叶轻飞，乍雨歇亭皋，帘卷秋光。',129,'宋词/ci.song.0.json','["木叶轻飞，乍雨歇亭皋，帘卷秋光。", "栏隈砌角，绽拒霜几处，蓓深浅红芳。", "应恨开时晚，伴翠菊、风前并香。", "晓来寒露，嫩脸低凝，似带啼妆。", "堪伤。", "记得佳人，当时怨别，盈腮泪粉行行。", "而今最苦，奈千里身心，两处凄凉。", "感物成消黯，念旧欢、空劳寸肠。", "月斜残漏，梦断孤帏，一枕思量。"]'),
('song-ci-868','鹤冲天','杜安世','宋','宋词','song-ci','鹤冲天','[]','清明天气。',106,'宋词/ci.song.0.json','["清明天气。", "永日愁如醉。", "台榭绿阴浓，薰风细。", "燕子巢方就，盆池小，新荷蔽。", "恰是逍遥际。", "单夹衣裳，半栊软玉肌体。", "石榴美艳，一撮红绡比。", "窗外数修篁，寒相倚。", "有个关心处，难相见、空凝睇。", "行坐深闺里。", "懒更妆梳，自知新来憔悴。"]'),
('song-ci-869','两同心','杜安世','宋','宋词','song-ci','两同心','[]','巍巍剑外，寒霜覆林枝。',90,'宋词/ci.song.0.json','["巍巍剑外，寒霜覆林枝。", "望衰柳、尚色依依。", "暮天静、雁阵高飞。", "入碧云际。", "江山秋色，遣客心悲。", "蜀道巇崄行迟。", "瞻京都迢递。", "听巴峡、数声猿啼。", "惟独个、未有归计。", "谩空怅望，每每无言，独对斜晖。"]'),
('song-ci-870','玉阑干','杜安世','宋','宋词','song-ci','玉阑干','[]','珠帘怕卷春残景。',67,'宋词/ci.song.0.json','["珠帘怕卷春残景。", "小雨牡丹零欲尽。", "庭轩悄悄燕高空，风飘絮、绿苔侵径。", "欲将幽恨传愁信。", "想后期、无个凭定。", "几回独睡不思量，还悠悠、梦里寻趁。"]'),
('song-ci-871','浣溪沙','杜安世','宋','宋词','song-ci','浣溪沙','[]','模样偏宜掌上怜。',48,'宋词/ci.song.0.json','["模样偏宜掌上怜。", "云如双鬓玉如颜。", "身材轻妙眼儿单。", "幽会未成双怅望，深情欲诉两艰难。", "空教魂梦到巫山。"]'),
('song-ci-872','浣溪沙','杜安世','宋','宋词','song-ci','浣溪沙','[]','横画功夫想未全。',48,'宋词/ci.song.0.json','["横画功夫想未全。", "双双文彩羽仪鲜。", "和鸣偕老是天然。", "暮雨并深流细草，暖风交颈傍清涟。", "羡他真个好因缘。"]'),
('song-ci-873','惜春令','杜安世','宋','宋词','song-ci','惜春令','[]','春梦无凭犹懒起。',60,'宋词/ci.song.0.json','["春梦无凭犹懒起。", "银烛尽、画帘低垂。", "小庭杨柳黄金翠，桃脸两三枝。", "妆阁慵梳洗。", "闷无绪、玉箫抛掷。", "絮飘纷纷人疏远，空对日迟迟。"]'),
('song-ci-874','惜春令','杜安世','宋','宋词','song-ci','惜春令','[]','今夕重阳秋意深。',60,'宋词/ci.song.0.json','["今夕重阳秋意深。", "篱边散、嫩菊开金。", "万里霜天林叶坠，萧索动离心。", "臂上茱萸新。", "似旧年、堪赏光阴。", "百盏香醑且酬身。", "牛山会难寻。"]'),
('song-ci-875','踏莎行','杜安世','宋','宋词','song-ci','踏莎行','[]','雨霁风光，春分天气。',68,'宋词/ci.song.0.json','["雨霁风光，春分天气。", "千花百草争明媚。", "画梁新燕一双双，玉笼鹦鹉爱孤睡。", "薜荔依墙，莓苔满地。", "青楼几处歌声丽。", "蓦然旧事上心头，无言敛皱眉山翠。"]'),
('song-ci-876','踏莎行','杜安世','宋','宋词','song-ci','踏莎行','[]','夜雨朝晴，东风微冷。',68,'宋词/ci.song.0.json','["夜雨朝晴，东风微冷。", "雕梁燕子闲相并。", "后园次第数芳菲，千香百艳年年定。", "步险楼高，人赊途迥。", "烟芜冉冉斜阳暝。", "红笺写尽寄无因，想伊不信人成病。"]'),
('song-ci-877','踏莎行','杜安世','宋','宋词','song-ci','踏莎行','[]','嫩柳成阴，残花双舞。',68,'宋词/ci.song.0.json','["嫩柳成阴，残花双舞。", "尘消院落新经雨。", "洞房深掩日长天，珠帘时有沈烟度。", "夜梦凄凉，晨妆薄注。", "香肌瘦尽宽金缕。", "到头终是恶因缘，当初只被多情误。"]'),
('song-ci-878','踏莎行','杜安世','宋','宋词','song-ci','踏莎行','[]','闲院秋千，又还拆了。',68,'宋词/ci.song.0.json','["闲院秋千，又还拆了。", "绿苔遍地青春老。", "画楼日晚燕归巢，红稀翠盛梅初小。", "窈窕身轻，怎禁烦恼。", "罗衣渐减怯风峭。", "韶华好景想多才，厌厌只为书音少。"]'),
('song-ci-879','端正好','杜安世','宋','宋词','song-ci','端正好','[]','栏菊愁烟沾秋露。',66,'宋词/ci.song.0.json','["栏菊愁烟沾秋露。", "天微冷、双燕辞去。", "月明空照别离苦。", "透素光、穿朱户。", "夜来西风雕寒树。", "凭阑望、迢遥长路。", "花笺写就此情绪。", "特寄传、知何处。"]'),
('song-ci-880','端正好','杜安世','宋','宋词','song-ci','端正好','[]','每逢春来长如病。',66,'宋词/ci.song.0.json','["每逢春来长如病。", "玉容瘦、薄妆相称。", "双欢未经成孤令。", "奈厚约、全无定。", "众禽啾唧声愁听。", "相思事、多少春恨。", "孤眠帐外银缸耿。", "透一点、炉烟暝。"]'),
('song-ci-881','端正好','杜安世','宋','宋词','song-ci','端正好','[]','露落风高桐叶坠。',66,'宋词/ci.song.0.json','["露落风高桐叶坠。", "小庭院、秋凉佳气。", "兰堂聚饮华筵启。", "罢令曲、呈珠缀。", "晚天行云凝香袂。", "新声内、分明心意。", "玉炉初喷檀烟起。", "敛愁在、双蛾翠。"]'),
('song-ci-882','端正好','杜安世','宋','宋词','song-ci','端正好','[]','野禽林栖啾唧语。',66,'宋词/ci.song.0.json','["野禽林栖啾唧语。", "闲庭院、残阳将暮。", "兰堂静悄珠帘窣。", "想玉人、归何处。", "喜鹊几回薄无据。", "愁都在、双眉头聚。", "凄凉方感孤鸳侣。", "对夜永、成愁绪。"]'),
('song-ci-883','菩萨蛮','杜安世','宋','宋词','song-ci','菩萨蛮','[]','游丝欲堕还重上。',52,'宋词/ci.song.0.json','["游丝欲堕还重上。", "春残日永人相望。", "花共燕争飞。", "青梅细雨枝。", "离愁终未解。", "忘了依前在。", "拟待不寻思。", "刚眠梦见伊。"]'),
('song-ci-884','菩萨蛮','杜安世','宋','宋词','song-ci','菩萨蛮','["\u957f\u6c5f"]','锦机织了相思字。',52,'宋词/ci.song.0.json','["锦机织了相思字。", "天涯路远无由寄。", "寒雁只衔芦。", "何曾解寄书。", "缄封和血泪。", "目断西江水。", "拟欲托双鱼。", "问君情有无。"]'),
('song-ci-885','丑奴儿・采桑子','杜安世','宋','宋词','song-ci','丑奴儿・采桑子','[]','樱桃谢了梨花发，红白相催。',52,'宋词/ci.song.0.json','["樱桃谢了梨花发，红白相催。", "燕子归来。", "几处风帘绣户开。", "人生乐事知多少，且酌金杯。", "管咽声哀。", "慢引萧娘舞一回。"]'),
('song-ci-886','凤衔杯','杜安世','宋','宋词','song-ci','凤衔杯','[]','人生不似月初圆。',72,'宋词/ci.song.0.json','["人生不似月初圆。", "叹分飞、容易经年。", "凄惨断云片雨、□□□。", "□□□、□□□。", "金钵小，玉槽悭。", "想至今、谁为相怜。", "多少旧欢往事、一潸然。", "空牵惹、病缠绵。"]'),
('song-ci-887','凤衔杯','杜安世','宋','宋词','song-ci','凤衔杯','[]','留花不住怨花飞。',72,'宋词/ci.song.0.json','["留花不住怨花飞。", "向南园、情绪依依。", "可惜倚红斜白、一枝枝。", "经宿雨、暮江披。", "凭朱槛，把金卮。", "对芳丛、惆怅多时。", "何况旧欢新恨、阻心期。", "空满眼、是相思。"]'),
('song-ci-888','少年游','杜安世','宋','宋词','song-ci','少年游','[]','小轩深院是秋时。',60,'宋词/ci.song.0.json','["小轩深院是秋时。", "风叶堕高枝。", "疏帘静永，薄帷清夜，暑退觉寒微。", "凄凉天气离愁意，音书杳难期。", "多情成病不须医。", "更憔悴、转寻思。"]'),
('song-ci-889','玉楼春','杜安世','宋','宋词','song-ci','玉楼春','[]','玉烛光明正旦好。',64,'宋词/ci.song.0.json','["玉烛光明正旦好。", "斗柄东回春太早。", "岭寒犹锁去年梅，江暖新催今岁草。", "蜀国熙熙冬令杪。", "更喜寿阳新梦觉。", "玉杯齐举乐音谐，遥想金阶天仗晓。"]'),
('song-ci-890','玉楼春','杜安世','宋','宋词','song-ci','玉楼春','[]','风解池冰蝉翅薄。',64,'宋词/ci.song.0.json','["风解池冰蝉翅薄。", "庭树枝枯笼翠萼。", "背寒迎暖起犹慵，闲卷珠帘凭画阁。", "晴景融融烟漠漠。", "天际行人乖信约。", "病容先怯见春来，长到恁时添瘦削。"]'),
('song-ci-891','玉楼春','杜安世','宋','宋词','song-ci','玉楼春','[]','晴景融融春色浅。',64,'宋词/ci.song.0.json','["晴景融融春色浅。", "落尽梅花千万片。", "小池冰解水纹生，消息未闻梁上燕。", "楼倚轻寒风力软。", "目断孤云天自远。", "又还依旧去年时，寂寞病容人怪见。"]'),
('song-ci-892','玉楼春','杜安世','宋','宋词','song-ci','玉楼春','[]','三月牡丹呈艳态。',64,'宋词/ci.song.0.json','["三月牡丹呈艳态。", "壮观人间春世界。", "鲛绡玉槛作扃栊，淹雅洞中王母队。", "不奈风吹兼日㬠。", "国貌天香无物赛。", "直须共赏莫轻孤，回首万金何处买。"]'),
('song-ci-893','玉楼春','杜安世','宋','宋词','song-ci','玉楼春','[]','纶命忽从天上至。',64,'宋词/ci.song.0.json','["纶命忽从天上至。", "便绾兵权辞漕计。", "汉廷起草旧郎官，蜀部坐筹新将帅。", "红旆碧幢春色里。", "娇马嘶风花片坠。", "送行今日短亭中，恼乱故人须尽醉。"]'),
('song-ci-894','玉楼春','杜安世','宋','宋词','song-ci','玉楼春','[]','春景抛人无处问。',64,'宋词/ci.song.0.json','["春景抛人无处问。", "多谢石榴花又喷。", "茜罗揉出碎英繁，红蜡缕成香萼润。", "血色新裙羞莫近。", "密叶柔条相间衬。", "雨馀寂寞假山傍，乡国尚遥西海信。"]'),
('song-ci-895','玉楼春','杜安世','宋','宋词','song-ci','玉楼春','[]','三月初三春渐老。',64,'宋词/ci.song.0.json','["三月初三春渐老。", "遍地残花风暗扫。", "命俦啸侣拥笙歌，临水泛觞游宴好。", "浮利浮名何足道。", "丽景芳时须笑傲。", "今年不似去年欢，云海路长天杳杳。"]'),
('song-ci-896','河满子','杜安世','宋','宋词','song-ci','河满子','[]','细雨裛开红杏，新妆粉面鲜明。',84,'宋词/ci.song.0.json','["细雨裛开红杏，新妆粉面鲜明。", "东君何事交来早，更无绿叶同荣。", "独倚青楼吟赏，目前无限轻盈。", "命薄不依栏槛，或占郊坰。", "清香繁艳真堪爱，枉教寂寞凋零。", "相次牡丹芍药，王孙谁道多情。"]'),
('song-ci-897','河满子','杜安世','宋','宋词','song-ci','河满子','[]','柳嫩不禁摇动，梅残尽任飘零。',86,'宋词/ci.song.0.json','["柳嫩不禁摇动，梅残尽任飘零。", "雨馀天气来深院，向阳纤草重青。", "寂寞小桃初绽，两三枝上红英。", "又见云中归雁，嗈嗈断续和鸣。", "年年依旧无情绪，镇长冷落银屏。", "不语闲寻往事，微风频动帘旌。"]'),
('song-ci-898','山亭柳','杜安世','宋','宋词','song-ci','山亭柳','[]','晓来风雨，万花飘落。',96,'宋词/ci.song.0.json','["晓来风雨，万花飘落。", "叹韶光虚过。", "却芳草萋萋，映楼台、淡烟漠漠。", "纷纷絮飞院宇，燕子过朱阁。", "玉容淡妆添寂寞。", "檀郎孤愿太情薄。", "数归期，绝信约。", "暗添春宵恨，平康恣迷欢乐。", "时时闷饮绿醑，甚转转、思量著。"]'),
('song-ci-899','合欢带','杜安世','宋','宋词','song-ci','合欢带','[]','楼台高下玲珑。',128,'宋词/ci.song.0.json','["楼台高下玲珑。", "斗芳草、绿阴浓。", "芍药孤栖香艳晚，见樱桃、万颗初红。", "巢喧乳燕，珠帘镂曳，满户香风。", "罩纱帏、象床屏枕，昼眠才似朦胧。", "起来无语更兼慵。", "念分明、事成空。", "被你厌厌牵系我，怪纤腰、绣带宽松。", "春来早是，分飞两处，长恨西东。", "到如今、扇移明月，簟铺寒浪与谁同。"]'),
('song-ci-900','更漏子','杜安世','宋','宋词','song-ci','更漏子','[]','雪肌轻，花脸薄。',58,'宋词/ci.song.0.json','["雪肌轻，花脸薄。", "愁困不忺梳掠。", "眉翠袅，眼波长。", "偎人言语香。", "看难厌，怜不足。", "苦恨别离何速。", "珠树远，彩鸾孤。", "今生重见无。"]'),
('song-ci-901','更漏子','杜安世','宋','宋词','song-ci','更漏子','[]','脸如花，花不笑。',58,'宋词/ci.song.0.json','["脸如花，花不笑。", "双脸胜花能笑。", "肌似玉，玉非温。", "肌温胜玉温。", "既相逢，情不重。", "何似当初休共。", "情既重，却分飞。", "争如不见伊。"]'),
('song-ci-902','更漏子','杜安世','宋','宋词','song-ci','更漏子','[]','镂金环，连玉珥。',58,'宋词/ci.song.0.json','["镂金环，连玉珥。", "颗颗蚌蛤相缀。", "偎粉面，映莲腮。", "露浓花正开。", "冷光凝，员影重。", "几度偷期摇动。", "山枕上，恐人知。", "摘嫌纤手迟。"]'),
('song-ci-903','喜迁莺','杜安世','宋','宋词','song-ci','喜迁莺','[]','花不尽，柳无穷。',57,'宋词/ci.song.0.json','["花不尽，柳无穷。", "应与我心同。", "觥船一棹百分空。", "何处不相逢。", "朱弦悄。", "知音少。", "天若有情应老。", "劝君看取利名场。", "今古梦忙忙。"]'),
('song-ci-904','杜韦娘','杜安世','宋','宋词','song-ci','杜韦娘','[]','暮春天气，莺老燕子忙如织。',134,'宋词/ci.song.0.json','["暮春天气，莺老燕子忙如织。", "间嫩叶题诗哨梅小，乍遍水、新萍圆碧。", "初牡丹谢了，秋千搭起，垂杨暗锁深深陌。", "暖风轻，尽日闲把、榆钱乱掷。", "恨寂寂。", "芳容衰减，顿敧玳枕困无力。", "为少年、狂荡恩情薄，尚未有、归来消息。", "想当初、凤侣鸳俦，唤作平生，更不轻离拆。", "倚朱扉，泪眼滴损、红绡数尺。"]'),
('song-ci-905','胡捣练','杜安世','宋','宋词','song-ci','胡捣练','[]','数枝半敛半开时，洞阁晓妆新注。',58,'宋词/ci.song.0.json','["数枝半敛半开时，洞阁晓妆新注。", "宝香格艳姿天赋。", "甘被群芳妒。", "狂风横雨且相饶，又恐有彩云迎去。", "牵破少年心情，无计为长主。"]'),
('song-ci-906','少年游','杜安世','宋','宋词','song-ci','少年游','[]','小楼归燕又黄昏。',62,'宋词/ci.song.0.json','["小楼归燕又黄昏。", "寂寞锁高门。", "轻风细雨，惜花天气，相次过春分。", "画堂无绪，初燃绛蜡，罗帐掩馀薰。", "多情不解怨王孙。", "任薄幸、一从君。"]'),
('song-ci-907','凤栖梧・蝶恋花','杜安世','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','整顿云鬟初睡起。',70,'宋词/ci.song.0.json','["整顿云鬟初睡起。", "庭院无风，尽日帘垂地。", "画阁巢新燕声喜。", "杨花狂散无拘系。", "近来早是添憔悴。", "金缕衣宽，赛过宫腰细。", "苒苒光阴似流水。", "春残莺老人千里。"]'),
('song-ci-908','凤栖梧・蝶恋花','杜安世','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','池上新秋帘幕卷。',70,'宋词/ci.song.0.json','["池上新秋帘幕卷。", "菡萏娇红，鉴里西施面。", "衰柳摇风尚柔软。", "眠沙鸂鶒临清浅。", "新翻归翅云间燕。", "满地槐花，尽日蝉声乱。", "独倚阑干暮山远。", "一场寂寞无人见。"]'),
('song-ci-909','凤栖梧・蝶恋花','杜安世','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','闲上江楼初雨过。',70,'宋词/ci.song.0.json','["闲上江楼初雨过。", "满袖清风，微散谁知我。", "莲脸佳人颜未破。", "沙洲两两鸳鸯卧。", "时有渔歌相应和。", "叠秀危横，黛拨山千朵。", "一片凄凉无计那。", "离愁还有些些个。"]'),
('song-ci-910','凤栖梧・蝶恋花','杜安世','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','惆怅留春留不住。',70,'宋词/ci.song.0.json','["惆怅留春留不住。", "欲到清和，背我堂堂去。", "飞絮落花和细雨。", "凄凉庭院流莺度。", "更被闲愁相赚误。", "梦断高唐，回首桃源路。", "一饷沈吟无意绪。", "分明往事今何处。"]'),
('song-ci-911','浪淘沙','杜安世','宋','宋词','song-ci','浪淘沙','[]','后约无凭。',64,'宋词/ci.song.0.json','["后约无凭。", "往事堪惊。", "秋蛩永夜绕床鸣。", "展转寻思求好梦，还又难成。", "愁思若浮云。", "消尽重生。", "佳人何处独盈盈。", "可惜一天无用月，照空为谁明。"]'),
('song-ci-912','浪淘沙','杜安世','宋','宋词','song-ci','浪淘沙','[]','又是春暮。',66,'宋词/ci.song.0.json','["又是春暮。", "落花飞絮。", "子规啼尽断肠声，秋千庭院，红旗彩索，淡烟疏雨。", "念念相思苦。", "黛眉长聚。", "碧池惊散睡鸳鸯，当初容易分飞去。", "恨孤儿欢侣。"]'),
('song-ci-913','浪淘沙','杜安世','宋','宋词','song-ci','浪淘沙','[]','帘外微风。',66,'宋词/ci.song.0.json','["帘外微风。", "云雨回踪。", "银釭烬冷锦帏中。", "枕上深盟，年少心事，陡顿成空。", "岭外白头翁。", "到没由逢。", "一床鸳被叠香红。", "明月满庭花似绣，闷不见虫虫。"]'),
('song-ci-914','更漏子','杜安世','宋','宋词','song-ci','更漏子','[]','庭远途程。',126,'宋词/ci.song.0.json','["庭远途程。", "算万山千水，路入神京。", "暖日春郊，绿柳红杏，香迳舞燕流莺。", "客馆悄悄闲庭，堪惹旧恨深。", "有多少驱驱，蓦岭涉水，枉费身心。", "思想厚利高名。", "谩惹得忧烦，枉度浮生。", "幸有青松，白云深洞，清闲且乐升平。", "长是宦游羁思，别离泪满襟。", "望江乡踪迹，旧游题书，尚自分明。"]'),
('song-ci-915','行香子','杜安世','宋','宋词','song-ci','行香子','["\u957f\u6c5f"]','黄金叶细，碧玉枝纤。',86,'宋词/ci.song.0.json','["黄金叶细，碧玉枝纤。", "初暖日、当乍晴天。", "向武昌溪畔，於彭泽门前。", "陶潜影，张绪态，两相牵。", "数株堤面，几树桥边。", "嫩垂条、絮荡轻绵。", "系长江舴艋，拂深院秋千。", "寒食下，半和雨，半和烟。"]'),
('song-ci-916','巫山一段云','杜安世','宋','宋词','song-ci','巫山一段云','[]','笑拟条风戏，装迟谷雨催。',52,'宋词/ci.song.0.json','["笑拟条风戏，装迟谷雨催。", "彩云飞下柳楼台。", "千朵一时开。", "惜恐尘埃染，惊疑紫府来。", "有时香喷入人怀。", "魂断客徘徊。"]'),
('song-ci-917','生查子','杜安世','宋','宋词','song-ci','生查子','[]','关山魂梦长，寒雁音书少。',48,'宋词/ci.song.0.json','["关山魂梦长，寒雁音书少。", "两鬓可怜青，只为相思老。", "归傍碧纱窗，说向人人道。", "真个别离难，不似相逢好。"]'),
('song-ci-918','贺圣朝','杜安世','宋','宋词','song-ci','贺圣朝','[]','东君造物无凝滞。',57,'宋词/ci.song.0.json','["东君造物无凝滞。", "芳容相替。", "杏花桃萼一时开，就中明媚。", "绿丛金朵，枝长叶细。", "称花王相待。", "万般堪爱，暂时见了，断肠无计。"]'),
('song-ci-919','贺圣朝','杜安世','宋','宋词','song-ci','贺圣朝','[]','牡丹盛拆春将暮。',56,'宋词/ci.song.0.json','["牡丹盛拆春将暮。", "群芳羞妒。", "几时流落在人间，半间仙露。", "馨香艳冶，吟看醉赏，叹谁能留住。", "莫辞持烛夜深深，怨等闲风雨。"]'),
('song-ci-920','安公子','杜安世','宋','宋词','song-ci','安公子','[]','又是春将半。',130,'宋词/ci.song.0.json','["又是春将半。", "杏花零落闲庭院。", "天气有时阴淡淡，绿杨轻软。", "连画阁、绣帘半卷。", "招新燕。", "残黛敛、独倚阑干遍。", "暗思前事，月下风流，狂踪无限。", "惜恐莺花晚。", "更堪容易相抛远。", "离恨结成心上病，几时消散。", "空际有、断云片片。", "遥峰暖。", "闻杜宇、终日哀啼怨。", "暮烟芳草，写望迢迢，甚时重见。"]'),
('song-ci-921','苏幕遮','杜安世','宋','宋词','song-ci','苏幕遮','[]','尽思量，还叵耐。',76,'宋词/ci.song.0.json','["尽思量，还叵耐。", "因甚当初，故故相招买。", "早是幽欢多障碍。", "更遣分飞，脉脉如天外。", "有心怜，无计奈。", "两处厌厌，一点虚恩爱。", "独上高楼临暮霭。", "凭暖朱阑，这意无人会。"]'),
('song-ci-922','渔家傲','杜安世','宋','宋词','song-ci','渔家傲','[]','微雨初收月映云。',72,'宋词/ci.song.0.json','["微雨初收月映云。", "巢栖燕子欲黄昏。", "花片不飞风力困。", "春色尽。", "蜡梅枝上樱□嫩。", "谁撼金环锁深洞。", "薰馀乍厌锦衾温。", "消灭玉肌谁与问。", "朱明近。", "日长无事添闲闷。"]'),
('song-ci-923','渔家傲','杜安世','宋','宋词','song-ci','渔家傲','[]','疏雨才收淡泞天。',72,'宋词/ci.song.0.json','["疏雨才收淡泞天。", "微云绽处月婵娟。", "寒雁一声人正远。", "添幽怨。", "那堪往事思量遍。", "谁道绸缪两意坚。", "水萍风絮不相缘。", "舞鉴鸾肠虚寸断。", "芳容变。", "好将憔悴教伊见。"]'),
('song-ci-924','渔家傲','杜安世','宋','宋词','song-ci','渔家傲','[]','每到春来长如病。',71,'宋词/ci.song.0.json','["每到春来长如病。", "玉容瘦与薄妆称。", "不惯被人抛掷。", "思当本。", "奈向后期全无定。", "早是厌厌愁欲凝。", "花间众禽愁难听。", "天赋多情翻成恨。", "有谁问。", "花屏一点炉烟暝。"]'),
('song-ci-925','剔银灯','杜安世','宋','宋词','song-ci','剔银灯','[]','昨夜一场风雨。',90,'宋词/ci.song.0.json','["昨夜一场风雨。", "催促牡丹归去。", "孙武宫中，石崇楼下，多情怎生为主。", "真疑洛浦。", "云水算、杳无重数。", "独倚阑干凝伫。", "香片乱沾尘土。", "争似当初，不曾相见，免恁恼人肠肚。", "绿丛无语。", "空留得、宝刀翦处。"]'),
('song-ci-926','剔银灯','杜安世','宋','宋词','song-ci','剔银灯','[]','夜永衾寒梦觉。',93,'宋词/ci.song.0.json','["夜永衾寒梦觉。", "翠屏共、绣帏灯照。", "就枕思量，离多会少。", "孤负小欢轻笑。", "风流争表。", "空惹尽、一生烦恼。", "写遍香笺，分剖鳞翼，路遥难到。", "泪眼愁肠，朝朝暮暮，去便不知音耗。", "终须拼了。", "别选个、如伊才调。"]'),
('song-ci-927','剔银灯','杜安世','宋','宋词','song-ci','剔银灯','[]','好事争如不遇。',94,'宋词/ci.song.0.json','["好事争如不遇。", "可惜许、多情相误。", "月下风前，偷期窃会，共把衷肠分付。", "尤云殢雨。", "正缱绻、朝朝暮暮。", "无奈别离情绪。", "和酒病、双眉长聚。", "往事凄凉，佳音迢递，似此因缘谁做。", "洞云深处。", "暗回首、落花飞絮。"]'),
('song-ci-928','临江仙','杜安世','宋','宋词','song-ci','临江仙','[]','太史占天云物好，初阳律合黄锺。',70,'宋词/ci.song.0.json','["太史占天云物好，初阳律合黄锺。", "日缠南极北郊风。", "雪花先柳絮，飞舞透帘栊。", "圣运时和兼岁稔，歌欢处处皆同。", "簪声相庆晓光中。", "金炉红兽炭，一举寿杯空。"]'),
('song-ci-929','临江仙','杜安世','宋','宋词','song-ci','临江仙','[]','遍地残花庭院静，流莺对对相过。',70,'宋词/ci.song.0.json','["遍地残花庭院静，流莺对对相过。", "万条风柳间婆娑。", "樱桃初弄色，萱草自成窠。", "早是芳菲时节晚，追游期会无多。", "眉山敛翠近秋波。", "日长初睡起，愁与病相和。"]'),
('song-ci-930','采明珠','杜安世','宋','宋词','song-ci','采明珠','[]','雨乍收，小院尘消，云淡天高露冷。',120,'宋词/ci.song.0.json','["雨乍收，小院尘消，云淡天高露冷。", "坐看月华生，射玉楼清莹。", "蟋蟀鸣金井。", "下帘帏、悄悄空阶，败叶坠风，惹动闲愁，千端万绪难整。", "秋夜永。", "凉天迥。", "可不念光景。", "嗟薄命。", "倏忽少年，忍交孤令。", "灯闪红窗影。", "步回廊、懒入香闺，暗落泪珠满面，谁人知我，为伊成病。"]'),
('song-ci-931','朝玉阶・朝天子','杜安世','宋','宋词','song-ci','朝玉阶・朝天子','[]','春色欺人拂眼清。',71,'宋词/ci.song.0.json','["春色欺人拂眼清。", "柳条绿丝软，雪花轻。", "黄金才钺掩银屏。", "阴沈深院静，语娇莺。", "美人春困宝钗横。", "惜花芳态，泪盈盈。", "风流何处最多情。", "千金一笑，须信倾城。"]'),
('song-ci-932','朝玉阶・朝天子','杜安世','宋','宋词','song-ci','朝玉阶・朝天子','[]','帘卷春寒小雨天。',72,'宋词/ci.song.0.json','["帘卷春寒小雨天。", "牡丹花落尽，悄庭轩。", "高空双燕舞翩翩。", "无风轻絮坠，暗苔钱。", "拟将幽怨写香笺。", "中心多少事，语难传。", "思量真个恶因缘。", "那堪长梦见，在伊边。"]'),
('song-ci-933','卜算子','杜安世','宋','宋词','song-ci','卜算子','[]','深院花铺地。',56,'宋词/ci.song.0.json','["深院花铺地。", "淡淡阴天气。", "水榭风亭朱明景，又别是、愁情味。", "有情奈无计。", "漫惹成憔悴。", "欲把罗巾暗传寄。", "细认取、斑点泪。"]'),
('song-ci-934','卜算子','杜安世','宋','宋词','song-ci','卜算子','[]','尊前一曲歌。',56,'宋词/ci.song.0.json','["尊前一曲歌。", "歌里千重意，才欲歌时泪已流，恨应更、多於泪。", "试问缘何事。", "不语如痴醉。", "我亦情多不忍闻，怕和我、成憔悴。"]'),
('song-ci-935','瑞鹧鸪','杜安世','宋','宋词','song-ci','瑞鹧鸪','[]','夜来风雨损馀芳。',64,'宋词/ci.song.0.json','["夜来风雨损馀芳。", "数片衰红落槛傍。", "媚景背人容易去，半轩飞絮日空长。", "从来不信相思切，及至如今倍感伤。", "独立黄昏绣帘外，可堪新月露圆光。"]'),
('song-ci-936','燕归梁','杜安世','宋','宋词','song-ci','燕归梁','[]','风摆红绦卷画帘。',61,'宋词/ci.song.0.json','["风摆红绦卷画帘。", "宝鉴慵拈。", "日高梳洗几时忺。", "金盆水，弄纤纤。", "髻云松亸衣斜褪，和娇懒、瘦岩岩。", "离愁更被宿酲兼。", "空赢得，病厌厌。"]'),
('song-ci-937','菊花新','杜安世','宋','宋词','song-ci','菊花新','[]','怎奈花残又莺老。',64,'宋词/ci.song.0.json','["怎奈花残又莺老。", "槛里青梅数枝小。", "新荷长池沼。", "当晴昼、燕子声闹。", "亭栏花绽颜色好。", "风雨催催、等闲开了。", "酒醒暗思量，无个事、甚刚烦恼。"]'),
('song-ci-938','菊花新','杜安世','宋','宋词','song-ci','菊花新','[]','坐卧双眉镇长敛。',63,'宋词/ci.song.0.json','["坐卧双眉镇长敛。", "绣户初开花满院。", "罗帏翠屏空，风微动、玉炉烟飐。", "儿夫心肠多薄幸，百计思、难为拘捡。", "几回向伊言，交今后、更休抛闪。"]'),
('song-ci-939','鹊桥仙','杜安世','宋','宋词','song-ci','鹊桥仙','[]','别离情绪，多方开解，却免厌厌似醉。',68,'宋词/ci.song.0.json','["别离情绪，多方开解，却免厌厌似醉。", "楼高终日倚阑干，目断有、千山万水。", "妖娆薄媚，不禁抛摆，渐觉肌肤瘦悴。", "当初相见偶然间，不唤作、如今恁地。"]'),
('song-ci-940','鹊桥仙','杜安世','宋','宋词','song-ci','鹊桥仙','[]','日长天气，深深庭院，又是春愁滋味。',68,'宋词/ci.song.0.json','["日长天气，深深庭院，又是春愁滋味。", "池边昨夜雨兼风，战红杏、馀香乱坠。", "阴阴亭榭，暖烟轻柳，万缕黄金窣地。", "一双新燕却重来，但暗把、罗巾掩泪。"]'),
('song-ci-941','虞美人','杜安世','宋','宋词','song-ci','虞美人','[]','红颜绿鬓催人老。',68,'宋词/ci.song.0.json','["红颜绿鬓催人老。", "世事何时了。", "君心天意与年光。", "春花未遍已秋霜。", "为谁忙。", "樽前正好闲风月。", "莫话生离别。", "直饶终日踏红尘。", "浮名浮利枉劳神。", "更愁萦。"]'),
('song-ci-942','虞美人','杜安世','宋','宋词','song-ci','虞美人','[]','江亭春晚芳菲尽。',68,'宋词/ci.song.0.json','["江亭春晚芳菲尽。", "行色青天近。", "画桥杨柳也多情。", "暗抛飞絮惹前行。", "路尘清。", "彤庭早晚瞻虞舜。", "遥听恩迁峻。", "二年歌宴绮罗人。", "片云疏雨忍漂沦。", "泪沾巾。"]'),
('song-ci-943','虞美人','杜安世','宋','宋词','song-ci','虞美人','[]','炉香昼永龙烟白。',68,'宋词/ci.song.0.json','["炉香昼永龙烟白。", "风动金鸾额。", "画屏细展小山川。", "睡容初起枕痕圆。", "坠花钿。", "楼高不及烟霄半。", "望尽相思眼。", "艳阳刚爱挫愁天。", "故生芳草碧云连。", "怨王孙。"]'),
('song-ci-944','凤栖梧・蝶恋花','杜安世','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','秋日楼台在空际。',70,'宋词/ci.song.0.json','["秋日楼台在空际。", "画角声沈，历历寒更起。", "深院黄昏人独自。", "想伊遥共伤前事。", "懊恼当初无算计。", "些子欢娱，多少凄凉味。", "相去江山千万里。", "一回东望心如醉。"]'),
('song-ci-945','凤栖梧・蝶恋花','杜安世','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','任在芦花最深处。',70,'宋词/ci.song.0.json','["任在芦花最深处。", "浪静风恬，又泛轻舟去。", "去到滩头遇俦侣。", "散唱狂歌鱼未取。", "不把身心干时务。", "一副轮竿，莫笑闲家具。", "待拟观光佐明主。", "将甚医他民病苦。"]'),
('song-ci-946','凤栖梧・蝶恋花','杜安世','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','别浦迟留恋清浅。',70,'宋词/ci.song.0.json','["别浦迟留恋清浅。", "菱蔓荷花，尽日妨钩线。", "向晚澄江静如练。", "风送归帆飞似箭。", "鸥鹭相将是家眷。", "坐对云山，一任炎凉变。", "定是寰区又清宴。", "不见龙骧波上战。"]'),
('song-ci-947','凤栖梧・蝶恋花','杜安世','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','闲把浮生细思算。',70,'宋词/ci.song.0.json','["闲把浮生细思算。", "百岁光阴，梦里销除半。", "白首为郎休浩叹。", "偷安自喜身强健。", "多少英贤裨圣旦。", "一个非才，深谢容疏懒。", "席上清歌珠一串。", "莫教欢会轻分散。"]'),
('song-ci-948','凤栖梧・蝶恋花','杜安世','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','新月羞光影庭树。',70,'宋词/ci.song.0.json','["新月羞光影庭树。", "窗外芭蕉，数点黄昏雨。", "何事秋来无意绪。", "玉容寂寞双眉聚。", "一点银釭扃绣户。", "莎砌寒蛩，历历啼声苦。", "孤枕夜长君信否。", "披衣顒坐魂飞去。"]'),
('song-ci-949','忆汉月','杜安世','宋','宋词','song-ci','忆汉月','[]','红杏一枝遥见。',63,'宋词/ci.song.0.json','["红杏一枝遥见。", "凝露粉愁香怨。", "吹开吹谢任春风，恨流莺、不能拘管。", "曲池连夜雨，绿水上、碎红千片。", "直拟移来向深院。", "任凋零、不孤双眼。"]'),
('song-ci-950','诉衷情','杜安世','宋','宋词','song-ci','诉衷情','[]','烧残绛蜡泪成痕。',54,'宋词/ci.song.0.json','["烧残绛蜡泪成痕。", "街鼓报黄昏。", "碧云又阻来信，廊上月侵门。", "愁永夜，拂香裀。", "待谁温。", "梦兰憔悴，掷果凄凉，两处消魂。"]'),
('song-ci-951','朝中措','杜安世','宋','宋词','song-ci','朝中措','[]','养花天气近清明。',57,'宋词/ci.song.0.json','["养花天气近清明。", "丝雨酿寒轻。", "满眼春工如绣。", "消磨不尽离情。", "行行又宿，小桃旧坞，芳草邮亭。", "唤起两眉新恨。", "绿杨深处啼莺。"]'),
('song-ci-952','折新荷引・折新荷','赵','宋','宋词','song-ci','折新荷引・折新荷','[]','雨过回廊，圆荷嫩绿新抽。',101,'宋词/ci.song.0.json','["雨过回廊，圆荷嫩绿新抽。", "越女轻盈，画桡稳泛兰舟。", "芳容艳粉，红香透、脉脉娇羞。", "菱歌隐隐渐遥，依约回眸。", "堤上郎心，波间妆影迟留。", "不觉归时，淡天碧衬蟾钩。", "风蝉噪晚，馀霞际、几点沙鸥。", "渔笛、不道有人，独倚危楼。"]'),
('song-ci-953','梅花曲','刘几','宋','宋词','song-ci','梅花曲','[]','汉宫中侍女，娇额半涂黄。',113,'宋词/ci.song.0.json','["汉宫中侍女，娇额半涂黄。", "盈盈粉色凌时，寒玉体、先透薄妆。", "好借月魂来，娉婷画烛旁。", "惟恐随、阳春好梦去，所思飞扬。", "宜向风亭把盏，酬孤艳，醉永夕何妨。", "雪径蕊、真凝密，降回舆、认暗香。", "不为藉我作和羹，肯放结子花狂。", "向上林，留此占年芳。"]'),
('song-ci-954','梅花曲','刘几','宋','宋词','song-ci','梅花曲','[]','结子非贪，有香不俗，宜当鼎鼐尝。',121,'宋词/ci.song.0.json','["结子非贪，有香不俗，宜当鼎鼐尝。", "偶先红紫，度韶华、玉笛占年芳。", "众花杂色满上林，未能教、腊雪埋藏。", "却怕春风漏泄，一一尽天香。", "不须更御铅黄。", "知国色，禀自天真殊常。", "只裁云缕，奈芳滑、玉体想仙妆。", "少陵为尔东阁。", "美艳激诗肠。", "当已阴未雨春光。", "无心赋海棠。"]'),
('song-ci-955','梅花曲','刘几','宋','宋词','song-ci','梅花曲','[]','浅浅池塘。',117,'宋词/ci.song.0.json','["浅浅池塘。", "深深庭院，复出短短垣墙。", "年年为尔，若九真巡会、宝惜流芳。", "向人自有，绵渺无言，深意深藏。", "倾国倾城，天教与、抵死芳香。", "袅须金色，轻危欲压，绰约冠中央。", "蒂团红蜡，兰肌粉艳巧能妆。", "婵娟一种风流，如雪如冰衣霓裳。", "永日依倚，春风笑野棠。"]'),
('song-ci-956','花发状元红慢','刘几','宋','宋词','song-ci','花发状元红慢','[]','三春向暮，万卉成阴、有嘉艳方坼。',125,'宋词/ci.song.0.json','["三春向暮，万卉成阴、有嘉艳方坼。", "娇姿嫩质。", "冠群品，共赏倾城倾国。", "上苑晴昼暄，千素万红尤奇特。", "绮筵开，会咏歌才子，压倒元白。", "别有芳幽苞小，步障华丝，绮轩油壁。", "与紫鸳鸯、素蛱蝶。", "自清旦、往往连夕。", "巧莺喧翠管，娇燕语雕梁留客。", "武陵人，念梦役意浓，堪遣情溺。"]'),
('song-ci-957','减字木兰花','元绛','宋','宋词','song-ci','减字木兰花','[]','绿杨阴下。',52,'宋词/ci.song.0.json','["绿杨阴下。", "短帽轻衫行信马。", "过尽春风。", "踏尽青青打尽红。", "舞鸾歌凤。", "人面湖光红影动。", "醉眼归时。", "人在朱楼曲角西。"]'),
('song-ci-958','映山红慢','元绛','宋','宋词','song-ci','映山红慢','[]','谷雨风前，占淑景、名花独秀。',124,'宋词/ci.song.0.json','["谷雨风前，占淑景、名花独秀。", "露国色仙姿，品流第一，春工成就。", "罗帏护日金泥皱。", "映霞腮动檀痕溜。", "长记得天上，瑶池阆苑曾有。", "千匝绕、红玉阑干，愁只恐、朝云难久。", "须款折、绣囊剩戴，细把蜂须频嗅。", "佳人再拜抬娇面，敛红巾、捧金杯酒。", "献千千寿。", "愿长恁、天香满袖。"]'),
('song-ci-959','渔家傲','程师孟','宋','宋词','song-ci','渔家傲','[]','折柳赠君君且住。',8,'宋词/ci.song.0.json','["折柳赠君君且住。"]'),
('song-ci-960','望江南・忆江南','陈朴','宋','宋词','song-ci','望江南・忆江南','[]','中黄宝，须向胆中求。',64,'宋词/ci.song.0.json','["中黄宝，须向胆中求。", "春帝令行生万物，乾坤膝下与吾俦。", "百脉自流通。", "施造化，左右火双抽。", "浩浩腾腾充宇宙，苦烟袅袅上环楼。", "夫妇渐相谋。"]'),
('song-ci-961','望江南・忆江南','陈朴','宋','宋词','song-ci','望江南・忆江南','[]','玄珠降，丹窟在中宫。',64,'宋词/ci.song.0.json','["玄珠降，丹窟在中宫。", "九候息调重九数，赤波忽迸太阳东。", "心肾始交通。", "逢六变，重六息阴功。", "火自海门朝帝坐，水从莲沼佐丁公。", "紫电透玲珑。"]'),
('song-ci-962','望江南・忆江南','陈朴','宋','宋词','song-ci','望江南・忆江南','[]','毛发落，丹左运行阳。',64,'宋词/ci.song.0.json','["毛发落，丹左运行阳。", "胎色渐红阴渐小，推移岁运助乾刚。", "育火养中央。", "成物象，五岳辨微茫。", "出入尚迟形尚小，晨昏天籁奏笙簧。", "常饮玉壶浆。"]'),
('song-ci-963','望江南・忆江南','陈朴','宋','宋词','song-ci','望江南・忆江南','[]','丹往右，四转运行阴。',64,'宋词/ci.song.0.json','["丹往右，四转运行阴。", "逢六闭藏阳户气，玉关泉透合丁壬。", "龟戏任浮沉。", "时出入，无碍贯他心。", "游戏神通常出面，圆光周匝绕千寻。", "寒暑不相侵。"]'),
('song-ci-964','望江南・忆江南','陈朴','宋','宋词','song-ci','望江南・忆江南','[]','珠自右，飞电入丹城。',64,'宋词/ci.song.0.json','["珠自右，飞电入丹城。", "内养婴儿盈尺象，时逢九数采阳精。", "火向水中生。", "烧鬼岳，紫殿势峥嵘。", "随意出游寰海内，寐如砂碛卧长鲸。", "时序与偕行。"]'),
('song-ci-965','望江南・忆江南','陈朴','宋','宋词','song-ci','望江南・忆江南','[]','日精满，阴魄化无形。',64,'宋词/ci.song.0.json','["日精满，阴魄化无形。", "每遇月圆开北户，神龟时饮碧瑶玲。", "形魄岂能停。", "阳砂赤，阴粉色微青。", "粉换肉肌砂换骨，凡胎换尽圣胎灵。", "飞举似流星。"]'),
('song-ci-966','望江南・忆江南','陈朴','宋','宋词','song-ci','望江南・忆江南','[]','形透日，七转任飞腾。',64,'宋词/ci.song.0.json','["形透日，七转任飞腾。", "幽入深岩图宴坐，息无来去使神凝。", "却粒著奇能。", "生神火，返本气清澄。", "九候浴时开地户，月中取火日求冰。", "五内换重新。"]'),
('song-ci-967','望江南・忆江南','陈朴','宋','宋词','song-ci','望江南・忆江南','[]','内外遍，八转始还元。',64,'宋词/ci.song.0.json','["内外遍，八转始还元。", "地带长垂生坎户，周行胎息贯天门。", "太始道方存。", "纯一体，黑赤气常喷。", "丹火发来烧内境，冷泉深处浴猴孙。", "神水赤龟吞。"]'),
('song-ci-968','望江南・忆江南','陈朴','宋','宋词','song-ci','望江南・忆江南','[]','丹九转，纯一太初颜。',64,'宋词/ci.song.0.json','["丹九转，纯一太初颜。", "内外无为常抱朴，纵横海外与人间。", "功行积丘山。", "青阙诏，玉简赐金环。", "饮罢刀圭乘羽驾，旌幢箫鼓过天关。", "朝帝列仙班。"]'),
('song-ci-969','西江月','张伯端','宋','宋词','song-ci','西江月','[]','内药还同外药，内通外亦须通。',58,'宋词/ci.song.0.json','["内药还同外药，内通外亦须通。", "丹头和合类相同。", "温养两般作用。", "内有天然真火，炉中赫赫长红。", "外炉增减要勤功。", "妙绝无过真种。"]'),
('song-ci-970','西江月','张伯端','宋','宋词','song-ci','西江月','[]','此道至神至圣，忧君分薄难消。',58,'宋词/ci.song.0.json','["此道至神至圣，忧君分薄难消。", "调和铅汞不终朝。", "早睹玄珠形兆。", "志士若能修炼，何妨在市居朝。", "工夫容易药非遥。", "说破人须失笑。"]'),
('song-ci-971','西江月','张伯端','宋','宋词','song-ci','西江月','[]','白虎首经至宝，华池神水真金。',58,'宋词/ci.song.0.json','["白虎首经至宝，华池神水真金。", "故知上善利源深。", "不比寻常药品。", "若要修成九转，先须炼己持心。", "依时采取定浮沈。", "进火须防危甚。"]');
